-- Poems batch 440
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-41','九日龍山飲','李白','唐','御定全唐诗','yuding','','[]','九日龍山飲，黃花笑逐臣。醉看風落帽，舞愛月留人。',24,'御定全唐詩/json/179.json','["九日龍山飲，黃花笑逐臣。醉看風落帽，舞愛月留人。"]'),
('yuding-42','九月十日即事','李白','唐','御定全唐诗','yuding','','[]','昨日登高罷，今朝更舉觴。菊花何太苦，遭此兩重陽。',24,'御定全唐詩/json/179.json','["昨日登高罷，今朝更舉觴。菊花何太苦，遭此兩重陽。"]'),
('yuding-43','陪族叔當塗宰遊化城寺升公清風亭','李白','唐','御定全唐诗','yuding','','[]','化城若化出，金榜天宮開。疑是海上雲，飛空結樓臺。',156,'御定全唐詩/json/179.json','["化城若化出，金榜天宮開。疑是海上雲，飛空結樓臺。", "升公湖上秀，粲然有辯才。濟人不利己，立俗無嫌猜。", "了見水中月，青蓮出塵埃。閒居清風亭，左右清風來。", "當暑陰廣殿，太陽為裴回。茗酌待幽客，珍盤薦凋梅。", "飛文何灑落，萬象為之摧。季父擁鳴琴，德聲布雲雷。", "雖游道林室，亦舉陶潛杯。清樂動諸天，長松自吟哀。", "留歡若可盡，劫石乃成灰。"]'),
('yuding-0','登錦城散花樓','李白','唐','御定全唐诗','yuding','','[]','日照錦城頭，朝光散花樓。金窗夾繡戶，珠箔懸銀鉤。',60,'御定全唐詩/json/180.json','["日照錦城頭，朝光散花樓。金窗夾繡戶，珠箔懸銀鉤。", "飛梯綠雲中，極目散我憂。暮雨向三峽，春江繞雙流。", "今來一登望，如上九天遊。"]'),
('yuding-1','登峨眉山','李白','唐','御定全唐诗','yuding','','[]','蜀國多仙山，峨眉邈難匹。周流試登覽，絕怪安可息。',96,'御定全唐詩/json/180.json','["蜀國多仙山，峨眉邈難匹。周流試登覽，絕怪安可息。", "青冥倚天開，彩錯疑畫出。泠然紫霞賞，果得錦囊術。", "雲間吟瓊簫，石上弄寶瑟。平生有微尚，歡笑自此畢。", "煙容如在顏，塵累忽相失。倘逢騎羊子，攜手淩白日。"]'),
('yuding-2','大庭庫','李白','唐','御定全唐诗','yuding','','[]','朝登大庭庫，雲物何蒼然。莫辨陳鄭火，空霾鄒魯煙。',60,'御定全唐詩/json/180.json','["朝登大庭庫，雲物何蒼然。莫辨陳鄭火，空霾鄒魯煙。", "我來尋梓慎，觀化入寥天。古木朔氣多，松風如五弦。", "帝圖終冥沒，歎息滿山川。"]'),
('yuding-3','登單父陶少府半月臺','李白','唐','御定全唐诗','yuding','','[]','陶公有逸興，不與常人俱。築台像半月，回向高城隅。',72,'御定全唐詩/json/180.json','["陶公有逸興，不與常人俱。築台像半月，回向高城隅。", "置酒望白雲，商飆起寒梧。秋山入遠海，桑柘羅平蕪。", "水色淥且明，令人思鏡湖。終當過江去，愛此暫踟躕。"]'),
('yuding-4','天臺曉望','李白','唐','御定全唐诗','yuding','','[]','天臺鄰四明，華頂高百越。門標赤城霞，樓棲滄島月。',96,'御定全唐詩/json/180.json','["天臺鄰四明，華頂高百越。門標赤城霞，樓棲滄島月。", "憑高登遠覽，直下見溟渤。雲垂大鵬翻，波動巨鼇沒。", "風潮爭洶湧，神怪何翕忽。觀奇跡無倪，好道心不歇。", "攀條摘朱實，服藥煉金骨。安得生羽毛，千春臥蓬闕。"]'),
('yuding-5','早望海霞邊','李白','唐','御定全唐诗','yuding','','[]','四明三千里，朝起赤城霞。日出紅光散，分輝照雪崖。',48,'御定全唐詩/json/180.json','["四明三千里，朝起赤城霞。日出紅光散，分輝照雪崖。", "一餐咽瓊液，五內發金沙。舉手何所待，青龍白虎車。"]'),
('yuding-6','焦山望寥山','李白','唐','御定全唐诗','yuding','','[]','石壁望松寥，宛然在碧霄。安得五彩虹，駕天作長橋。',36,'御定全唐詩/json/180.json','["石壁望松寥，宛然在碧霄。安得五彩虹，駕天作長橋。", "仙人如愛我，舉手來相招。"]'),
('yuding-7','杜陵絕句','李白','唐','御定全唐诗','yuding','','[]','南登杜陵上，北望五陵間。秋水明落日，流光滅遠山。',24,'御定全唐詩/json/180.json','["南登杜陵上，北望五陵間。秋水明落日，流光滅遠山。"]'),
('yuding-8','登太白峰','李白','唐','御定全唐诗','yuding','','[]','西上太白峰，夕陽窮登攀。太白與我語，為我開天關。',60,'御定全唐詩/json/180.json','["西上太白峰，夕陽窮登攀。太白與我語，為我開天關。", "願乘泠風去，直出浮雲間。舉手可近月，前行若無山。", "一別武功去，何時複見還。"]'),
('yuding-9','登邯鄲洪波台，置酒觀發兵','李白','唐','御定全唐诗','yuding','','[]','我把兩赤羽，來游燕趙間。天狼正可射，感激無時閑。',84,'御定全唐詩/json/180.json','["我把兩赤羽，來游燕趙間。天狼正可射，感激無時閑。", "觀兵洪波台，倚劍望玉關。請纓不系越，且向燕然山。", "風引龍虎旗，歌鐘昔追攀。擊築落高月，投壺破愁顏。", "遙知百戰勝，定掃鬼方還。"]'),
('yuding-10','登新平樓','李白','唐','御定全唐诗','yuding','','[]','去國登茲樓，懷歸傷暮秋。天長落日遠，水淨寒波流。',48,'御定全唐詩/json/180.json','["去國登茲樓，懷歸傷暮秋。天長落日遠，水淨寒波流。", "秦雲起嶺樹，胡雁飛沙洲。蒼蒼幾萬里，目極令人愁。"]'),
('yuding-11','謁老君廟','李白','唐','御定全唐诗','yuding','','[]','先君懷聖德，靈廟肅神心。草合人蹤斷，塵濃鳥跡深。',48,'御定全唐詩/json/180.json','["先君懷聖德，靈廟肅神心。草合人蹤斷，塵濃鳥跡深。", "流沙丹灶滅，關路紫煙沉。獨傷千載後，空餘松柏林。"]'),
('yuding-12','秋日登揚州西靈塔','李白','唐','御定全唐诗','yuding','','[]','寶塔淩蒼蒼，登攀覽四荒。頂高元氣合，標出海雲長。',96,'御定全唐詩/json/180.json','["寶塔淩蒼蒼，登攀覽四荒。頂高元氣合，標出海雲長。", "萬象分空界，三天接畫梁。水搖金刹影，日動火珠光。", "鳥拂瓊簾度，霞連繡栱張。目隨征路斷，心逐去帆揚。", "露浴梧楸白，霜催橘柚黃。玉毫如可見，於此照迷方。"]'),
('yuding-13','登金陵冶城西北謝安墩','李白','唐','御定全唐诗','yuding','','[]','晉室昔橫潰，永嘉遂南奔。沙塵何茫茫，龍虎鬥朝昏。',204,'御定全唐詩/json/180.json','["晉室昔橫潰，永嘉遂南奔。沙塵何茫茫，龍虎鬥朝昏。", "胡馬風漢草，天驕蹙中原。哲匠感頹運，雲鵬忽飛翻。", "組練照楚國，旌旗連海門。西秦百萬眾，戈甲如雲屯。", "投鞭可填江，一掃不足論。皇運有返正，醜虜無遺魂。", "談笑遏橫流，蒼生望斯存。冶城訪古跡，猶有謝安墩。", "憑覽周地險，高標絕人喧。想像東山姿，緬懷右軍言。", "梧桐識嘉樹，蕙草留芳根。白鷺映春洲，青龍見朝暾。", "地古雲物在，台傾禾黍繁。我來酌清波，於此樹名園。", "功成拂衣去，歸入武陵源。"]'),
('yuding-14','登瓦官閣','李白','唐','御定全唐诗','yuding','','[]','晨登瓦官閣，極眺金陵城。鐘山對北戶，淮水入南榮。',120,'御定全唐詩/json/180.json','["晨登瓦官閣，極眺金陵城。鐘山對北戶，淮水入南榮。", "漫漫雨花落，嘈嘈天樂鳴。兩廊振法鼓，四角吟風箏。", "杳出霄漢上，仰攀日月行。山空霸氣滅，地古寒陰生。", "寥廓雲海晚，蒼茫宮觀平。門餘閶闔字，樓識鳳凰名。", "雷作百山動，神扶萬栱傾。靈光何足貴，長此鎮吳京。"]'),
('yuding-15','登梅岡望金陵，贈族侄高座寺僧中孚','李白','唐','御定全唐诗','yuding','','[]','鐘山抱金陵，霸氣昔騰發。天開帝王居，海色照宮闕。',192,'御定全唐詩/json/180.json','["鐘山抱金陵，霸氣昔騰發。天開帝王居，海色照宮闕。", "群峰如逐鹿，奔走相馳突。江水九道來，雲端遙明沒。", "時遷大運去，龍虎勢休歇。我來屬天清，登覽窮楚越。", "吾宗挺禪伯，特秀鸞鳳骨。眾星羅青天，明者獨有月。", "冥居順生理，草木不剪伐。煙窗引薔薇，石壁老野蕨。", "吳風謝安屐，白足傲履襪。幾宿一下山，蕭然忘幹謁。", "談經演金偈，降鶴舞海雪。時聞天香來，了與世事絕。", "佳游不可得，春風惜遠別。賦詩留岩屏，千載庶不滅。"]'),
('yuding-16','登金陵鳳凰台','李白','唐','御定全唐诗','yuding','','[]','鳳凰臺上鳳凰遊，鳳去台空江自流。吳宮花草埋幽徑，',40,'御定全唐詩/json/180.json','["鳳凰臺上鳳凰遊，鳳去台空江自流。吳宮花草埋幽徑，", "總為浮雲能蔽日，長安不見使人愁。"]'),
('yuding-17','望廬山瀑布水二首','李白','唐','御定全唐诗','yuding','','[]','西登香爐峰，南見瀑布水。掛流三百丈，噴壑數十裏。',164,'御定全唐詩/json/180.json','["西登香爐峰，南見瀑布水。掛流三百丈，噴壑數十裏。", "欻如飛電來，隱若白虹起。初驚河漢落，半灑雲天裏。", "仰觀勢轉雄，壯哉造化功。海風吹不斷，江月照還空。", "空中亂潈射，左右洗青壁。飛珠散輕霞，流沫沸穹石。", "而我樂名山，對之心益閑。無論漱瓊液，還得洗塵顏。", "且諧宿所好，永願辭人間。", "日照香爐生紫煙，遙看瀑布掛前川。", "飛流直下三千尺，疑是銀河落九天。"]'),
('yuding-18','登廬山五老峰','李白','唐','御定全唐诗','yuding','','[]','廬山東南五老峰，青天削出金芙蓉。',32,'御定全唐詩/json/180.json','["廬山東南五老峰，青天削出金芙蓉。", "九江秀色可攬結，吾將此地巢雲松。"]'),
('yuding-19','江上望皖公山','李白','唐','御定全唐诗','yuding','','[]','奇峰出奇雲，秀木含秀氣。清宴皖公山，巉絕稱人意。',72,'御定全唐詩/json/180.json','["奇峰出奇雲，秀木含秀氣。清宴皖公山，巉絕稱人意。", "獨遊滄江上，終日淡無味。但愛茲嶺高，何由討靈異。", "默然遙相許，欲往心莫遂。待吾還丹成，投跡歸此地。"]'),
('yuding-20','望黃鶴樓','李白','唐','御定全唐诗','yuding','','[]','東望黃鶴山，雄雄半空出。四面生白雲，中峰倚紅日。',120,'御定全唐詩/json/180.json','["東望黃鶴山，雄雄半空出。四面生白雲，中峰倚紅日。", "岩巒行穹跨，峰嶂亦冥密。頗聞列仙人，于此學飛術。", "一朝向蓬海，千載空石室。金灶生煙埃，玉潭秘清謐。", "地古遺草木，庭寒老芝朮。蹇予羨攀躋，因欲保閒逸。", "觀奇遍諸嶽，茲嶺不可匹。結心寄青松，永悟客情畢。"]'),
('yuding-21','鸚鵡洲','李白','唐','御定全唐诗','yuding','','[]','鸚鵡來過吳江水，江上洲傳鸚鵡名。鸚鵡西飛隴山去，',40,'御定全唐詩/json/180.json','["鸚鵡來過吳江水，江上洲傳鸚鵡名。鸚鵡西飛隴山去，", "遷客此時徒極目，長洲孤月向誰明。"]'),
('yuding-22','九日登巴陵，置酒望洞庭水軍','李白','唐','御定全唐诗','yuding','','[]','九日天氣清，登高無秋雲。造化辟川岳，了然楚漢分。',120,'御定全唐詩/json/180.json','["九日天氣清，登高無秋雲。造化辟川岳，了然楚漢分。", "長風鼓橫波，合遝蹙龍文。憶昔傳游豫，樓船壯橫汾。", "今茲討鯨鯢，旌旆何繽紛。白羽落酒樽，洞庭羅三軍。", "黃花不掇手，戰鼓遙相聞。劍舞轉頹陽，當時日停曛。", "酣歌激壯士，可以摧妖氛。齷齪東籬下，淵明不足群。"]'),
('yuding-23','秋登巴陵望洞庭','李白','唐','御定全唐诗','yuding','','[]','清晨登巴陵，周覽無不極。明湖映天光，徹底見秋色。',120,'御定全唐詩/json/180.json','["清晨登巴陵，周覽無不極。明湖映天光，徹底見秋色。", "秋色何蒼然，際海俱澄鮮。山青滅遠樹，水綠無寒煙。", "來帆出江中，去鳥向日邊。風清長沙浦，山空雲夢田。", "瞻光惜頹發，閱水悲徂年。北渚既蕩漾，東流自潺湲。", "郢人唱白雪，越女歌採蓮。聽此更腸斷，憑崖淚如泉。"]'),
('yuding-24','與夏十二登岳陽樓','李白','唐','御定全唐诗','yuding','','[]','樓觀岳陽盡，川迥洞庭開。雁引愁心去，山銜好月來。',48,'御定全唐詩/json/180.json','["樓觀岳陽盡，川迥洞庭開。雁引愁心去，山銜好月來。", "雲間連下榻，天上接行杯。醉後涼風起，吹人舞袖回。"]'),
('yuding-25','登巴陵開元寺西閣，贈衡岳僧方外','李白','唐','御定全唐诗','yuding','','[]','衡嶽有闡士，五峰秀真骨。見君萬里心，海水照秋月。',72,'御定全唐詩/json/180.json','["衡嶽有闡士，五峰秀真骨。見君萬里心，海水照秋月。", "大臣南溟去，問道皆請謁。灑以甘露言，清涼潤肌發。", "明湖落天鏡，香閣淩銀闕。登眺餐惠風，新花期啟發。"]'),
('yuding-26','與賈至舍人于龍興寺剪落梧桐枝望灉湖','李白','唐','御定全唐诗','yuding','','[]','剪落青梧枝，灉湖坐可窺。雨洗秋山淨，林光澹碧滋。',48,'御定全唐詩/json/180.json','["剪落青梧枝，灉湖坐可窺。雨洗秋山淨，林光澹碧滋。", "水閑明鏡轉，雲繞畫屏移。千古風流事，名賢共此時。"]'),
('yuding-27','掛席江上待月有懷','李白','唐','御定全唐诗','yuding','','[]','待月月未出，望江江自流。倏忽城西郭，青天懸玉鉤。',48,'御定全唐詩/json/180.json','["待月月未出，望江江自流。倏忽城西郭，青天懸玉鉤。", "素華雖可攬，清景不可遊。耿耿金波里，空瞻鳷鵲樓。"]'),
('yuding-28','金陵望漢江','李白','唐','御定全唐诗','yuding','','[]','漢江回萬里，派作九龍盤。橫潰豁中國，崔嵬飛迅湍。',60,'御定全唐詩/json/180.json','["漢江回萬里，派作九龍盤。橫潰豁中國，崔嵬飛迅湍。", "六帝淪亡後，三吳不足觀。我君混區宇，垂拱眾流安。", "今日任公子，滄浪罷釣竿。"]'),
('yuding-29','秋登宣城謝脁北樓','李白','唐','御定全唐诗','yuding','','[]','江城如畫裏，山曉望晴空。兩水夾明鏡，雙橋落彩虹。',48,'御定全唐詩/json/180.json','["江城如畫裏，山曉望晴空。兩水夾明鏡，雙橋落彩虹。", "人煙寒橘柚，秋色老梧桐。誰念北樓上，臨風懷謝公。"]'),
('yuding-30','望天門山','李白','唐','御定全唐诗','yuding','','[]','天門中斷楚江開，碧水東流至北回。',32,'御定全唐詩/json/180.json','["天門中斷楚江開，碧水東流至北回。", "兩岸青山相對出，孤帆一片日邊來。"]'),
('yuding-31','望木瓜山','李白','唐','御定全唐诗','yuding','','[]','早起見日出，暮見棲鳥還。客心自酸楚，況對木瓜山。',24,'御定全唐詩/json/180.json','["早起見日出，暮見棲鳥還。客心自酸楚，況對木瓜山。"]'),
('yuding-32','登敬亭北二小山，余時送客，逢崔侍禦，並登此地','李白','唐','御定全唐诗','yuding','','[]','送客謝亭北，逢君縱酒還。屈盤戲白馬，大笑上青山。',48,'御定全唐詩/json/180.json','["送客謝亭北，逢君縱酒還。屈盤戲白馬，大笑上青山。", "回鞭指長安，西日落秦關。帝鄉三千里，杳在碧雲間。"]'),
('yuding-33','過崔八丈水亭','李白','唐','御定全唐诗','yuding','','[]','高閣橫秀氣，清幽並在君。簷飛宛溪水，窗落敬亭雲。',48,'御定全唐詩/json/180.json','["高閣橫秀氣，清幽並在君。簷飛宛溪水，窗落敬亭雲。", "猿嘯風中斷，漁歌月裏聞。閑隨白鷗去，沙上自為群。"]'),
('yuding-34','登廣武古戰場懷古','李白','唐','御定全唐诗','yuding','','[]','秦鹿奔野草，逐之若飛蓬。項王氣蓋世，紫電明雙瞳。',180,'御定全唐詩/json/180.json','["秦鹿奔野草，逐之若飛蓬。項王氣蓋世，紫電明雙瞳。", "呼吸八千人，橫行起江東。赤精斬白帝，叱吒入關中。", "兩龍不並躍，五緯與天同。楚滅無英圖，漢興有成功。", "按劍清八極，歸酣歌大風。伊昔臨廣武，連兵決雌雄。", "分我一杯羹，太皇乃汝翁。戰爭有古跡，壁壘頹層穹。", "猛虎嘯洞壑，饑鷹鳴秋空。翔雲列曉陣，殺氣赫長虹。", "撥亂屬豪聖，俗儒安可通。沉湎呼豎子，狂言非至公。", "撫掌黃河曲，嗤嗤阮嗣宗。"]'),
('yuding-0','《安州應城玉女湯作','李白','唐','御定全唐诗','yuding','','[]','神女歿幽境，湯池流大川。陰陽結炎炭，造化開靈泉。',132,'御定全唐詩/json/181.json','["神女歿幽境，湯池流大川。陰陽結炎炭，造化開靈泉。", "地底爍朱火，沙傍歊素煙。沸珠躍明月，皎鏡函空天。", "氣浮蘭芳滿，色漲桃花然。精覽萬殊入，潛行七澤連。", "愈疾功莫尚，變盈道乃全。濯濯氣清泚，晞發弄潺湲。", "散下楚王國，分澆宋玉田。可以奉巡幸，奈何隔窮偏。", "獨隨朝宗水，赴海輸微涓。"]'),
('yuding-1','之廣陵宿常二南郭幽居','李白','唐','御定全唐诗','yuding','','[]','綠水接柴門，有如桃花源。忘憂或假草，滿院羅叢萱。',72,'御定全唐詩/json/181.json','["綠水接柴門，有如桃花源。忘憂或假草，滿院羅叢萱。", "暝色湖上來，微雨飛南軒。故人宿茅宇，夕鳥棲楊園。", "還惜詩酒別，深為江海言。明朝廣陵道，獨憶此傾樽。"]'),
('yuding-2','夜下征虜亭','李白','唐','御定全唐诗','yuding','','[]','船下廣陵去，月明征虜亭。山花如繡頰，江火似流螢。',24,'御定全唐詩/json/181.json','["船下廣陵去，月明征虜亭。山花如繡頰，江火似流螢。"]'),
('yuding-3','下途歸石門舊居','李白','唐','御定全唐诗','yuding','','[]','吳山高，越水清，握手無言傷別情。將欲辭君掛帆去，',168,'御定全唐詩/json/181.json','["吳山高，越水清，握手無言傷別情。將欲辭君掛帆去，", "雲物共傾三月酒，歲時同餞五侯門。羨君素書嘗滿案，", "何當脫屣謝時去，壺中別有日月天。俯仰人間易凋朽，", "隱居寺，隱居山，陶公煉液棲其間。靈神閉氣昔登攀，", "我離雖則歲物改，如今了然失所在。別君莫道不盡歡，", "不知何處得雞豕，就中仍見繁桑麻。翛然遠與世事間，", "挹君去，長相思，雲遊雨散從此辭。欲知悵別心易苦，"]'),
('yuding-4','客中行','李白','唐','御定全唐诗','yuding','','[]','蘭陵美酒鬱金香，玉碗盛來琥珀光。',32,'御定全唐詩/json/181.json','["蘭陵美酒鬱金香，玉碗盛來琥珀光。", "但使主人能醉客，不知何處是他鄉。"]'),
('yuding-5','太原早秋','李白','唐','御定全唐诗','yuding','','[]','歲落眾芳歇，時當大火流。霜威出塞早，雲色渡河秋。',48,'御定全唐詩/json/181.json','["歲落眾芳歇，時當大火流。霜威出塞早，雲色渡河秋。", "夢繞邊城月，心飛故國樓。思歸若汾水，無日不悠悠。"]'),
('yuding-6','奔亡道中五首','李白','唐','御定全唐诗','yuding','','[]','蘇武天山上，田橫海島邊。萬重關塞斷，何日是歸年。',168,'御定全唐詩/json/181.json','["蘇武天山上，田橫海島邊。萬重關塞斷，何日是歸年。", "亭伯去安在，李陵降未歸。愁容變海色，短服改胡衣。", "談笑三軍卻，交遊七貴疏。仍留一隻箭，未射魯連書。", "函谷如玉關，幾時可生還。洛陽為易水，嵩岳是燕山。", "俗變羌胡語，人多沙塞顏。申包惟慟哭，七日鬢毛斑。", "淼淼望湖水，青青蘆葉齊。歸心落何處，日沒大江西。", "歇馬傍春草，欲行遠道迷。誰忍子規鳥，連聲向我啼。"]'),
('yuding-7','郢門秋懷','李白','唐','御定全唐诗','yuding','','[]','郢門一為客，巴月三成弦。朔風正搖落，行子愁歸旋。',120,'御定全唐詩/json/181.json','["郢門一為客，巴月三成弦。朔風正搖落，行子愁歸旋。", "杳杳山外日，茫茫江上天。人迷洞庭水，雁度瀟湘煙。", "清曠諧宿好，緇磷及此年。百齡何蕩漾，萬化相推遷。", "空謁蒼梧帝，徒尋溟海仙。已聞蓬海淺，豈見三桃圓。", "倚劍增浩歎，捫襟還自憐。終當遊五湖，濯足滄浪泉。"]'),
('yuding-8','至鴨欄驛上白馬磯，贈裴侍禦','李白','唐','御定全唐诗','yuding','','[]','側疊萬古石，橫為白馬磯。亂流若電轉，舉棹揚珠輝。',48,'御定全唐詩/json/181.json','["側疊萬古石，橫為白馬磯。亂流若電轉，舉棹揚珠輝。", "臨驛卷緹幕，升常接繡衣。情親不避馬，為我解霜威。"]'),
('yuding-9','荊門浮舟望蜀江','李白','唐','御定全唐诗','yuding','','[]','春水月峽來，浮舟望安極。正是桃花流，依然錦江色。',96,'御定全唐詩/json/181.json','["春水月峽來，浮舟望安極。正是桃花流，依然錦江色。", "江色綠且明，茫茫與天平。逶迤巴山盡，搖曳楚雲行。", "雪照聚沙雁，花飛出穀鶯。芳洲卻已轉，碧樹森森迎。", "流目浦煙夕，揚帆海月生。江陵識遙火，應到渚宮城。"]'),
('yuding-10','上三峽','李白','唐','御定全唐诗','yuding','','[]','巫山夾青天，巴水流若茲。巴水忽可盡，青天無到時。',48,'御定全唐詩/json/181.json','["巫山夾青天，巴水流若茲。巴水忽可盡，青天無到時。", "三朝上黃牛，三暮行太遲。三朝又三暮，不覺鬢成絲。"]'),
('yuding-11','自巴東舟行經瞿唐峽，登巫山最高峰，晚還題壁','李白','唐','御定全唐诗','yuding','','[]','江行幾千里，海月十五圓。始經瞿塘峽，遂步巫山巔。',168,'御定全唐詩/json/181.json','["江行幾千里，海月十五圓。始經瞿塘峽，遂步巫山巔。", "巫山高不窮，巴國盡所曆。日邊攀垂蘿，霞外倚穹石。", "飛步淩絕頂，極目無纖煙。卻顧失丹壑，仰觀臨青天。", "青天若可捫，銀漢去安在。望雲知蒼梧，記水辨瀛海。", "周遊孤光晚，曆覽幽意多。積雪照空穀，悲風鳴森柯。", "歸途行欲曛，佳趣尚未歇。江寒早啼猿，松暝已吐月。", "月色何悠悠，清猿響啾啾。辭山不忍聽，揮策還孤舟。"]'),
('yuding-12','早發白帝城','李白','唐','御定全唐诗','yuding','','[]','朝辭白帝彩雲間，千里江陵一日還。',32,'御定全唐詩/json/181.json','["朝辭白帝彩雲間，千里江陵一日還。", "兩岸猿聲啼不盡，輕舟已過萬重山。"]'),
('yuding-13','秋下荊門','李白','唐','御定全唐诗','yuding','','[]','霜落荊門江樹空，布帆無恙掛秋風。',32,'御定全唐詩/json/181.json','["霜落荊門江樹空，布帆無恙掛秋風。", "此行不為鱸魚鱠，自愛名山入剡中。"]'),
('yuding-14','江行寄遠','李白','唐','御定全唐诗','yuding','','[]','刳木出吳楚，危槎百餘尺。疾風吹片帆，日暮千里隔。',48,'御定全唐詩/json/181.json','["刳木出吳楚，危槎百餘尺。疾風吹片帆，日暮千里隔。", "別時酒猶在，已為異鄉客。思君不可得，愁見江水碧。"]'),
('yuding-15','宿五松山下荀媼家','李白','唐','御定全唐诗','yuding','','[]','我宿五松下，寂寥無所歡。田家秋作苦，鄰女夜舂寒。',48,'御定全唐詩/json/181.json','["我宿五松下，寂寥無所歡。田家秋作苦，鄰女夜舂寒。", "跪進雕胡飯，月光明素盤。令人慚漂母，三謝不能餐。"]'),
('yuding-16','下涇縣陵陽溪至澀灘','李白','唐','御定全唐诗','yuding','','[]','澀灘鳴嘈嘈，兩山足猿猱。白波若卷雪，側足不容舠。',36,'御定全唐詩/json/181.json','["澀灘鳴嘈嘈，兩山足猿猱。白波若卷雪，側足不容舠。", "漁子與舟人，撐折萬張篙。"]'),
('yuding-17','下陵陽沿高溪三門六剌灘','李白','唐','御定全唐诗','yuding','','[]','三門橫峻灘，六剌走波瀾。石驚虎伏起，水狀龍縈盤。',36,'御定全唐詩/json/181.json','["三門橫峻灘，六剌走波瀾。石驚虎伏起，水狀龍縈盤。", "何慚七裏瀨，使我欲垂竿。"]'),
('yuding-18','夜泊黃山，聞殷十四吳吟','李白','唐','御定全唐诗','yuding','','[]','昨夜誰為吳會吟，風生萬壑振空林。龍驚不敢水中臥，',48,'御定全唐詩/json/181.json','["昨夜誰為吳會吟，風生萬壑振空林。龍驚不敢水中臥，", "朝來果是滄洲逸，酤酒醍盤飯霜栗。半酣更發江海聲，"]'),
('yuding-19','宿鰕湖','李白','唐','御定全唐诗','yuding','','[]','雞鳴發黃山，暝投鰕湖宿。白雨映寒山，森森似銀竹。',72,'御定全唐詩/json/181.json','["雞鳴發黃山，暝投鰕湖宿。白雨映寒山，森森似銀竹。", "提攜采鉛客，結荷水邊沐。半夜四天開，星河爛人目。", "明晨大樓去，岡隴多屈伏。當與持斧翁，前溪伐雲木。"]'),
('yuding-20','西施','李白','唐','御定全唐诗','yuding','','[]','西施越溪女，出自苧蘿山。秀色掩今古，荷花羞玉顏。',84,'御定全唐詩/json/181.json','["西施越溪女，出自苧蘿山。秀色掩今古，荷花羞玉顏。", "浣紗弄碧水，自與清波閑。皓齒信難開，沉吟碧雲間。", "勾踐征絕豔，揚蛾入吳關。提攜館娃宮，杳渺詎可攀。", "一破夫差國，千秋竟不還。"]'),
('yuding-21','王右軍','李白','唐','御定全唐诗','yuding','','[]','右軍本清真，瀟灑出風塵。山陰過羽客，愛此好鵝賓。',48,'御定全唐詩/json/181.json','["右軍本清真，瀟灑出風塵。山陰過羽客，愛此好鵝賓。", "掃素寫道經，筆精妙入神。書罷籠鵝去，何曾別主人。"]'),
('yuding-22','上元夫人','李白','唐','御定全唐诗','yuding','','[]','上元誰夫人，偏得王母嬌。嵯峨三角髻，餘發散垂腰。',60,'御定全唐詩/json/181.json','["上元誰夫人，偏得王母嬌。嵯峨三角髻，餘發散垂腰。", "裘披青毛錦，身著赤霜袍。手提嬴女兒，閑與鳳吹簫。", "眉語兩自笑，忽然隨風飄。"]'),
('yuding-23','蘇台覽古','李白','唐','御定全唐诗','yuding','','[]','舊苑荒台楊柳新，菱歌清唱不勝春。',32,'御定全唐詩/json/181.json','["舊苑荒台楊柳新，菱歌清唱不勝春。", "只今惟有西江月，曾照吳王宮裏人。"]'),
('yuding-24','越中覽古','李白','唐','御定全唐诗','yuding','','[]','越王勾踐破吳歸，義士還鄉盡錦衣。',32,'御定全唐詩/json/181.json','["越王勾踐破吳歸，義士還鄉盡錦衣。", "宮女如花滿春殿，只今惟有鷓鴣飛。"]'),
('yuding-25','商山四皓','李白','唐','御定全唐诗','yuding','','[]','白髮四老人，昂藏南山側。偃臥松雪間，冥翳不可識。',120,'御定全唐詩/json/181.json','["白髮四老人，昂藏南山側。偃臥松雪間，冥翳不可識。", "雲窗拂青靄，石壁橫翠色。龍虎方戰爭，於焉自休息。", "秦人失金鏡，漢祖升紫極。陰虹濁太陽，前星遂淪匿。", "一行佐明聖，倏起生羽翼。功成身不居，舒卷在胸臆。", "窅冥合元化，茫昧信難測。飛聲塞天衢，萬古仰遺則。"]'),
('yuding-26','過四皓墓','李白','唐','御定全唐诗','yuding','','[]','我行至商洛，幽獨訪神仙。園綺複安在，雲蘿尚宛然。',96,'御定全唐詩/json/181.json','["我行至商洛，幽獨訪神仙。園綺複安在，雲蘿尚宛然。", "荒涼千古跡，蕪沒四墳連。伊昔煉金鼎，何年閉玉泉。", "隴寒惟有月，松古漸無煙。木魅風號去，山精雨嘯旋。", "紫芝高詠罷，青史舊名傳。今日並如此，哀哉信可憐。"]'),
('yuding-27','峴山懷古','李白','唐','御定全唐诗','yuding','','[]','訪古登峴首，憑高眺襄中。天清遠峰出，水落寒沙空。',48,'御定全唐詩/json/181.json','["訪古登峴首，憑高眺襄中。天清遠峰出，水落寒沙空。", "弄珠見遊女，醉酒懷山公。感歎發秋興，長松鳴夜風。"]'),
('yuding-28','蘇武','李白','唐','御定全唐诗','yuding','','[]','蘇武在匈奴，十年持漢節。白雁上林飛，空傳一書劄。',72,'御定全唐詩/json/181.json','["蘇武在匈奴，十年持漢節。白雁上林飛，空傳一書劄。", "牧羊邊地苦，落日歸心絕。渴飲月窟冰，饑餐天上雪。", "東還沙塞遠，北愴河梁別。泣把李陵衣，相看淚成血。"]'),
('yuding-29','經下邳圯橋懷張子房','李白','唐','御定全唐诗','yuding','','[]','子房未虎嘯，破產不為家。滄海得壯士，椎秦博浪沙。',84,'御定全唐詩/json/181.json','["子房未虎嘯，破產不為家。滄海得壯士，椎秦博浪沙。", "報韓雖不成，天地皆振動。潛匿遊下邳，豈曰非智勇。", "我來圯橋上，懷古欽英風。惟見碧流水，曾無黃石公。", "歎息此人去，蕭條徐泗空。"]'),
('yuding-30','金陵三首','李白','唐','御定全唐诗','yuding','','[]','晉家南渡日，此地舊長安。地即帝王宅，山為龍虎盤。',144,'御定全唐詩/json/181.json','["晉家南渡日，此地舊長安。地即帝王宅，山為龍虎盤。", "金陵空壯觀，天塹淨波瀾。醉客回橈去，吳歌且自歡。", "地擁金陵勢，城回江水流。當時百萬戶，夾道起朱樓。", "亡國生春草，離宮沒古丘。空餘後湖月，波上對江州。", "六代興亡國，三杯為爾歌。苑方秦地少，山似洛陽多。", "古殿吳花草，深宮晉綺羅。並隨人事滅，東逝與滄波。"]'),
('yuding-31','秋夜板橋浦泛月獨酌懷謝脁','李白','唐','御定全唐诗','yuding','','[]','天上何所有，迢迢白玉繩。斜低建章闕，耿耿對金陵。',72,'御定全唐詩/json/181.json','["天上何所有，迢迢白玉繩。斜低建章闕，耿耿對金陵。", "漢水舊如練，霜江夜清澄。長川瀉落月，洲渚曉寒凝。", "獨酌板橋浦，古人誰可征。玄暉難再得，灑酒氣填膺。"]'),
('yuding-32','入彭蠡經松門觀石鏡，緬懷謝康樂題詩書遊覽之志','李白','唐','御定全唐诗','yuding','','[]','謝公之彭蠡，因此遊松門。余方窺石鏡，兼得窮江源。',120,'御定全唐詩/json/181.json','["謝公之彭蠡，因此遊松門。余方窺石鏡，兼得窮江源。", "將欲繼風雅，豈徒清心魂。前賞逾所見，後來道空存。", "況屬臨泛美，而無洲渚喧。漾水向東去，漳流直南奔。", "空蒙三川夕，回合千里昏。青桂隱遙月，綠楓鳴愁猿。", "水碧或可采，金精秘莫論。吾將學仙去，冀與琴高言。"]'),
('yuding-33','廬江主人婦','李白','唐','御定全唐诗','yuding','','[]','孔雀東飛何處棲，廬江小吏仲卿妻。',32,'御定全唐詩/json/181.json','["孔雀東飛何處棲，廬江小吏仲卿妻。", "為客裁縫君自見，城烏獨宿夜空啼。"]'),
('yuding-34','陪宋中丞武昌夜飲懷古','李白','唐','御定全唐诗','yuding','','[]','清景南樓夜，風流在武昌。庾公愛秋月，乘興坐胡床。',48,'御定全唐詩/json/181.json','["清景南樓夜，風流在武昌。庾公愛秋月，乘興坐胡床。", "龍笛吟寒水，天河落曉霜。我心還不淺，懷古醉餘觴。"]'),
('yuding-35','望鸚鵡洲懷禰衡','李白','唐','御定全唐诗','yuding','','[]','魏帝營八極，蟻觀一禰衡。黃祖鬥筲人，殺之受惡名。',96,'御定全唐詩/json/181.json','["魏帝營八極，蟻觀一禰衡。黃祖鬥筲人，殺之受惡名。", "吳江賦鸚鵡，落筆超群英。鏘鏘振金玉，句句欲飛鳴。", "鷙鶚啄孤鳳，千春傷我情。五嶽起方寸，隱然詎可平。", "才高竟何施，寡識冒天刑。至今芳洲上，蘭蕙不忍生。"]'),
('yuding-36','宿巫山下','李白','唐','御定全唐诗','yuding','','[]','昨夜巫山下，猿聲夢裏長。桃花飛綠水，三月下瞿塘。',48,'御定全唐詩/json/181.json','["昨夜巫山下，猿聲夢裏長。桃花飛綠水，三月下瞿塘。", "雨色風吹去，南行拂楚王。高丘懷宋玉，訪古一沾裳。"]'),
('yuding-37','金陵白楊十字巷','李白','唐','御定全唐诗','yuding','','[]','白楊十字巷，北夾湖溝道。不見吳時人，空生唐年草。',48,'御定全唐詩/json/181.json','["白楊十字巷，北夾湖溝道。不見吳時人，空生唐年草。", "天地有反復，宮城盡傾倒。六帝餘古丘，樵蘇泣遺老。"]'),
('yuding-38','謝公亭','李白','唐','御定全唐诗','yuding','','[]','謝公離別處，風景每生愁。客散青天月，山空碧水流。',48,'御定全唐詩/json/181.json','["謝公離別處，風景每生愁。客散青天月，山空碧水流。", "池花春映日，窗竹夜鳴秋。今古一相接，長歌懷舊遊。"]'),
('yuding-39','紀南陵題五松山','李白','唐','御定全唐诗','yuding','','[]','聖達有去就，潛光愚其德。魚與龍同池，龍去魚不測。',144,'御定全唐詩/json/181.json','["聖達有去就，潛光愚其德。魚與龍同池，龍去魚不測。", "當時版築輩，豈知傅說情。一朝和殷羹，光氣為列星。", "伊尹生空桑，捐庖佐皇極。桐宮放太甲，攝政無愧色。", "三年帝道明，委質終輔翼。曠哉至人心，萬古可為則。", "時命或大繆，仲尼將奈何。鸞鳳忽覆巢，麒麟不來過。", "龜山蔽魯國，有斧且無柯。歸來歸去來，宵濟越洪波。"]'),
('yuding-40','夜泊牛渚懷古','李白','唐','御定全唐诗','yuding','','[]','牛渚西江夜，青天無片雲。登舟望秋月，空憶謝將軍。',48,'御定全唐詩/json/181.json','["牛渚西江夜，青天無片雲。登舟望秋月，空憶謝將軍。", "余亦能高詠，斯人不可聞。明朝掛帆席，楓葉落紛紛。"]'),
('yuding-41','姑孰十詠：姑孰溪','李白','唐','御定全唐诗','yuding','','[]','愛此溪水閑，乘流興無極。漾楫怕鷗驚，垂竿待魚食。',48,'御定全唐詩/json/181.json','["愛此溪水閑，乘流興無極。漾楫怕鷗驚，垂竿待魚食。", "波翻曉霞影，岸疊春山色。何處浣紗人，紅顏未相識。"]'),
('yuding-42','姑孰十詠：丹陽湖','李白','唐','御定全唐诗','yuding','','[]','湖與元氣連，風波浩難止。天外賈客歸，雲間片帆起。',48,'御定全唐詩/json/181.json','["湖與元氣連，風波浩難止。天外賈客歸，雲間片帆起。", "龜游蓮葉上，鳥宿蘆花裏。少女棹歸舟，歌聲逐流水。"]'),
('yuding-43','姑孰十詠：謝公宅','李白','唐','御定全唐诗','yuding','','[]','青山日將暝，寂寞謝公宅。竹裏無人聲，池中虛月白。',48,'御定全唐詩/json/181.json','["青山日將暝，寂寞謝公宅。竹裏無人聲，池中虛月白。", "荒庭衰草遍，廢井蒼苔積。惟有清風閑，時時起泉石。"]'),
('yuding-44','姑孰十詠：陵歊台','李白','唐','御定全唐诗','yuding','','[]','曠望登古台，台高極人目。疊嶂列遠空，雜花間平陸。',48,'御定全唐詩/json/181.json','["曠望登古台，台高極人目。疊嶂列遠空，雜花間平陸。", "閑雲入窗牖，野翠生松竹。欲覽碑上文，苔侵豈堪讀。"]'),
('yuding-45','姑孰十詠：桓公井','李白','唐','御定全唐诗','yuding','','[]','桓公名已古，廢井曾未竭。石甃冷蒼苔，寒泉湛孤月。',48,'御定全唐詩/json/181.json','["桓公名已古，廢井曾未竭。石甃冷蒼苔，寒泉湛孤月。", "秋來桐暫落，春至桃還發。路遠人罕窺，誰能見清澈。"]'),
('yuding-46','姑孰十詠：慈姥竹','李白','唐','御定全唐诗','yuding','','[]','野竹攢石生，含煙映江島。翠色落波深，虛聲帶寒早。',48,'御定全唐詩/json/181.json','["野竹攢石生，含煙映江島。翠色落波深，虛聲帶寒早。", "龍吟曾未聽，鳳曲吹應好。不學蒲柳凋，貞心嘗自保。"]'),
('yuding-47','姑孰十詠：望夫山','李白','唐','御定全唐诗','yuding','','[]','顒望臨碧空，怨情感離別。江草不知愁，岩花但爭發。',48,'御定全唐詩/json/181.json','["顒望臨碧空，怨情感離別。江草不知愁，岩花但爭發。", "雲山萬重隔，音信千里絕。春去秋複來，相思幾時歇。"]'),
('yuding-48','姑孰十詠：牛渚磯','李白','唐','御定全唐诗','yuding','','[]','絕壁臨巨川，連峰勢相向。亂石流洑間，回波自成浪。',48,'御定全唐詩/json/181.json','["絕壁臨巨川，連峰勢相向。亂石流洑間，回波自成浪。", "但驚群木秀，莫測精靈狀。更聽猿夜啼，憂心醉江上。"]'),
('yuding-49','姑孰十詠：靈墟山','李白','唐','御定全唐诗','yuding','','[]','丁令辭世人，拂衣向仙路。伏煉九丹成，方隨五雲去。',48,'御定全唐詩/json/181.json','["丁令辭世人，拂衣向仙路。伏煉九丹成，方隨五雲去。", "松蘿蔽幽洞，桃杏深隱處。不知曾化鶴，遼海歸幾度。"]'),
('yuding-50','姑孰十詠：天門山','李白','唐','御定全唐诗','yuding','','[]','迥出江山上，雙峰自相對。岸映松色寒，石分浪花碎。',48,'御定全唐詩/json/181.json','["迥出江山上，雙峰自相對。岸映松色寒，石分浪花碎。", "參差遠天際，縹緲晴霞外。落日舟去遙，回首沉青靄。"]'),
('yuding-0','與元丹丘方城寺談玄作','李白','唐','御定全唐诗','yuding','','[]','茫茫大夢中，惟我獨先覺。騰轉風火來，假合作容貌。',108,'御定全唐詩/json/182.json','["茫茫大夢中，惟我獨先覺。騰轉風火來，假合作容貌。", "滅除昏疑盡，領略入精要。澄慮觀此身，因得通寂照。", "郎悟前後際，始知金仙妙。幸逢禪居人，酌玉坐相召。", "彼我俱若喪，雲山豈殊調。清風生虛空，明月見談笑。", "怡然青蓮宮，永願恣遊眺。"]'),
('yuding-1','尋高鳳石門山中元丹丘','李白','唐','御定全唐诗','yuding','','[]','尋幽無前期，乘興不覺遠。蒼崖渺難涉，白日忽欲晚。',120,'御定全唐詩/json/182.json','["尋幽無前期，乘興不覺遠。蒼崖渺難涉，白日忽欲晚。", "未窮三四山，已曆千萬轉。寂寂聞猿愁，行行見雲收。", "高松來好月，空穀宜清秋。溪深古雪在，石斷寒泉流。", "峰巒秀中天，登眺不可盡。丹丘遙相呼，顧我忽而哂。", "遂造窮穀間，始知靜者閑。留歡達永夜，清曉方言還。"]'),
('yuding-2','安州般若寺水閣納涼，喜遇薛員外乂','李白','唐','御定全唐诗','yuding','','[]','翛然金園賞，遠近含晴光。樓臺成海氣，草木皆天香。',84,'御定全唐詩/json/182.json','["翛然金園賞，遠近含晴光。樓臺成海氣，草木皆天香。", "忽逢青雲士，共解丹霞裳。水退池上熱，風生松下涼。", "吞討破萬象，搴窺臨眾芳。而我遺有漏，與君用無方。", "心垢都已滅，永言題禪房。"]'),
('yuding-3','魯中都東樓醉起作','李白','唐','御定全唐诗','yuding','','[]','昨日東樓醉，還應倒接z5。阿誰扶上馬，不省下樓時。',25,'御定全唐詩/json/182.json','["昨日東樓醉，還應倒接z5。阿誰扶上馬，不省下樓時。"]'),
('yuding-4','對酒醉題屈突明府廳','李白','唐','御定全唐诗','yuding','','[]','陶令八十日，長歌歸去來。故人建昌宰，借問幾時回。',48,'御定全唐詩/json/182.json','["陶令八十日，長歌歸去來。故人建昌宰，借問幾時回。", "風落吳江雪，紛紛入酒杯。山翁今已醉，舞袖為君開。"]'),
('yuding-5','月下獨酌四首','李白','唐','御定全唐诗','yuding','','[]','花間一壺酒，獨酌無相親。舉杯邀明月，對影成三人。',324,'御定全唐詩/json/182.json','["花間一壺酒，獨酌無相親。舉杯邀明月，對影成三人。", "月既不解飲，影徒隨我身。暫伴月將影，行樂須及春。", "我歌月裴回，我舞影零亂。醒時同交歡，醉後各分散。", "永結無情遊，相期邈雲漢。", "天若不愛酒，酒星不在天。地若不愛酒，地應無酒泉。", "天地既愛酒，愛酒不愧天。已聞清比聖，複道濁如賢。", "賢聖既已飲，何必求神仙。三杯通大道，一鬥合自然。", "但得酒中趣，勿為醒者傳。", "三月咸陽城，千花晝如錦。誰能春獨愁，對此徑須飲。", "窮通與修短，造化夙所稟。一樽齊死生，萬事固難審。", "醉後失天地，兀然就孤枕。不知有吾身，此樂最為甚。", "窮愁千萬端，美酒三百杯。愁多酒雖少，酒傾愁不來。", "所以知酒聖，酒酣心自開。辭粟臥首陽，屢空饑顏回。", "當代不樂飲，虛名安用哉。蟹螯即金液，糟丘是蓬萊。", "且須飲美酒，乘月醉高臺。"]'),
('yuding-6','春歸終南山松龕舊隱','李白','唐','御定全唐诗','yuding','','[]','我來南山陽，事事不異昔。卻尋溪中水，還望岩下石。',60,'御定全唐詩/json/182.json','["我來南山陽，事事不異昔。卻尋溪中水，還望岩下石。", "薔薇緣東窗，女蘿繞北壁。別來能幾日，草木長數尺。", "且複命酒樽，獨酌陶永夕。"]'),
('yuding-7','冬夜醉宿龍門，覺起言志','李白','唐','御定全唐诗','yuding','','[]','醉來脫寶劍，旅憩高堂眠。中夜忽驚覺，起立明燈前。',120,'御定全唐詩/json/182.json','["醉來脫寶劍，旅憩高堂眠。中夜忽驚覺，起立明燈前。", "開軒聊直望，曉雪河冰壯。哀哀歌苦寒，鬱鬱獨惆悵。", "傅說版築臣，李斯鷹犬人。欻起匡社稷，甯複長艱辛。", "而我胡為者，歎息龍門下。富貴未可期，殷憂向誰寫。", "去去淚滿襟，舉聲梁甫吟。青雲當自致，何必求知音。"]'),
('yuding-8','尋山僧不遇作','李白','唐','御定全唐诗','yuding','','[]','石徑入丹壑，松門閉青苔。閑階有鳥跡，禪室無人開。',84,'御定全唐詩/json/182.json','["石徑入丹壑，松門閉青苔。閑階有鳥跡，禪室無人開。", "窺窗見白拂，掛壁生塵埃。使我空歎息，欲去仍裴回。", "香雲遍山起，花雨從天來。已有空樂好，況聞青猿哀。", "了然絕世事，此地方悠哉。"]'),
('yuding-9','過汪氏別業二首','李白','唐','御定全唐诗','yuding','','[]','遊山誰可遊，子明與浮丘。疊嶺礙河漢，連峰橫鬥牛。',192,'御定全唐詩/json/182.json','["遊山誰可遊，子明與浮丘。疊嶺礙河漢，連峰橫鬥牛。", "汪生面北阜，池館清且幽。我來感意氣，捶炰列珍羞。", "掃石待歸月，開池漲寒流。酒酣益爽氣，為樂不知秋。", "疇昔未識君，知君好賢才。隨山起館宇，鑿石營池台。", "星火五月中，景風從南來。數枝石榴發，一丈荷花開。", "恨不當此時，相過醉金罍。我行值木落，月苦清猿哀。", "永夜達五更，吳歈送瓊杯。酒酣欲起舞，四座歌相催。", "日出遠海明，軒車且裴回。更游龍潭去，枕石拂莓苔。"]'),
('yuding-10','待酒不至','李白','唐','御定全唐诗','yuding','','[]','玉壺系青絲，沽酒來何遲。山花向我笑，正好銜杯時。',48,'御定全唐詩/json/182.json','["玉壺系青絲，沽酒來何遲。山花向我笑，正好銜杯時。", "晚酌東窗下，流鶯複在茲。春風與醉客，今日乃相宜。"]'),
('yuding-11','獨酌','李白','唐','御定全唐诗','yuding','','[]','春草如有意，羅生玉堂陰。東風吹愁來，白髮坐相侵。',72,'御定全唐詩/json/182.json','["春草如有意，羅生玉堂陰。東風吹愁來，白髮坐相侵。", "獨酌勸孤影，閑歌面芳林。長松爾何知，蕭瑟為誰吟。", "手舞石上月，膝橫花間琴。過此一壺外，悠悠非我心。"]'),
('yuding-12','友人會宿','李白','唐','御定全唐诗','yuding','','[]','滌蕩千古愁，留連百壺飲。良宵宜清談，皓月未能寢。',36,'御定全唐詩/json/182.json','["滌蕩千古愁，留連百壺飲。良宵宜清談，皓月未能寢。", "醉來臥空山，天地即衾枕。"]'),
('yuding-13','春日獨酌二首','李白','唐','御定全唐诗','yuding','','[]','東風扇淑氣，水木榮春暉。白日照綠草，落花散且飛。',120,'御定全唐詩/json/182.json','["東風扇淑氣，水木榮春暉。白日照綠草，落花散且飛。", "孤雲還空山，眾鳥各已歸。彼物皆有托，吾生獨無依。", "對此石上月，長醉歌芳菲。", "我有紫霞想，緬懷滄洲間。思對一壺酒，澹然萬事閑。", "橫琴倚高松，把酒望遠山。長空去鳥沒，落日孤雲還。", "但恐光景晚，宿昔成秋顏。"]'),
('yuding-14','金陵江上遇蓬池隱者','李白','唐','御定全唐诗','yuding','','[]','心愛名山遊，身隨名山遠。羅浮麻姑台，此去或未返。',132,'御定全唐詩/json/182.json','["心愛名山遊，身隨名山遠。羅浮麻姑台，此去或未返。", "遇君蓬池隱，就我石上飯。空言不成歡，強笑惜日晚。", "綠水向雁門，黃雲蔽龍山。歎息兩客鳥，裴回吳越間。", "共語一執手，留連夜將久。解我紫綺裘，且換金陵酒。", "酒來笑複歌，興酣樂事多。水影弄月色，清光奈愁何。", "明晨掛帆席，離恨滿滄波。"]'),
('yuding-15','月夜聽盧子順彈琴','李白','唐','御定全唐诗','yuding','','[]','閑坐夜明月，幽人彈素琴。忽聞悲風調，宛若寒松吟。',48,'御定全唐詩/json/182.json','["閑坐夜明月，幽人彈素琴。忽聞悲風調，宛若寒松吟。", "白雪亂纖手，綠水清虛心。鐘期久已沒，世上無知音。"]'),
('yuding-16','清溪半夜聞笛','李白','唐','御定全唐诗','yuding','','[]','羌笛梅花引，吳溪隴水情。寒山秋浦月，腸斷玉關聲。',24,'御定全唐詩/json/182.json','["羌笛梅花引，吳溪隴水情。寒山秋浦月，腸斷玉關聲。"]'),
('yuding-17','日夕山中忽然有懷','李白','唐','御定全唐诗','yuding','','[]','久臥青山雲，遂為青山客。山深雲更好，賞弄終日夕。',84,'御定全唐詩/json/182.json','["久臥青山雲，遂為青山客。山深雲更好，賞弄終日夕。", "月銜樓間峰，泉漱階下石。素心自此得，真趣非外惜。", "鼯啼桂方秋，風滅籟歸寂。緬思洪崖術，欲往滄海隔。", "雲車來何遲，撫幾空歎息。"]'),
('yuding-18','夏日山中','李白','唐','御定全唐诗','yuding','','[]','懶搖白羽扇，裸體青林中。脫巾掛石壁，露頂灑松風。',24,'御定全唐詩/json/182.json','["懶搖白羽扇，裸體青林中。脫巾掛石壁，露頂灑松風。"]'),
('yuding-19','山中與幽人對酌','李白','唐','御定全唐诗','yuding','','[]','兩人對酌山花開，一杯一杯複一杯。',32,'御定全唐詩/json/182.json','["兩人對酌山花開，一杯一杯複一杯。", "我醉欲眠卿且去，明朝有意抱琴來。"]'),
('yuding-20','春日醉起言志','李白','唐','御定全唐诗','yuding','','[]','處世若大夢，胡為勞其生。所以終日醉，頹然臥前楹。',72,'御定全唐詩/json/182.json','["處世若大夢，胡為勞其生。所以終日醉，頹然臥前楹。", "覺來盼庭前，一鳥花間鳴。借問此何時，春風語流鶯。", "感之欲歎息，對酒還自傾。浩歌待明月，曲盡已忘情。"]'),
('yuding-21','廬山東林寺夜懷','李白','唐','御定全唐诗','yuding','','[]','我尋青蓮宇，獨往謝城闕。霜清東林鐘，水白虎溪月。',60,'御定全唐詩/json/182.json','["我尋青蓮宇，獨往謝城闕。霜清東林鐘，水白虎溪月。", "天香生虛空，天樂鳴不歇。宴坐寂不動，大千入毫髮。", "湛然冥真心，曠劫斷出沒。"]'),
('yuding-22','尋雍尊師隱居','李白','唐','御定全唐诗','yuding','','[]','群峭碧摩天，逍遙不記年。撥雲尋古道，倚石聽流泉。',48,'御定全唐詩/json/182.json','["群峭碧摩天，逍遙不記年。撥雲尋古道，倚石聽流泉。", "花暖青牛臥，松高白鶴眠。語來江色暮，獨自下寒煙。"]'),
('yuding-23','與史郎中欽聽黃鶴樓上吹笛','李白','唐','御定全唐诗','yuding','','[]','一為遷客去長沙，西望長安不見家。',32,'御定全唐詩/json/182.json','["一為遷客去長沙，西望長安不見家。", "黃鶴樓中吹玉笛，江城五月落梅花。"]'),
('yuding-24','對酒','李白','唐','御定全唐诗','yuding','','[]','勸君莫拒杯，春風笑人來。桃李如舊識，傾花向我開。',84,'御定全唐詩/json/182.json','["勸君莫拒杯，春風笑人來。桃李如舊識，傾花向我開。", "流鶯啼碧樹，明月窺金罍。昨日朱顏子，今日白髮催。", "棘生石虎殿，鹿走姑蘇台。自古帝王宅，城闕閉黃埃。", "君若不飲酒，昔人安在哉。"]'),
('yuding-25','醉題王漢陽廳','李白','唐','御定全唐诗','yuding','','[]','我似鷓鴣鳥，南遷懶北飛。時尋漢陽令，取醉月中歸。',24,'御定全唐詩/json/182.json','["我似鷓鴣鳥，南遷懶北飛。時尋漢陽令，取醉月中歸。"]'),
('yuding-26','嘲王曆陽不肯飲酒','李白','唐','御定全唐诗','yuding','','[]','地白風色寒，雪花大如手。笑殺陶淵明，不飲杯中酒。',48,'御定全唐詩/json/182.json','["地白風色寒，雪花大如手。笑殺陶淵明，不飲杯中酒。", "浪撫一張琴，虛栽五株柳。空負頭上巾，吾于爾何有。"]'),
('yuding-27','獨坐敬亭山','李白','唐','御定全唐诗','yuding','','[]','眾鳥高飛盡，孤雲獨去閑。相看兩不厭，只有敬亭山。',24,'御定全唐詩/json/182.json','["眾鳥高飛盡，孤雲獨去閑。相看兩不厭，只有敬亭山。"]'),
('yuding-28','自遣','李白','唐','御定全唐诗','yuding','','[]','對酒不覺暝，落花盈我衣。醉起步溪月，鳥還人亦稀。',24,'御定全唐詩/json/182.json','["對酒不覺暝，落花盈我衣。醉起步溪月，鳥還人亦稀。"]'),
('yuding-29','訪戴天山道士不遇','李白','唐','御定全唐诗','yuding','','[]','犬吠水聲中，桃花帶雨濃。樹深時見鹿，溪午不聞鐘。',48,'御定全唐詩/json/182.json','["犬吠水聲中，桃花帶雨濃。樹深時見鹿，溪午不聞鐘。", "野竹分青靄，飛泉掛碧峰。無人知所去，愁倚兩三松。"]'),
('yuding-30','秋日與張少府、楚城韋公藏書高齋作','李白','唐','御定全唐诗','yuding','','[]','日下空庭暮，城荒古跡餘。地形連海盡，天影落江虛。',72,'御定全唐詩/json/182.json','["日下空庭暮，城荒古跡餘。地形連海盡，天影落江虛。", "舊賞人雖隔，新知樂未疏。彩雲思作賦，丹壁間藏書。", "楂擁隨流葉，萍開出水魚。夕來秋興滿，回首意何如。"]'),
('yuding-31','秋夜獨坐懷故山','李白','唐','御定全唐诗','yuding','','[]','小隱慕安石，遠遊學屈平。天書訪江海，雲臥起咸京。',120,'御定全唐詩/json/182.json','["小隱慕安石，遠遊學屈平。天書訪江海，雲臥起咸京。", "入侍瑤池宴，出陪玉輦行。誇胡新賦作，諫獵短書成。", "但奉紫霄顧，非邀青史名。莊周空說劍，墨翟恥論兵。", "拙薄遂疏絕，歸閒事耦耕。顧無蒼生望，空愛紫芝榮。", "寥落暝霞色，微茫舊壑情。秋山綠蘿月，今夕為誰明。"]'),
('yuding-32','憶崔郎中宗之游南陽遺吾孔子琴，撫之潸然感舊','李白','唐','御定全唐诗','yuding','','[]','昔在南陽城，唯餐獨山蕨。憶與崔宗之，白水弄素月。',96,'御定全唐詩/json/182.json','["昔在南陽城，唯餐獨山蕨。憶與崔宗之，白水弄素月。", "時過菊潭上，縱酒無休歇。泛此黃金花，頹然清歌發。", "一朝摧玉樹，生死殊飄忽。留我孔子琴，琴存人已歿。", "誰傳廣陵散，但哭邙山骨。泉戶何時明，長掃狐兔窟。"]'),
('yuding-33','憶東山二首','李白','唐','御定全唐诗','yuding','','[]','不向東山久，薔薇幾度花。白雲還自散，明月落誰家。',48,'御定全唐詩/json/182.json','["不向東山久，薔薇幾度花。白雲還自散，明月落誰家。", "我今攜謝妓，長嘯絕人群。欲報東山客，開關掃白雲。"]'),
('yuding-34','望月有懷','李白','唐','御定全唐诗','yuding','','[]','清泉映疏鬆，不知幾千古。寒月搖清波，流光入窗戶。',48,'御定全唐詩/json/182.json','["清泉映疏鬆，不知幾千古。寒月搖清波，流光入窗戶。", "對此空長吟，思君意何深。無因見安道，興盡愁人心。"]'),
('yuding-35','對酒憶賀監二首','李白','唐','御定全唐诗','yuding','','[]','四明有狂客，風流賀季真。長安一相見，呼我謫仙人。',96,'御定全唐詩/json/182.json','["四明有狂客，風流賀季真。長安一相見，呼我謫仙人。", "昔好杯中物，翻為松下塵。金龜換酒處，卻憶淚沾巾。", "狂客歸四明，山陰道士迎。敕賜鏡湖水，為君台沼榮。", "人亡餘故宅，空有荷花生。念此杳如夢，淒然傷我情。"]'),
('yuding-36','重憶一首','李白','唐','御定全唐诗','yuding','','[]','欲向江東去，定將誰舉杯。稽山無賀老，卻棹酒船回。',24,'御定全唐詩/json/182.json','["欲向江東去，定將誰舉杯。稽山無賀老，卻棹酒船回。"]'),
('yuding-37','春滯沅湘有懷山中','李白','唐','御定全唐诗','yuding','','[]','沅湘春色還，風暖煙草綠。古之傷心人，於此腸斷續。',48,'御定全唐詩/json/182.json','["沅湘春色還，風暖煙草綠。古之傷心人，於此腸斷續。", "予非懷沙客，但美采菱曲。所願歸東山，寸心於此足。"]'),
('yuding-38','落日憶山中','李白','唐','御定全唐诗','yuding','','[]','雨後煙景綠，晴天散餘霞。東風隨春歸，發我枝上花。',48,'御定全唐詩/json/182.json','["雨後煙景綠，晴天散餘霞。東風隨春歸，發我枝上花。", "花落時欲暮，見此令人嗟。願遊名山去，學道飛丹砂。"]'),
('yuding-39','憶秋浦桃花舊游，時竄夜郎','李白','唐','御定全唐诗','yuding','','[]','桃花春水生，白石今出沒。搖盪女蘿枝，半搖青天月。',48,'御定全唐詩/json/182.json','["桃花春水生，白石今出沒。搖盪女蘿枝，半搖青天月。", "不知舊行徑，初拳幾枝蕨。三載夜郎還，于茲煉金骨。"]'),
('yuding-0','越中秋懷','李白','唐','御定全唐诗','yuding','','[]','越水繞碧山，周回數千里。乃是天鏡中，分明畫相似。',96,'御定全唐詩/json/183.json','["越水繞碧山，周回數千里。乃是天鏡中，分明畫相似。", "愛此從冥搜，永懷臨湍遊。一為滄波客，十見紅蕖秋。", "觀濤壯天險，望海令人愁。路遐迫西照，歲晚悲東流。", "何必探禹穴，逝將歸蓬丘。不然五湖上，亦可乘扁舟。"]'),
('yuding-1','效古二首','李白','唐','御定全唐诗','yuding','','[]','朝入天苑中，謁帝蓬萊宮。青山映輦道，碧樹搖蒼空。',192,'御定全唐詩/json/183.json','["朝入天苑中，謁帝蓬萊宮。青山映輦道，碧樹搖蒼空。", "謬題金閨籍，得與銀台通。待詔奉明主，抽毫頌清風。", "歸時落日晚，躞蹀浮雲驄。人馬本無意，飛馳自豪雄。", "入門紫鴛鴦，金井雙梧桐。清歌弦古曲，美酒沽新豐。", "快意且為樂，列筵坐群公。光景不可留，生世如轉蓬。", "早達勝晚遇，羞比垂釣翁。", "自古有秀色，西施與東鄰。蛾眉不可妒，況乃效其顰。", "所以尹婕妤，羞見邢夫人。低頭不出氣，塞默少精神。", "寄語無鹽子，如君何足珍。"]'),
('yuding-2','擬古十二首','李白','唐','御定全唐诗','yuding','','[]','青天何歷歷，明星如白石。黃姑與織女，相去不盈尺。',540,'御定全唐詩/json/183.json','["青天何歷歷，明星如白石。黃姑與織女，相去不盈尺。", "銀河無鵲橋，非時將安適。閨人理紈素，遊子悲行役。", "瓶冰知冬寒，霜露欺遠客。客似秋葉飛，飄颻不言歸。", "別後羅帶長，愁寬去時衣。乘月托宵夢，因之寄金徽。", "高樓入青天，下有白玉堂。明月看欲墮，當窗懸清光。", "遙夜一美人，羅衣沾秋霜。含情弄柔瑟，彈作陌上桑。", "弦聲何激烈，風捲繞飛梁。行人皆躑躅，棲鳥起回翔。", "但寫妾意苦，莫辭此曲傷。願逢同心者，飛作紫鴛鴦。", "長繩難系日，自古共悲辛。黃金高北斗，不惜買陽春。", "石火無留光，還如世中人。即事已如夢，後來我誰身。", "提壺莫辭貧，取酒會四鄰。仙人殊恍惚，未若醉中真。", "清都綠玉樹，灼爍瑤台春。攀花弄秀色，遠贈天仙人。", "香風送紫蕊，直到扶桑津。取掇世上豔，所貴心之珍。", "相思傳一笑，聊欲示情親。", "今日風日好，明日恐不如。春風笑于人，何乃愁自居。", "吹簫舞彩鳳，酌醴鱠神魚。千金買一醉，取樂不求餘。", "達士遺天地，東門有二疏。愚夫同瓦石，有才知卷舒。", "無事坐悲苦，塊然涸轍魚。", "運速天地閉，胡風結飛霜。百草死冬月，六龍頹西荒。", "太白出東方，彗星揚精光。鴛鴦非越鳥，何為眷南翔。", "惟昔鷹將犬，今為侯與王。得水成蛟龍，爭池奪鳳凰。", "北斗不酌酒，南箕空簸揚。", "世路今太行，回車竟何托。萬族皆凋枯，遂無少可樂。", "曠野多白骨，幽魂共銷鑠。榮貴當及時，春華宜照灼。"]'),
('yuding-3','感興六首','李白','唐','御定全唐诗','yuding','','[]','瑤姬天帝女，精彩化朝雲。宛轉入宵夢，無心向楚君。',348,'御定全唐詩/json/183.json','["瑤姬天帝女，精彩化朝雲。宛轉入宵夢，無心向楚君。", "錦衾抱秋月，綺席空蘭芬。茫昧竟誰測，虛傳宋玉文。", "洛浦有宓妃，飄颻雪爭飛。輕雲拂素月，了可見清輝。", "解佩欲西去，含情詎相違。香塵動羅襪，綠水不沾衣。", "陳王徒作賦，神女豈同歸。好色傷大雅，多為世所譏。", "裂素持作書，將寄萬里懷。眷眷待遠信，竟歲無人來。", "征鴻務隨陽，又不為我棲。委之在深篋，蠹魚壞其題。", "何如投水中，流落他人開。不惜他人開，但恐生是非。", "十五游神仙，仙游未曾歇。吹笙坐松風，泛瑟窺海月。", "西山玉童子，使我煉金骨。欲逐黃鶴飛，相呼向蓬闕。", "西國有美女，結樓青雲端。蛾眉豔曉月，一笑傾城歡。", "高節不可奪，炯心如凝丹。常恐彩色晚，不為人所觀。", "安得配君子，共乘雙飛鸞。", "嘉谷隱豐草，草深苗且稀。農夫既不異，孤穗將安歸。", "常恐委疇隴，忽與秋蓬飛。烏得薦宗廟，為君生光輝。"]'),
('yuding-4','寓言三首','李白','唐','御定全唐诗','yuding','','[]','周公負斧扆，成王何夔夔。武王昔不豫，剪爪投河湄。',168,'御定全唐詩/json/183.json','["周公負斧扆，成王何夔夔。武王昔不豫，剪爪投河湄。", "賢聖遇讒慝，不免人君疑。天風拔大木，禾黍咸傷萎。", "管蔡扇蒼蠅，公賦鴟鴞詩。金縢若不啟，忠信誰明之。", "搖裔雙彩鳳，婉孌三青禽。往還瑤台裏，鳴舞玉山岑。", "以歡秦娥意，複得王母心。區區精衛鳥，銜木空哀吟。", "長安春色歸，先入青門道。綠楊不自持，從風欲傾倒。", "海燕還秦宮，雙飛入簾櫳。相思不相見，托夢遼城東。"]'),
('yuding-5','秋夕旅懷','李白','唐','御定全唐诗','yuding','','[]','涼風度秋海，吹我鄉思飛。連山去無際，流水何時歸。',72,'御定全唐詩/json/183.json','["涼風度秋海，吹我鄉思飛。連山去無際，流水何時歸。", "目極浮雲色，心斷明月暉。芳草歇柔豔，白露催寒衣。", "夢長銀漢落，覺罷天星稀。含悲想舊國，泣下誰能揮。"]'),
('yuding-6','感遇四首','李白','唐','御定全唐诗','yuding','','[]','吾愛王子晉，得道伊洛濱。金骨既不毀，玉顏長自春。',204,'御定全唐詩/json/183.json','["吾愛王子晉，得道伊洛濱。金骨既不毀，玉顏長自春。", "可憐浮丘公，猗靡與情親。舉首白日間，分明謝時人。", "二仙去已遠，夢想空殷勤。", "可歎東籬菊，莖疏葉且微。雖言異蘭蕙，亦自有芳菲。", "未泛盈樽酒，徒沾清露輝。當榮君不采，飄落欲何依。", "昔余聞姮娥，竊藥駐雲發。不自嬌玉顏，方希煉金骨。", "飛去身莫返，含笑坐明月。紫宮誇蛾眉，隨手會凋歇。", "宋玉事楚王，立身本高潔。巫山賦彩雲，郢路歌白雪。", "舉國莫能和，巴人皆捲舌。一感登徒言，恩情遂中絕。"]'),
('yuding-7','翰林讀書言懷，呈集賢諸學士','李白','唐','御定全唐诗','yuding','','[]','晨趨紫禁中，夕待金門詔。觀書散遺帙，探古窮至妙。',108,'御定全唐詩/json/183.json','["晨趨紫禁中，夕待金門詔。觀書散遺帙，探古窮至妙。", "片言苟會心，掩卷忽而笑。青蠅易相點，白雪難同調。", "本是疏散人，屢貽褊促誚。雲天屬清朗，林壑憶遊眺。", "或時清風來，閑倚欄下嘯。嚴光桐廬溪，謝客臨海嶠。", "功成謝人間，從此一投釣。"]'),
('yuding-8','尋陽紫極宮感秋作','李白','唐','御定全唐诗','yuding','','[]','何處聞秋聲，翛翛北窗竹。回薄萬古心，攬之不盈掬。',96,'御定全唐詩/json/183.json','["何處聞秋聲，翛翛北窗竹。回薄萬古心，攬之不盈掬。", "靜坐觀眾妙，浩然媚幽獨。白雲南山來，就我簷下宿。", "懶從唐生決，羞訪季主蔔。四十九年非，一往不可複。", "野情轉蕭灑，世道有翻覆。陶令歸去來，田家酒應熟。"]'),
('yuding-9','江上秋懷','李白','唐','御定全唐诗','yuding','','[]','餐霞臥舊壑，散發謝遠遊。山蟬號枯桑，始複知天秋。',84,'御定全唐詩/json/183.json','["餐霞臥舊壑，散發謝遠遊。山蟬號枯桑，始複知天秋。", "朔雁別海裔，越燕辭江樓。颯颯風卷沙，茫茫霧縈洲。", "黃雲結暮色，白水揚寒流。惻愴心自悲，潺湲淚難收。", "蘅蘭方蕭瑟，長歎令人愁。"]'),
('yuding-10','秋夕書懷','李白','唐','御定全唐诗','yuding','','[]','北風吹海雁，南渡落寒聲。感此瀟湘客，淒其流浪情。',96,'御定全唐詩/json/183.json','["北風吹海雁，南渡落寒聲。感此瀟湘客，淒其流浪情。", "海懷結滄洲，霞想遊赤城。始探蓬壺事，旋覺天地輕。", "澹然吟高秋，閑臥瞻太清。蘿月掩空幕，松霜結前楹。", "滅見息群動，獵微窮至精。桃花有源水，可以保吾生。"]'),
('yuding-11','避地司空原言懷','李白','唐','御定全唐诗','yuding','','[]','南風昔不競，豪聖思經綸。劉琨與祖逖，起舞雞鳴晨。',132,'御定全唐詩/json/183.json','["南風昔不競，豪聖思經綸。劉琨與祖逖，起舞雞鳴晨。", "雖有匡濟心，終為樂禍人。我則異於是，潛光皖水濱。", "卜築司空原，北將天柱鄰。雪霽萬里月，雲開九江春。", "俟乎泰階平，然後托微身。傾家事金鼎，年貌可長新。", "所願得此道，終然保清真。弄景奔日馭，攀星戲河津。", "一隨王喬去，長年玉天賓。"]'),
('yuding-12','上崔相百憂章','李白','唐','御定全唐诗','yuding','','[]','共公赫怒，天維中摧。鯤鯨噴蕩，揚濤起雷。魚龍陷人，',145,'御定全唐詩/json/183.json','["共公赫怒，天維中摧。鯤鯨噴蕩，揚濤起雷。魚龍陷人，", "箭發石開，戈揮日回。鄒衍慟哭，燕霜颯來，微誠不感。", "猶縶夏台。蒼鷹搏攫，丹棘崔嵬。豪聖凋枯，王風傷哀。", "斯文未喪，東嶽豈頹。穆逃楚難，鄒脫吳災。見機苦遲，", "萬憤結習，憂從中催。金瑟玉壺，盡為愁媒。舉酒太息，", "冶長非罪，尼父無猜。覆盆倘舉，應照寒灰。"]'),
('yuding-13','萬憤詞投魏郎中','李白','唐','御定全唐诗','yuding','','[]','海水渤潏，人罹鯨鯢。蓊胡沙而四塞，始滔天于燕齊。',158,'御定全唐詩/json/183.json','["海水渤潏，人罹鯨鯢。蓊胡沙而四塞，始滔天于燕齊。", "何六龍之浩蕩，遷白日于秦西。九土星分，嗷嗷棲棲。", "南冠君子，呼天而啼。戀高堂而掩泣，淚血地而成泥。", "獄戶春而不草，獨幽怨而沉迷。兄九江兮弟三峽，", "一門骨肉散百草，遇難不復相提攜。樹榛拔桂，", "好我者恤我，不好我者何忍臨危而相擠。子胥鴟夷，", "如其聽卑，脫我牢狴。儻辨美玉，君收白珪。"]'),
('yuding-14','荊州賊平，臨洞庭言懷作','李白','唐','御定全唐诗','yuding','','[]','修蛇橫洞庭，吞象臨江島。積骨成巴陵，遺言聞楚老。',120,'御定全唐詩/json/183.json','["修蛇橫洞庭，吞象臨江島。積骨成巴陵，遺言聞楚老。", "水窮三苗國，地窄三湘道。歲晏天崢嶸，時危人枯槁。", "思歸陰喪亂，去國傷懷抱。郢路方丘墟，章華亦傾倒。", "風悲猿嘯苦，木落鴻飛早。日隱西赤沙，月明東城草。", "關河望已絕，氛霧行當掃。長叫天可聞，吾將問蒼昊。"]'),
('yuding-15','覽鏡書懷','李白','唐','御定全唐诗','yuding','','[]','得道無古今，失道還衰老。自笑鏡中人，白髮如霜草。',48,'御定全唐詩/json/183.json','["得道無古今，失道還衰老。自笑鏡中人，白髮如霜草。", "捫心空歎息，問影何枯槁。桃李竟何言，終成南山皓。"]'),
('yuding-16','田園言懷','李白','唐','御定全唐诗','yuding','','[]','賈誼三年謫，班超萬里侯。何如牽白犢，飲水對清流。',24,'御定全唐詩/json/183.json','["賈誼三年謫，班超萬里侯。何如牽白犢，飲水對清流。"]'),
('yuding-17','江南春懷','李白','唐','御定全唐诗','yuding','','[]','青春幾何時，黃鳥鳴不歇。天涯失鄉路，江外老華髮。',60,'御定全唐詩/json/183.json','["青春幾何時，黃鳥鳴不歇。天涯失鄉路，江外老華髮。", "心飛秦塞雲，影滯楚關月。身世殊爛漫，田園久蕪沒。", "歲晏何所從，長歌謝金闕。"]'),
('yuding-18','聽蜀僧浚彈琴','李白','唐','御定全唐诗','yuding','','[]','蜀僧抱綠綺，西下峨眉峰。為我一揮手，如聽萬壑松。',48,'御定全唐詩/json/183.json','["蜀僧抱綠綺，西下峨眉峰。為我一揮手，如聽萬壑松。", "客心洗流水，餘響入霜鐘。不覺碧山暮，秋雲暗幾重。"]'),
('yuding-19','魯東門觀刈蒲','李白','唐','御定全唐诗','yuding','','[]','魯國寒事早，初霜刈渚蒲。揮鐮若轉月，拂水生連珠。',60,'御定全唐詩/json/183.json','["魯國寒事早，初霜刈渚蒲。揮鐮若轉月，拂水生連珠。", "此草最可珍，何必貴龍須。織作玉床席，欣承清夜娛。", "羅衣能再拂，不畏素塵蕪。"]'),
('yuding-20','詠鄰女東窗海石榴','李白','唐','御定全唐诗','yuding','','[]','魯女東窗下，海榴世所稀。珊瑚映綠水，未足比光輝。',60,'御定全唐詩/json/183.json','["魯女東窗下，海榴世所稀。珊瑚映綠水，未足比光輝。", "清香隨風發，落日好鳥歸。願為東南枝，低舉拂羅衣。", "無由共攀折，引領望金扉。"]'),
('yuding-21','南軒松','李白','唐','御定全唐诗','yuding','','[]','南軒有孤松，柯葉自綿冪。清風無閒時，瀟灑終日夕。',48,'御定全唐詩/json/183.json','["南軒有孤松，柯葉自綿冪。清風無閒時，瀟灑終日夕。", "陰生古苔綠，色染秋煙碧。何當淩雲霄，直上數千尺。"]'),
('yuding-22','詠山樽二首','李白','唐','御定全唐诗','yuding','','[]','蟠木不雕飾，且將斤斧疏。樽成山嶽勢，材是棟樑餘。',72,'御定全唐詩/json/183.json','["蟠木不雕飾，且將斤斧疏。樽成山嶽勢，材是棟樑餘。", "外與金罍並，中涵玉醴虛。慚君垂拂拭，遂忝玳筵居。", "擁腫寒山木，嵌空成酒樽。愧無江海量，偃蹇在君門。"]'),
('yuding-23','初出金門，尋王侍禦不遇，詠壁上鸚鵡','李白','唐','御定全唐诗','yuding','','[]','落羽辭金殿，孤鳴吒繡衣。能言終見棄，還向隴西飛。',24,'御定全唐詩/json/183.json','["落羽辭金殿，孤鳴吒繡衣。能言終見棄，還向隴西飛。"]'),
('yuding-24','紫藤樹','李白','唐','御定全唐诗','yuding','','[]','紫藤掛雲木，花蔓宜陽春。密葉隱歌鳥，香風留美人。',24,'御定全唐詩/json/183.json','["紫藤掛雲木，花蔓宜陽春。密葉隱歌鳥，香風留美人。"]'),
('yuding-25','觀放白鷹二首','李白','唐','御定全唐诗','yuding','','[]','八月邊風高，胡鷹白錦毛。孤飛一片雪，百里見秋毫。',44,'御定全唐詩/json/183.json','["八月邊風高，胡鷹白錦毛。孤飛一片雪，百里見秋毫。", "寒冬十二月，蒼鷹八九毛。寄言燕雀莫相啅，"]'),
('yuding-26','觀博平王志安少府山水粉圖','李白','唐','御定全唐诗','yuding','','[]','粉壁為空天，丹青狀江海。遊雲不知歸，日見白鷗在。',48,'御定全唐詩/json/183.json','["粉壁為空天，丹青狀江海。遊雲不知歸，日見白鷗在。", "博平真人王志安，沉吟至此願掛冠。松溪石磴帶秋色，"]'),
('yuding-27','題雍丘崔明府丹灶','李白','唐','御定全唐诗','yuding','','[]','美人為政本忘機，服藥求仙事不違。葉縣已泥丹灶畢，',40,'御定全唐詩/json/183.json','["美人為政本忘機，服藥求仙事不違。葉縣已泥丹灶畢，", "九轉但能生羽翼，雙鳧忽去定何依。"]'),
('yuding-28','觀元丹丘坐巫山屏風','李白','唐','御定全唐诗','yuding','','[]','昔遊三峽見巫山，見畫巫山宛相似。疑是天邊十二峰，',72,'御定全唐詩/json/183.json','["昔遊三峽見巫山，見畫巫山宛相似。疑是天邊十二峰，", "錦衾瑤席何寂寂，楚王神女徒盈盈。高咫尺，如千里，", "水石潺湲萬壑分，煙光草色俱氛氳。溪花笑日何年發，"]'),
('yuding-29','求崔山人百丈崖瀑布圖','李白','唐','御定全唐诗','yuding','','[]','百丈素崖裂，四山丹壁開。龍潭中噴射，晝夜生風雷。',72,'御定全唐詩/json/183.json','["百丈素崖裂，四山丹壁開。龍潭中噴射，晝夜生風雷。", "但見瀑泉落，如潈雲漢來。聞君寫真圖，島嶼備縈回。", "石黛刷幽草，曾青澤古苔。幽緘倘相傳，何必向天臺。"]'),
('yuding-30','見野草中有曰白頭翁者','李白','唐','御定全唐诗','yuding','','[]','醉入田家去，行歌荒野中。如何青草裏，亦有白頭翁。',48,'御定全唐詩/json/183.json','["醉入田家去，行歌荒野中。如何青草裏，亦有白頭翁。", "折取對明鏡，宛將衰鬢同。微芳似相誚，留恨向東風。"]'),
('yuding-31','流夜郎題葵葉','李白','唐','御定全唐诗','yuding','','[]','慚君能衛足，歎我遠移根。白日如分照，還歸守故園。',24,'御定全唐詩/json/183.json','["慚君能衛足，歎我遠移根。白日如分照，還歸守故園。"]'),
('yuding-32','塋禪師房觀山海圖','李白','唐','御定全唐诗','yuding','','[]','真僧閉精宇，滅跡含達觀。列嶂圖雲山，攢峰入霄漢。',120,'御定全唐詩/json/183.json','["真僧閉精宇，滅跡含達觀。列嶂圖雲山，攢峰入霄漢。", "丹崖森在目，清晝疑卷幔。蓬壺來軒窗，瀛海入幾案。", "煙濤爭噴薄，島嶼相淩亂。征帆飄空中，瀑水灑天半。", "崢嶸若可陟，想像徒盈歎。杳與真心冥，遂諧靜者玩。", "如登赤城裏，揭步滄洲畔。即事能娛人，從茲得消散。"]'),
('yuding-33','白鷺鶿','李白','唐','御定全唐诗','yuding','','[]','白鷺下秋水，孤飛如墜霜。心閑且未去，獨立沙洲傍。',24,'御定全唐詩/json/183.json','["白鷺下秋水，孤飛如墜霜。心閑且未去，獨立沙洲傍。"]'),
('yuding-34','詠槿','李白','唐','御定全唐诗','yuding','','[]','園花笑芳年，池草豔春色。猶不如槿花，嬋娟玉階側。',48,'御定全唐詩/json/183.json','["園花笑芳年，池草豔春色。猶不如槿花，嬋娟玉階側。", "芬榮何夭促，零落在瞬息。豈若瓊樹枝，終歲長翕赩。"]'),
('yuding-35','詠桂','李白','唐','御定全唐诗','yuding','','[]','世人種桃李，皆在金張門。攀折爭捷徑，及此春風暄。',60,'御定全唐詩/json/183.json','["世人種桃李，皆在金張門。攀折爭捷徑，及此春風暄。", "一朝天霜下，榮耀難久存。安知南山桂，綠葉垂芳根。", "清陰亦可托，何惜樹君園。"]'),
('yuding-36','白胡桃','李白','唐','御定全唐诗','yuding','','[]','紅羅袖裏分明見，白玉盤中看卻無。',32,'御定全唐詩/json/183.json','["紅羅袖裏分明見，白玉盤中看卻無。", "疑是老僧休念誦，腕前推下水晶珠。"]'),
('yuding-37','巫山枕障','李白','唐','御定全唐诗','yuding','','[]','巫山枕障畫高丘，白帝城邊樹色秋。',32,'御定全唐詩/json/183.json','["巫山枕障畫高丘，白帝城邊樹色秋。", "朝雲夜入無行處，巴水橫天更不流。"]'),
('yuding-38','南奔書懷','李白','唐','御定全唐诗','yuding','','[]','遙夜何漫漫，空歌白石爛。甯戚未匡齊，陳平終佐漢。',228,'御定全唐詩/json/183.json','["遙夜何漫漫，空歌白石爛。甯戚未匡齊，陳平終佐漢。", "欃槍掃河洛，直割鴻溝半。歷數方未遷，雲雷屢多難。", "天人秉旄鉞，虎竹光藩翰。侍筆黃金台，傳觴青玉案。", "不因秋風起，自有思歸歎。主將動讒疑，王師忽離叛。", "自來白沙上，鼓噪丹陽岸。賓禦如浮雲，從風各消散。", "舟中指可掬，城上骸爭爨。草草出近關，行行昧前算。", "南奔劇星火，北寇無涯畔。顧乏七寶鞭，留連道傍玩。", "太白夜食昴，長虹日中貫。秦趙興天兵，茫茫九州亂。", "感遇明主恩，頗高祖逖言。過江誓流水，志在清中原。", "拔劍擊前柱，悲歌難重論。"]'),
('yuding-0','題隨州紫陽先生壁','李白','唐','御定全唐诗','yuding','','[]','神農好長生，風俗久已成。複聞紫陽客，早署丹台名。',96,'御定全唐詩/json/184.json','["神農好長生，風俗久已成。複聞紫陽客，早署丹台名。", "喘息餐妙氣，步虛吟真聲。道與古仙合，心將元化並。", "樓疑出蓬海，鶴似飛玉京。松雪窗外曉，池水階下明。", "忽耽笙歌樂，頗失軒冕情。終願惠金液，提攜淩太清。"]'),
('yuding-1','題元丹丘山居','李白','唐','御定全唐诗','yuding','','[]','故人棲東山，自愛丘壑美。青春臥空林，白日猶不起。',48,'御定全唐詩/json/184.json','["故人棲東山，自愛丘壑美。青春臥空林，白日猶不起。", "松風清襟袖，石潭洗心耳。羨君無紛喧，高枕碧霞裏。"]'),
('yuding-2','題元丹丘潁陽山居','李白','唐','御定全唐诗','yuding','','[]','仙游渡潁水，訪隱同元君。忽遺蒼生望，獨與洪崖群。',96,'御定全唐詩/json/184.json','["仙游渡潁水，訪隱同元君。忽遺蒼生望，獨與洪崖群。", "卜地初晦跡，興言且成文。卻顧北山斷，前瞻南嶺分。", "遙通汝海月，不隔嵩丘雲。之子合逸趣，而我欽清芬。", "舉跡倚松石，談笑迷朝曛。益願狎青鳥，拂衣棲江濆。"]'),
('yuding-3','題瓜州新河，餞族叔舍人賁','李白','唐','御定全唐诗','yuding','','[]','齊公鑿新河，萬古流不絕。豐功利生人，天地同朽滅。',120,'御定全唐詩/json/184.json','["齊公鑿新河，萬古流不絕。豐功利生人，天地同朽滅。", "兩橋對雙閣，芳樹有行列。愛此如甘棠，誰雲敢攀折。", "吳關倚此固，天險自茲設。海水落斗門，湖平見沙汭。", "我行送季父，弭棹徒流悅。楊花滿江來，疑是龍山雪。", "惜此林下興，愴為山陽別。瞻望清路塵，歸來空寂滅。"]'),
('yuding-4','洗腳亭','李白','唐','御定全唐诗','yuding','','[]','白道向姑熟，洪亭臨道傍。前有昔時井，下有五丈床。',60,'御定全唐詩/json/184.json','["白道向姑熟，洪亭臨道傍。前有昔時井，下有五丈床。", "樵女洗素足，行人歇金裝。西望白鷺洲，蘆花似朝霜。", "送君此時去，回首淚成行。"]'),
('yuding-5','勞勞亭','李白','唐','御定全唐诗','yuding','','[]','天下傷心處，勞勞送客亭。春風知別苦，不遣柳條青。',24,'御定全唐詩/json/184.json','["天下傷心處，勞勞送客亭。春風知別苦，不遣柳條青。"]'),
('yuding-6','題金陵王處士水亭','李白','唐','御定全唐诗','yuding','','[]','王子耽玄言，賢豪多在門。好鵝尋道士，愛竹嘯名園。',84,'御定全唐詩/json/184.json','["王子耽玄言，賢豪多在門。好鵝尋道士，愛竹嘯名園。", "樹色老荒苑，池光蕩華軒。此堂見明月，更憶陸平原。", "掃拭青玉簟，為余置金尊。醉罷欲歸去，花枝宿鳥喧。", "何時複來此，再得洗囂煩。"]'),
('yuding-7','題嵩山逸人元丹丘山居','李白','唐','御定全唐诗','yuding','','[]','家本紫雲山，道風未淪落。沉懷丹丘志，沖賞歸寂寞。',168,'御定全唐詩/json/184.json','["家本紫雲山，道風未淪落。沉懷丹丘志，沖賞歸寂寞。", "朅來遊閩荒，捫涉窮禹鑿。夤緣泛潮海，偃蹇陟廬霍。", "憑雷躡天窗，弄影憩霞閣。且欣登眺美，頗愜隱淪諾。", "三山曠幽期，四嶽聊所托。故人契嵩潁，高義炳丹雘。", "滅跡遺紛囂，終言本峰壑。自矜林湍好，不羨朝市樂。", "偶與真意並，頓覺世情薄。爾能折芳桂，吾亦采蘭若。", "拙妻好乘鸞，嬌女愛飛鶴。提攜訪神仙，從此煉金藥。"]'),
('yuding-8','題江夏修靜寺','李白','唐','御定全唐诗','yuding','','[]','我家北海宅，作寺南江濱。空庭無玉樹，高殿坐幽人。',48,'御定全唐詩/json/184.json','["我家北海宅，作寺南江濱。空庭無玉樹，高殿坐幽人。", "書帶留青草，琴堂冪素塵。平生種桃李，寂滅不成春。"]'),
('yuding-9','題宛溪館','李白','唐','御定全唐诗','yuding','','[]','吾憐宛溪好，百尺照心明。何謝新安水，千尋見底清。',48,'御定全唐詩/json/184.json','["吾憐宛溪好，百尺照心明。何謝新安水，千尋見底清。", "白沙留月色，綠竹助秋聲。卻笑嚴湍上，於今獨擅名。"]'),
('yuding-10','題東溪公幽居','李白','唐','御定全唐诗','yuding','','[]','杜陵賢人清且廉，東溪蔔築歲將淹。宅近青山同謝脁，',40,'御定全唐詩/json/184.json','["杜陵賢人清且廉，東溪蔔築歲將淹。宅近青山同謝脁，", "客到但知留一醉，盤中只有水晶鹽。"]'),
('yuding-11','嘲魯儒','李白','唐','御定全唐诗','yuding','','[]','魯叟談五經，白髮死章句。問以經濟策，茫如墜煙霧。',84,'御定全唐詩/json/184.json','["魯叟談五經，白髮死章句。問以經濟策，茫如墜煙霧。", "足著遠遊履，首戴方山巾。緩步從直道，未行先起塵。", "秦家丞相府，不重褒衣人。君非叔孫通，與我本殊倫。", "時事且未達，歸耕汶水濱。"]'),
('yuding-12','懼讒','李白','唐','御定全唐诗','yuding','','[]','二桃殺三士，詎假劍如霜。眾女妒蛾眉，雙花競春芳。',60,'御定全唐詩/json/184.json','["二桃殺三士，詎假劍如霜。眾女妒蛾眉，雙花競春芳。", "魏姝信鄭袖，掩袂對懷王。一惑巧言子，朱顏成死傷。", "行將泣團扇，戚戚愁人腸。"]'),
('yuding-13','觀獵','李白','唐','御定全唐诗','yuding','','[]','太守耀清威，乘閑弄晚暉。江沙橫獵騎，山火繞行圍。',48,'御定全唐詩/json/184.json','["太守耀清威，乘閑弄晚暉。江沙橫獵騎，山火繞行圍。", "箭逐雲鴻落，鷹隨月兔飛。不知白日暮，歡賞夜方歸。"]'),
('yuding-14','觀胡人吹笛','李白','唐','御定全唐诗','yuding','','[]','胡人吹玉笛，一半是秦聲。十月吳山曉，梅花落敬亭。',48,'御定全唐詩/json/184.json','["胡人吹玉笛，一半是秦聲。十月吳山曉，梅花落敬亭。", "愁聞出塞曲，淚滿逐臣纓。卻望長安道，空懷戀主情。"]'),
('yuding-15','軍行','李白','唐','御定全唐诗','yuding','','[]','騮馬新跨白玉鞍，戰罷沙場月色寒。',32,'御定全唐詩/json/184.json','["騮馬新跨白玉鞍，戰罷沙場月色寒。", "城頭鐵鼓聲猶震，匣裏金刀血未幹。"]'),
('yuding-16','從軍行','李白','唐','御定全唐诗','yuding','','[]','百戰沙場碎鐵衣，城南已合數重圍。',32,'御定全唐詩/json/184.json','["百戰沙場碎鐵衣，城南已合數重圍。", "突營射殺呼延將，獨領殘兵千騎歸。"]'),
('yuding-17','平虜將軍妻','李白','唐','御定全唐诗','yuding','','[]','平虜將軍婦，入門二十年。君心自有悅，妾寵豈能專。',48,'御定全唐詩/json/184.json','["平虜將軍婦，入門二十年。君心自有悅，妾寵豈能專。", "出解床前帳，行吟道上篇。古人不唾井，莫忘昔纏綿。"]'),
('yuding-18','春夜洛城聞笛','李白','唐','御定全唐诗','yuding','','[]','誰家玉笛暗飛聲，散入春風滿洛城。',32,'御定全唐詩/json/184.json','["誰家玉笛暗飛聲，散入春風滿洛城。", "此夜曲中聞折柳，何人不起故園情。"]'),
('yuding-19','嵩山采菖蒲者','李白','唐','御定全唐诗','yuding','','[]','神仙多古貌，雙耳下垂肩。嵩岳逢漢武，疑是九疑仙。',60,'御定全唐詩/json/184.json','["神仙多古貌，雙耳下垂肩。嵩岳逢漢武，疑是九疑仙。", "我來采菖蒲，服食可延年。言終忽不見，滅影入雲煙。", "喻帝竟莫悟，終歸茂陵田。"]'),
('yuding-20','金陵聽韓侍禦吹笛','李白','唐','御定全唐诗','yuding','','[]','韓公吹玉笛，倜儻流英音。風吹繞鐘山，萬壑皆龍吟。',48,'御定全唐詩/json/184.json','["韓公吹玉笛，倜儻流英音。風吹繞鐘山，萬壑皆龍吟。", "王子停鳳管，師襄掩瑤琴。餘韻度江去，天涯安可尋。"]'),
('yuding-21','流夜郎聞酺不預','李白','唐','御定全唐诗','yuding','','[]','北闕聖人歌太康，南冠君子竄遐荒。',32,'御定全唐詩/json/184.json','["北闕聖人歌太康，南冠君子竄遐荒。", "漢酺聞奏鈞天樂，願得風吹到夜郎。"]'),
('yuding-22','放後遇恩不沾','李白','唐','御定全唐诗','yuding','','[]','天作雲與雷，霈然德澤開。東風日本至，白雉越裳來。',48,'御定全唐詩/json/184.json','["天作雲與雷，霈然德澤開。東風日本至，白雉越裳來。", "獨棄長沙國，三年未許回。何時入宣室，更問洛陽才。"]'),
('yuding-23','《宣城見杜鵑花','李白','唐','御定全唐诗','yuding','','[]','蜀國曾聞子規鳥，宣城還見杜鵑花。',32,'御定全唐詩/json/184.json','["蜀國曾聞子規鳥，宣城還見杜鵑花。", "一叫一回腸一斷，三春三月憶三巴。"]'),
('yuding-24','白田馬上聞鶯','李白','唐','御定全唐诗','yuding','','[]','黃鸝啄紫椹，五月鳴桑枝。我行不記日，誤作陽春時。',48,'御定全唐詩/json/184.json','["黃鸝啄紫椹，五月鳴桑枝。我行不記日，誤作陽春時。", "蠶老客未歸，白田已繅絲。驅馬又前去，捫心空自悲。"]'),
('yuding-25','三五七言','李白','唐','御定全唐诗','yuding','','[]','秋風清，秋月明。落葉聚還散，寒鴉棲複驚。',36,'御定全唐詩/json/184.json','["秋風清，秋月明。落葉聚還散，寒鴉棲複驚。", "相思相見知何日，此時此夜難為情。"]'),
('yuding-26','雜詩','李白','唐','御定全唐诗','yuding','','[]','白日與明月，晝夜尚不閑。況爾悠悠人，安得久世間。',72,'御定全唐詩/json/184.json','["白日與明月，晝夜尚不閑。況爾悠悠人，安得久世間。", "傳聞海水上，乃有蓬萊山。玉樹生綠葉，靈仙每登攀。", "一食駐玄發，再食留紅顏。吾欲從此去，去之無時還。"]'),
('yuding-27','寄遠十一首','李白','唐','御定全唐诗','yuding','','[]','三鳥別王母，銜書來見過。腸斷若剪弦，其如愁思何。',534,'御定全唐詩/json/184.json','["三鳥別王母，銜書來見過。腸斷若剪弦，其如愁思何。", "遙知玉窗裏，纖手弄雲和。奏曲有深意，青松交女蘿。", "寫水山井中，同泉豈殊波。秦心與楚恨，皎皎為誰多。", "青樓何所在，乃在碧雲中。寶鏡掛秋水，羅衣輕春風。", "新妝坐落日，悵望金屏空。念此送短書，願因雙飛鴻。", "本作一行書，殷勤道相憶。一行複一行，滿紙情何極。", "瑤台有黃鶴，為報青樓人。朱顏凋落盡，白髮一何新。", "自知未應還，離居經三春。桃李今若為，當窗發光彩。", "莫使香風飄，留與紅芳待。", "玉箸落春鏡，坐愁湖陽水。聞與陰麗華，風煙接鄰里。", "青春已複過，白日忽相催。但恐荷花晚，令人意已摧。", "相思不惜夢，日夜向陽臺。", "遠憶巫山陽，花明綠江暖。躊躇未得往，淚向南雲滿。", "春風複無情，吹我夢魂斷。不見眼中人，天長音信短。", "陽臺隔楚水，春草生黃河。相思無日夜，浩蕩若流波。", "流波向海去，欲見終無因。遙將一點淚，遠寄如花人。", "妾在舂陵東，君居漢江島。一日望花光，往來成白道。", "一為雲雨別，此地生秋草。秋草秋蛾飛，相思愁落暉。", "何由一相見，滅燭解羅衣。", "憶昨東園桃李紅碧枝，與君此時初別離。金瓶落井無消息，", "碧窗紛紛下落花，青樓寂寂空明月。兩不見，但相思。", "空留錦字表心素，至今緘愁不忍窺。", "長短春草綠，緣階如有情。卷施心獨苦，抽卻死還生。", "睹物知妾意，希君種後庭。閒時當采掇，念此莫相輕。"]'),
('yuding-28','長信宮','李白','唐','御定全唐诗','yuding','','[]','月皎昭陽殿，霜清長信宮。天行乘玉輦，飛燕與君同。',48,'御定全唐詩/json/184.json','["月皎昭陽殿，霜清長信宮。天行乘玉輦，飛燕與君同。", "別有歡娛處，承恩樂未窮。誰憐團扇妾，獨坐怨秋風。"]'),
('yuding-29','長門怨二首','李白','唐','御定全唐诗','yuding','','[]','天回北斗掛西樓，金屋無人螢火流。',64,'御定全唐詩/json/184.json','["天回北斗掛西樓，金屋無人螢火流。", "月光欲到長門殿，別作深宮一段愁。", "桂殿長愁不記春，黃金四屋起秋塵。", "夜懸明鏡青天上，獨照長門宮裏人。"]'),
('yuding-30','春怨','李白','唐','御定全唐诗','yuding','','[]','白馬金羈遼海東，羅帷繡被臥春風。',32,'御定全唐詩/json/184.json','["白馬金羈遼海東，羅帷繡被臥春風。", "落月低軒窺燭盡，飛花入戶笑床空。"]'),
('yuding-31','代贈遠','李白','唐','御定全唐诗','yuding','','[]','妾本洛陽人，狂夫幽燕客。渴飲易水波，由來多感激。',132,'御定全唐詩/json/184.json','["妾本洛陽人，狂夫幽燕客。渴飲易水波，由來多感激。", "胡馬西北馳，香鬃搖綠絲。鳴鞭從此去，逐虜蕩邊陲。", "昔去有好言，不言久離別。燕支多美女，走馬輕風雪。", "見此不記人，恩情雲雨絕。啼流玉箸盡，坐恨金閨切。", "織錦作短書，腸隨回文結。相思欲有寄，恐君不見察。", "焚之揚其灰，手跡自此滅。"]'),
('yuding-32','陌上贈美人','李白','唐','御定全唐诗','yuding','','[]','駿馬驕行踏落花，垂鞭直拂五雲車。',32,'御定全唐詩/json/184.json','["駿馬驕行踏落花，垂鞭直拂五雲車。", "美人一笑褰珠箔，遙指紅樓是妾家。"]'),
('yuding-33','閨情','李白','唐','御定全唐诗','yuding','','[]','流水去絕國，浮雲辭故關。水或戀前浦，雲猶歸舊山。',84,'御定全唐詩/json/184.json','["流水去絕國，浮雲辭故關。水或戀前浦，雲猶歸舊山。", "恨君流沙去，棄妾漁陽間。玉箸夜垂流，雙雙落朱顏。", "黃鳥坐相悲，綠楊誰更攀。織錦心草草，挑燈淚斑斑。", "窺鏡不自識，況乃狂夫還。"]'),
('yuding-34','代別情人','李白','唐','御定全唐诗','yuding','','[]','清水本不動，桃花發岸傍。桃花弄水色，波蕩搖春光。',108,'御定全唐詩/json/184.json','["清水本不動，桃花發岸傍。桃花弄水色，波蕩搖春光。", "我悅子容豔，子傾我文章。風吹綠琴去，曲度紫鴛鴦。", "昔作一水魚，今成兩枝鳥。哀哀長雞鳴，夜夜達五曉。", "起折相思樹，歸贈知寸心。覆水不可收，行雲難重尋。", "天涯有度鳥，莫絕瑤華音。"]'),
('yuding-35','代秋情','李白','唐','御定全唐诗','yuding','','[]','幾日相別離，門前生穞葵。寒蟬聒梧桐，日夕長鳴悲。',48,'御定全唐詩/json/184.json','["幾日相別離，門前生穞葵。寒蟬聒梧桐，日夕長鳴悲。", "白露濕螢火，清霜淩兔絲。空掩紫羅袂，長啼無盡時。"]'),
('yuding-36','對酒','李白','唐','御定全唐诗','yuding','','[]','蒲萄酒，金叵羅，吳姬十五細馬馱。青黛畫眉紅錦靴，',24,'御定全唐詩/json/184.json','["蒲萄酒，金叵羅，吳姬十五細馬馱。青黛畫眉紅錦靴，"]'),
('yuding-37','怨情','李白','唐','御定全唐诗','yuding','','[]','新人如花雖可寵，故人似玉由來重。花性飄揚不自持，',40,'御定全唐詩/json/184.json','["新人如花雖可寵，故人似玉由來重。花性飄揚不自持，", "請看陳後黃金屋，寂寂珠簾生網絲。"]'),
('yuding-38','湖邊採蓮婦','李白','唐','御定全唐诗','yuding','','[]','小姑織白紵，未解將人語。大嫂采芙蓉，溪湖千萬重。',48,'御定全唐詩/json/184.json','["小姑織白紵，未解將人語。大嫂采芙蓉，溪湖千萬重。", "長兄行不在，莫使外人逢。願學秋胡婦，貞心比古松。"]'),
('yuding-39','怨情','李白','唐','御定全唐诗','yuding','','[]','美人卷珠簾，深坐顰蛾眉。但見淚痕濕，不知心恨誰。',24,'御定全唐詩/json/184.json','["美人卷珠簾，深坐顰蛾眉。但見淚痕濕，不知心恨誰。"]'),
('yuding-40','代寄情，楚詞體','李白','唐','御定全唐诗','yuding','','[]','君不來兮，徒蓄怨積思而孤吟。雲陽一去已遠，',83,'御定全唐詩/json/184.json','["君不來兮，徒蓄怨積思而孤吟。雲陽一去已遠，", "朝馳余馬于青樓，怳若空而夷猶。浮雲深兮不得語，", "何無情而雨絕，夢雖往而交疏。橫流涕而長嗟，", "願為連根同死之秋草，不作飛空之落花。"]'),
('yuding-41','學古思邊','李白','唐','御定全唐诗','yuding','','[]','銜悲上隴首，腸斷不見君。流水若有情，幽哀從此分。',108,'御定全唐詩/json/184.json','["銜悲上隴首，腸斷不見君。流水若有情，幽哀從此分。", "蒼茫愁邊色，惆悵落日曛。山外接遠天，天際複有雲。", "白雁從中來，飛鳴苦難聞。足系一書劄，寄言難離群。", "離群心斷絕，十見花成雪。胡地無春暉，征人行不歸。", "相思杳如夢，珠淚濕羅衣。"]'),
('yuding-42','思邊','李白','唐','御定全唐诗','yuding','','[]','去年何時君別妾，南園綠草飛蝴蝶。今歲何時妾憶君，',24,'御定全唐詩/json/184.json','["去年何時君別妾，南園綠草飛蝴蝶。今歲何時妾憶君，"]'),
('yuding-43','口號吳王美人半醉','李白','唐','御定全唐诗','yuding','','[]','風動荷花水殿香，姑蘇臺上宴吳王。',32,'御定全唐詩/json/184.json','["風動荷花水殿香，姑蘇臺上宴吳王。", "西施醉舞嬌無力，笑倚東窗白玉床。"]'),
('yuding-44','代美人愁鏡二首','李白','唐','御定全唐诗','yuding','','[]','明明金鵲鏡，了了玉台前。拂拭交冰月，光輝何清圓。',98,'御定全唐詩/json/184.json','["明明金鵲鏡，了了玉台前。拂拭交冰月，光輝何清圓。", "紅顏老昨日，白髮多去年。鉛粉坐相誤，照來空淒然。", "美人贈此盤龍之寶鏡，燭我金縷之羅衣。時將紅袖拂明月，", "稿砧一別若箭弦，去有日，來無年。狂風吹卻妾心斷，"]'),
('yuding-45','贈段七娘','李白','唐','御定全唐诗','yuding','','[]','羅襪淩波生網塵，那能得計訪情親。',32,'御定全唐詩/json/184.json','["羅襪淩波生網塵，那能得計訪情親。", "千杯綠酒何辭醉，一面紅妝惱殺人。"]'),
('yuding-46','別內赴征三首','李白','唐','御定全唐诗','yuding','','[]','王命三征去未還，明朝離別出吳關。',96,'御定全唐詩/json/184.json','["王命三征去未還，明朝離別出吳關。", "白玉高樓看不見，相思須上望夫山。", "出門妻子強牽衣，問我西行幾日歸。", "歸時倘佩黃金印，莫學蘇秦不下機。", "翡翠為樓金作梯，誰人獨宿倚門啼。", "夜坐寒燈連曉月，行行淚盡楚關西。"]'),
('yuding-47','秋浦寄內','李白','唐','御定全唐诗','yuding','','[]','我今尋陽去，辭家千里餘。結荷倦水宿，卻寄大雷書。',96,'御定全唐詩/json/184.json','["我今尋陽去，辭家千里餘。結荷倦水宿，卻寄大雷書。", "雖不同辛苦，愴離各自居。我自入秋浦，三年北信疏。", "紅顏愁落盡，白髮不能除。有客自梁苑，手攜五色魚。", "開魚得錦字，歸問我何如。江山雖道阻，意合不為殊。"]'),
('yuding-48','自代內贈','李白','唐','御定全唐诗','yuding','','[]','寶刀截流水，無有斷絕時。妾意逐君行，纏綿亦如之。',180,'御定全唐詩/json/184.json','["寶刀截流水，無有斷絕時。妾意逐君行，纏綿亦如之。", "別來門前草，秋巷春轉碧。掃盡更還生，萋萋滿行跡。", "鳴鳳始相得，雄驚雌各飛。游雲落何山，一往不見歸。", "估客發大樓，知君在秋浦。梁苑空錦衾，陽臺夢行雨。", "妾家三作相，失勢去西秦。猶有舊歌管，淒清聞四鄰。", "曲度入紫雲，啼無眼中人。妾似井底桃，開花向誰笑。", "君如天上月，不肯一回照。窺鏡不自識，別多憔悴深。", "安得秦吉了，為人道寸心。"]'),
('yuding-49','秋浦感主人歸燕寄內','李白','唐','御定全唐诗','yuding','','[]','霜凋楚關木，始知殺氣嚴。寥寥金天廓，婉婉綠紅潛。',84,'御定全唐詩/json/184.json','["霜凋楚關木，始知殺氣嚴。寥寥金天廓，婉婉綠紅潛。", "胡燕別主人，雙雙語前簷。三飛四回顧，欲去複相瞻。", "豈不戀華屋，終然謝珠簾。我不及此鳥，遠行歲已淹。", "寄書道中歎，淚下不能緘。"]'),
('yuding-50','送內尋廬山女道士李騰空二首','李白','唐','御定全唐诗','yuding','','[]','君尋騰空子，應到碧山家。水舂雲母碓，風掃石楠花。',72,'御定全唐詩/json/184.json','["君尋騰空子，應到碧山家。水舂雲母碓，風掃石楠花。", "若愛幽居好，相邀弄紫霞。", "多君相門女，學道愛神仙。素手掬青靄，羅衣曳紫煙。", "一往屏風疊，乘鸞著玉鞭。"]'),
('yuding-51','贈內','李白','唐','御定全唐诗','yuding','','[]','三百六十日，日日醉如泥。雖為李白婦，何異太常妻。',24,'御定全唐詩/json/184.json','["三百六十日，日日醉如泥。雖為李白婦，何異太常妻。"]'),
('yuding-52','在潯陽非所寄內','李白','唐','御定全唐诗','yuding','','[]','聞難知慟哭，行啼入府中。多君同蔡琰，流淚請曹公。',60,'御定全唐詩/json/184.json','["聞難知慟哭，行啼入府中。多君同蔡琰，流淚請曹公。", "知登吳章嶺，昔與死無分。崎嶇行石道，外折入青雲。", "相見若悲歎，哀聲那可聞。"]'),
('yuding-53','南流夜郎寄內','李白','唐','御定全唐诗','yuding','','[]','夜郎天外怨離居，明月樓中音信疏。',32,'御定全唐詩/json/184.json','["夜郎天外怨離居，明月樓中音信疏。", "北雁春歸看欲盡，南來不得豫章書。"]'),
('yuding-54','越女詞五首','李白','唐','御定全唐诗','yuding','','[]','長幹吳兒女，眉目豔新月。屐上足如霜，不著鴉頭襪。',120,'御定全唐詩/json/184.json','["長幹吳兒女，眉目豔新月。屐上足如霜，不著鴉頭襪。", "吳兒多白皙，好為蕩舟劇。賣眼擲春心，折花調行客。", "耶溪採蓮女，見客棹歌回。笑入荷花去，佯羞不出來。", "東陽素足女，會稽素舸郎。相看月未墮，白地斷肝腸。", "鏡湖水如月，耶溪女似雪。新妝蕩新波，光景兩奇絕。"]'),
('yuding-55','浣紗石上女','李白','唐','御定全唐诗','yuding','','[]','玉面耶溪女，青娥紅粉妝。一雙金齒屐，兩足白如霜。',24,'御定全唐詩/json/184.json','["玉面耶溪女，青娥紅粉妝。一雙金齒屐，兩足白如霜。"]'),
('yuding-56','示金陵子','李白','唐','御定全唐诗','yuding','','[]','金陵城東誰家子，竊聽琴聲碧窗裏。落花一片天上來，',40,'御定全唐詩/json/184.json','["金陵城東誰家子，竊聽琴聲碧窗裏。落花一片天上來，", "謝公正要東山妓，攜手林泉處處行。"]'),
('yuding-57','出妓金陵子呈盧六四首','李白','唐','御定全唐诗','yuding','','[]','安石東山三十春，傲然攜妓出風塵。',112,'御定全唐詩/json/184.json','["安石東山三十春，傲然攜妓出風塵。", "樓中見我金陵子，何似陽臺雲雨人。", "南國新豐酒，東山小妓歌。對君君不樂，花月奈愁何。", "東道煙霞主，西江詩酒筵。相逢不覺醉，日墮曆陽川。", "小妓金陵歌楚聲，家僮丹砂學鳳鳴。", "我亦為君飲清酒，君心不肯向人傾。"]'),
('yuding-58','巴女詞','李白','唐','御定全唐诗','yuding','','[]','巴水急如箭，巴船去若飛。十月三千里，郎行幾歲歸。',24,'御定全唐詩/json/184.json','["巴水急如箭，巴船去若飛。十月三千里，郎行幾歲歸。"]'),
('yuding-59','哭晁卿衡','李白','唐','御定全唐诗','yuding','','[]','日本晁卿辭帝都，征帆一片繞蓬壺。',32,'御定全唐詩/json/184.json','["日本晁卿辭帝都，征帆一片繞蓬壺。", "明月不歸沉碧海，白雲愁色滿蒼梧。"]'),
('yuding-60','自溧水道哭王炎三首','李白','唐','御定全唐诗','yuding','','[]','白楊雙行行，白馬悲路傍。晨興見曉月，更似發雲陽。',200,'御定全唐詩/json/184.json','["白楊雙行行，白馬悲路傍。晨興見曉月，更似發雲陽。", "溧水通吳關，逝川去未央。故人萬化盡，閉骨茅山岡。", "天上墜玉棺，泉中掩龍章。名飛日月上，義與風雲翔。", "逸氣竟莫展，英圖俄夭傷。楚國一老人，來嗟龔勝亡。", "有言不可道，雪泣憶蘭芳。", "王公希代寶，棄世一何早。吊死不及哀，殯宮已秋草。", "悲來欲脫劍，掛向何枝好。哭向茅山雖未摧，", "王家碧瑤樹，一樹忽先摧。海內故人泣，天涯吊鶴來。", "未成霖雨用，先失濟川材。一罷廣陵散，鳴琴更不開。"]'),
('yuding-61','哭宣城善釀紀叟','李白','唐','御定全唐诗','yuding','','[]','紀叟黃泉裏，還應釀老春。夜台無曉日，沽酒與何人。',24,'御定全唐詩/json/184.json','["紀叟黃泉裏，還應釀老春。夜台無曉日，沽酒與何人。"]'),
('yuding-62','宣城哭蔣征君華','李白','唐','御定全唐诗','yuding','','[]','敬亭埋玉樹，知是蔣征君。安得相如草，空餘封禪文。',48,'御定全唐詩/json/184.json','["敬亭埋玉樹，知是蔣征君。安得相如草，空餘封禪文。", "池台空有月，詞賦舊淩雲。獨掛延陵劍，千秋在古墳。"]'),
('yuding-0','鞠歌行','李白','唐','御定全唐诗','yuding','','[]','麗莫似漢宮妃，謙莫似黃家女。黃女持謙齒發高，',87,'御定全唐詩/json/185.json','["麗莫似漢宮妃，謙莫似黃家女。黃女持謙齒發高，", "君不見蔡澤嵌枯詭怪之形狀，大言直取秦丞相。", "又不見田千秋才智不出人，一朝富貴如有神。", "二侯行事在方冊，泣麟老人終困厄。夜光抱恨良歎悲，"]'),
('yuding-1','胡無人','李白','唐','御定全唐诗','yuding','','[]','十萬羽林兒，臨洮破郅支。殺添胡地骨，降足漢營旗。',48,'御定全唐詩/json/185.json','["十萬羽林兒，臨洮破郅支。殺添胡地骨，降足漢營旗。", "塞闊牛羊散，兵休帳幕移。空餘隴頭水，嗚咽向人悲。"]'),
('yuding-2','月夜金陵懷古','李白','唐','御定全唐诗','yuding','','[]','蒼蒼金陵月，空懸帝王州。天文列宿在，霸業大江流。',72,'御定全唐詩/json/185.json','["蒼蒼金陵月，空懸帝王州。天文列宿在，霸業大江流。", "綠水絕馳道，青松摧古丘。台傾鳷鵲觀，宮沒鳳凰樓。", "別殿悲清暑，芳園罷樂遊。一聞歌玉樹，蕭瑟後庭秋。"]'),
('yuding-3','冬日歸舊山','李白','唐','御定全唐诗','yuding','','[]','未洗染塵纓，歸來芳草平。一條藤徑綠，萬點雪峰晴。',120,'御定全唐詩/json/185.json','["未洗染塵纓，歸來芳草平。一條藤徑綠，萬點雪峰晴。", "地冷葉先盡，穀寒雲不行。嫩篁侵舍密，古樹倒江橫。", "白犬離村吠，蒼苔壁上生。穿廚孤雉過，臨屋舊猿鳴。", "木落禽巢在，籬疏獸路成。拂床蒼鼠走，倒篋素魚驚。", "洗硯修良策，敲松擬素貞。此時重一去，去合到三清。"]'),
('yuding-4','望夫石','李白','唐','御定全唐诗','yuding','','[]','仿佛古容儀，含愁帶曙輝。露如今日淚，苔似昔年衣。',48,'御定全唐詩/json/185.json','["仿佛古容儀，含愁帶曙輝。露如今日淚，苔似昔年衣。", "有恨同湘女，無言類楚妃。寂然芳靄內，猶若待夫歸。"]'),
('yuding-5','對雨','李白','唐','御定全唐诗','yuding','','[]','捲簾聊舉目，露濕草綿芊。古岫藏雲毳，空庭織碎煙。',48,'御定全唐詩/json/185.json','["捲簾聊舉目，露濕草綿芊。古岫藏雲毳，空庭織碎煙。", "水紋愁不起，風線重難牽。盡日扶犁叟，往來江樹前。"]'),
('yuding-6','曉晴','李白','唐','御定全唐诗','yuding','','[]','野涼疏雨歇，春色遍萋萋。魚躍青池滿，鶯吟綠樹低。',48,'御定全唐詩/json/185.json','["野涼疏雨歇，春色遍萋萋。魚躍青池滿，鶯吟綠樹低。", "野花妝面濕，山草紐斜齊。零落殘雲片，風吹掛竹溪。"]'),
('yuding-7','初月','李白','唐','御定全唐诗','yuding','','[]','玉蟾離海上，白露濕花時。雲畔風生爪，沙頭水浸眉。',48,'御定全唐詩/json/185.json','["玉蟾離海上，白露濕花時。雲畔風生爪，沙頭水浸眉。", "樂哉弦管客，愁殺戰征兒。因絕西園賞，臨風一詠詩。"]'),
('yuding-8','雨後望月','李白','唐','御定全唐诗','yuding','','[]','四郊陰靄散，開戶半蟾生。萬里舒霜合，一條江練橫。',48,'御定全唐詩/json/185.json','["四郊陰靄散，開戶半蟾生。萬里舒霜合，一條江練橫。", "出時山眼白，高後海心明。為惜如團扇，長吟到五更。"]'),
('yuding-9','賦得鶴，送史司馬赴崔相公幕','李白','唐','御定全唐诗','yuding','','[]','崢嶸丞相府，清切鳳凰池。羨爾瑤台鶴，高棲瓊樹枝。',72,'御定全唐詩/json/185.json','["崢嶸丞相府，清切鳳凰池。羨爾瑤台鶴，高棲瓊樹枝。", "歸飛晴日好，吟弄惠風吹。正有乘軒樂，初當學舞時。", "珍禽在羅網，微命若遊絲。願托周周羽，相銜漢水湄。"]'),
('yuding-10','送客歸吳','李白','唐','御定全唐诗','yuding','','[]','江村秋雨歇，酒盡一帆飛。路曆波濤去，家惟坐臥歸。',48,'御定全唐詩/json/185.json','["江村秋雨歇，酒盡一帆飛。路曆波濤去，家惟坐臥歸。", "島花開灼灼，汀柳細依依。別後無餘事，還應掃釣磯。"]'),
('yuding-11','送友生游峽中','李白','唐','御定全唐诗','yuding','','[]','風靜楊柳垂，看花又別離。幾年同在此，今日各驅馳。',48,'御定全唐詩/json/185.json','["風靜楊柳垂，看花又別離。幾年同在此，今日各驅馳。", "峽裏聞猿叫，山頭見月時。殷勤一杯酒，珍重歲寒姿。"]'),
('yuding-12','送袁明府任長沙','李白','唐','御定全唐诗','yuding','','[]','別離楊柳青，樽酒表丹誠。古道攜琴去，深山見峽迎。',48,'御定全唐詩/json/185.json','["別離楊柳青，樽酒表丹誠。古道攜琴去，深山見峽迎。", "暖風花繞樹，秋雨草沿城。自此長江內，無因夜犬驚。"]'),
('yuding-13','鄒衍穀','李白','唐','御定全唐诗','yuding','','[]','燕穀無暖氣，窮岩閉嚴陰。鄒子一吹律，能回天地心。',24,'御定全唐詩/json/185.json','["燕穀無暖氣，窮岩閉嚴陰。鄒子一吹律，能回天地心。"]'),
('yuding-14','《雜言用投丹陽知己兼奉宣慰判官','李白','唐','御定全唐诗','yuding','','[]','客從昆侖來，遺我雙玉璞。雲是古之得道者西王母食之餘，',86,'御定全唐詩/json/185.json','["客從昆侖來，遺我雙玉璞。雲是古之得道者西王母食之餘，", "如今雖在卞和手，□□正憔悴，了了知之亦何益。", "恭聞士有調相如，始從鎬京還，複欲鎬京去。能上秦王殿，", "無棄捐，服之與君俱神仙。"]'),
('yuding-15','觀魚潭','李白','唐','御定全唐诗','yuding','','[]','觀魚碧潭上，木落潭水清。日暮紫鱗躍，圓波處處生。',48,'御定全唐詩/json/185.json','["觀魚碧潭上，木落潭水清。日暮紫鱗躍，圓波處處生。", "涼煙浮竹盡，秋月照沙明。何必滄浪去，茲焉可濯纓。"]'),
('yuding-16','自廣平乘醉走馬六十裏至邯鄲，登城樓覽古書懷','李白','唐','御定全唐诗','yuding','','[]','醉騎白花馬，西走邯鄲城。揚鞭動柳色，寫鞚春風生。',240,'御定全唐詩/json/185.json','["醉騎白花馬，西走邯鄲城。揚鞭動柳色，寫鞚春風生。", "入郭登高樓，山川與雲平。深宮翳綠草，萬事傷人情。", "相如章華巔，猛氣折秦嬴。兩虎不可鬥，廉公終負荊。", "提攜袴中兒，杵臼及程嬰。立孤就白刃，必死耀丹誠。", "平原三千客，談笑盡豪英。毛君能穎脫，二國且同盟。", "皆為黃泉土，使我涕縱橫。磊磊石子岡，蕭蕭白楊聲。", "諸賢沒此地，碑版有殘銘。太古共今時，由來互哀榮。", "傷哉何足道，感激仰空名。趙俗愛長劍，文儒少逢迎。", "閑從博陵遊，暢飲雪朝酲。歌酣易水動，鼓震叢台傾。", "日落把燭歸，淩晨向燕京。方陳五餌策，一使胡塵清。"]'),
('yuding-17','宣州長史弟昭贈余琴溪中雙舞鶴詩以見志','李白','唐','御定全唐诗','yuding','','[]','令弟佐宣城，贈餘琴溪鶴。謂言天涯雪，忽向窗前落。',72,'御定全唐詩/json/185.json','["令弟佐宣城，贈餘琴溪鶴。謂言天涯雪，忽向窗前落。", "白玉為毛衣，黃金不肯博。背風振六翮，對舞臨山閣。", "顧我如有情，長鳴似相托。何當駕此物，與爾騰寥廓。"]'),
('yuding-18','題舒州司空山瀑布','李白','唐','御定全唐诗','yuding','','[]','斷崖如削瓜，嵐光破崖綠。天河從中來，白雲漲川穀。',48,'御定全唐詩/json/185.json','["斷崖如削瓜，嵐光破崖綠。天河從中來，白雲漲川穀。", "玉案赤文字，世眼不可讀。攝身淩青霄，松風拂我足。"]'),
('yuding-19','金陵新亭','李白','唐','御定全唐诗','yuding','','[]','金陵風景好，豪士集新亭。舉目山河異，偏傷周顗情。',48,'御定全唐詩/json/185.json','["金陵風景好，豪士集新亭。舉目山河異，偏傷周顗情。", "四坐楚囚悲，不憂社稷傾。王公何慷慨，千載仰雄名。"]'),
('yuding-20','《上清寶鼎詩','李白','唐','御定全唐诗','yuding','','[]','我居清空表，君處紅埃中。仙人持玉尺，廢君多少才。',72,'御定全唐詩/json/185.json','["我居清空表，君處紅埃中。仙人持玉尺，廢君多少才。", "玉尺不可盡，君才無時休。", "咽服十二環，奄有仙人房。暮騎紫麟去，海氣侵肌涼。", "贈我累累珠，靡靡明月光。"]'),
('yuding-21','《題許宣平庵壁','李白','唐','御定全唐诗','yuding','','[]','我吟傳舍詠，來訪真人居。煙嶺迷高跡，雲林隔太虛。',48,'御定全唐詩/json/185.json','["我吟傳舍詠，來訪真人居。煙嶺迷高跡，雲林隔太虛。", "窺庭但蕭瑟，倚杖空躊躇。應化遼天鶴，歸當千歲餘。"]'),
('yuding-22','《戲贈杜甫','李白','唐','御定全唐诗','yuding','','[]','飯顆山頭逢杜甫，頂戴笠子日卓午。',32,'御定全唐詩/json/185.json','["飯顆山頭逢杜甫，頂戴笠子日卓午。", "借問別來太瘦生，總為從前作詩苦。"]'),
('yuding-23','春感詩','李白','唐','御定全唐诗','yuding','','[]','茫茫南與北，道直事難諧。榆莢錢生樹，楊花玉糝街。',48,'御定全唐詩/json/185.json','["茫茫南與北，道直事難諧。榆莢錢生樹，楊花玉糝街。", "塵縈遊子面，蝶弄美人釵。卻憶青山上，雲門掩竹齋。"]'),
('yuding-24','白微時募縣小吏入令臥內嘗驅牛經堂下令妻怒將加詰責白亟以詩謝云','李白','唐','御定全唐诗','yuding','','[]','素面倚欄鉤，嬌聲出外頭。若非是織女，何得問牽牛。',24,'御定全唐詩/json/185.json','["素面倚欄鉤，嬌聲出外頭。若非是織女，何得問牽牛。"]'),
('yuding-25','句','李白','唐','御定全唐诗','yuding','','[]','焰隨紅日去，煙逐暮雲飛。',48,'御定全唐詩/json/185.json','["焰隨紅日去，煙逐暮雲飛。", "綠鬢隨波散，紅顏逐浪無。", "因何逢伍相，應是想秋胡。", "舉袖露條脫，招我飯胡麻。"]'),
('yuding-0','擬古詩十二首','韋應物','唐','御定全唐诗','yuding','','[]','辭君遠行邁，飲此長恨端。已謂道裏遠，如何中險艱。',564,'御定全唐詩/json/186.json','["辭君遠行邁，飲此長恨端。已謂道裏遠，如何中險艱。", "流水赴大壑，孤雲還暮山。無情尚有歸，行子何獨難。", "驅車背鄉園，朔風卷行跡。嚴冬霜斷肌，日入不遑息。", "憂歡容發變，寒暑人事易。中心君詎知，冰玉徒貞白。", "黃鳥何關關，幽蘭亦靡靡。此時深閨婦，日照紗窗裏。", "娟娟雙青娥，微微啟玉齒。自惜桃李年，誤身遊俠子。", "無事久離別，不知今生死。", "峨峨高山巔，浼浼青川流。世人不自悟，馳謝如驚飍。", "百金非所重，厚意良難得。旨酒親與朋，芳年樂京國。", "京城繁華地，軒蓋淩晨出。垂楊十二衢，隱映金張室。", "漢宮南北對，飛觀齊白日。游泳屬芳時，平生自雲畢。", "綺樓何氛氳，朝日正杲杲。四壁含清風，丹霞射其牖。", "玉顏上哀囀，絕耳非世有。但感離恨情，不知誰家婦。", "孤雲忽無色，邊馬為回首。曲絕碧天高，餘聲散秋草。", "徘徊帷中意，獨夜不堪守。思逐朔風翔，一去千里道。", "嘉樹藹初綠，靡蕪葉幽芳。君子不在賞，寄之雲路長。", "路長信難越，惜此芳時歇。孤鳥去不還，緘情向天末。", "月滿秋夜長，驚鳥號北林。天河橫未落，斗柄當西南。", "寒蛩悲洞房，好鳥無遺音。商飆一夕至，獨宿懷重衾。", "舊交日千里，隔我浮與沉。人生豈草木，寒暑移此心。", "酒星非所酌，月桂不為食。虛薄空有名，為君長歎息。", "蘭蕙雖可懷，芳香與時息。豈如淩霜葉，歲暮藹顏色。", "折柔將有贈，延意千里客。草木知賤微，所貴寒不易。", "神州高爽地，遐瞰靡不通。寒月野無綠，寥寥天宇空。"]'),
('yuding-1','雜體五首','韋應物','唐','御定全唐诗','yuding','','[]','沉沉匣中鏡，為此塵垢蝕。輝光何所如，月在雲中黑。',324,'御定全唐詩/json/186.json','["沉沉匣中鏡，為此塵垢蝕。輝光何所如，月在雲中黑。", "南金既雕錯，鞶帶共輝飾。空存鑒物名，坐使妍蚩惑。", "美人竭肝膽，思照冰玉色。自非磨瑩工，日日空歎息。", "古宅集祆鳥，群號枯樹枝。黃昏窺人室，鬼物相與期。", "居人不安寢，搏擊思此時。豈無鷹與鸇，飽肉不肯飛。", "既乖逐鳥節，空養淩雲姿。孤負肉食恩，何異城上鴟。", "春羅雙鴛鴦，出自寒夜女。心精煙霧色，指曆千萬緒。", "長安貴豪家，妖豔不可數。裁此百日功，唯將一朝舞。", "舞罷複裁新，豈思勞者苦。", "同聲自相應，體質不必齊。誰知賈人鐸，能使大樂諧。", "鏗鏘發宮征，和樂變其哀。人神既昭享，鳳鳥亦下來。", "豈非至賤物，一奏升天階。物情苟有合，莫問玉與泥。", "碌碌荊山璞，卞和獻君門。荊璞非有求，和氏非有恩。", "所獻知國寶，至公不待言。是非吾欲默，此道今豈存。"]'),
('yuding-2','與友生野飲效陶體','韋應物','唐','御定全唐诗','yuding','','[]','攜酒花林下，前有千載墳。于時不共酌，奈此泉下人。',60,'御定全唐詩/json/186.json','["攜酒花林下，前有千載墳。于時不共酌，奈此泉下人。", "始自玩芳物，行當念徂春。聊舒遠世蹤，坐望還山雲。", "且遂一歡笑，焉知賤與貧。"]'),
('yuding-3','效何水部二首','韋應物','唐','御定全唐诗','yuding','','[]','玉宇含清露，香籠散輕煙。應當結沉抱，難從茲夕眠。',48,'御定全唐詩/json/186.json','["玉宇含清露，香籠散輕煙。應當結沉抱，難從茲夕眠。", "夕漏起遙恨，蟲響亂秋陰。反復相思字，中有故人心。"]'),
('yuding-4','效陶彭澤','韋應物','唐','御定全唐诗','yuding','','[]','霜露悴百草，時菊獨妍華。物性有如此，寒暑其奈何。',48,'御定全唐詩/json/186.json','["霜露悴百草，時菊獨妍華。物性有如此，寒暑其奈何。", "掇英泛濁醪，日入會田家。盡醉茅簷下，一生豈在多。"]'),
('yuding-5','大樑亭會李四棲梧作','韋應物','唐','御定全唐诗','yuding','','[]','梁王昔愛才，千古化不泯。至今蓬池上，遠集八方賓。',120,'御定全唐詩/json/186.json','["梁王昔愛才，千古化不泯。至今蓬池上，遠集八方賓。", "車馬平明合，城郭滿埃塵。逢君一相許，豈要平生親。", "入仕三十載，如何獨未伸。英聲久籍籍，台閣多故人。", "置酒發清彈，相與樂佳辰。孤亭得長望，白日下廣津。", "富貴良可取，朅來西入秦。秋風旦夕起，安得客梁陳。"]'),
('yuding-6','燕李錄事','韋應物','唐','御定全唐诗','yuding','','[]','與君十五侍皇闈，曉拂爐煙上赤墀。花開漢苑經過處，',40,'御定全唐詩/json/186.json','["與君十五侍皇闈，曉拂爐煙上赤墀。花開漢苑經過處，", "此日相逢思舊日，一杯成喜亦成悲。"]'),
('yuding-7','淮上喜會梁川故人','韋應物','唐','御定全唐诗','yuding','','[]','江漢曾為客，相逢每醉還。浮雲一別後，流水十年間。',48,'御定全唐詩/json/186.json','["江漢曾為客，相逢每醉還。浮雲一別後，流水十年間。", "歡笑情如舊，蕭疏鬢已斑。何因北歸去，淮上對秋山。"]'),
('yuding-8','揚州偶會前洛陽盧耿主簿','韋應物','唐','御定全唐诗','yuding','','[]','楚塞故人稀，相逢本不期。猶存袖裏字，忽怪鬢中絲。',48,'御定全唐詩/json/186.json','["楚塞故人稀，相逢本不期。猶存袖裏字，忽怪鬢中絲。", "客舍盈樽酒，江行滿篋詩。更能連騎出，還似洛橋時。"]'),
('yuding-9','賈常侍林亭燕集','韋應物','唐','御定全唐诗','yuding','','[]','高賢侍天陛，跡顯心獨幽。朱軒騖關右，池館在東周。',132,'御定全唐詩/json/186.json','["高賢侍天陛，跡顯心獨幽。朱軒騖關右，池館在東周。", "繚繞接都城，氤氳望嵩丘。群公盡詞客，方駕永日遊。", "朝旦氣候佳，逍遙寫煩憂。綠林藹已布，華沼澹不流。", "沒露摘幽草，涉煙玩輕舟。圓荷既出水，廣廈可淹留。", "放神遺所拘，觥罰屢見酬。樂燕良未極，安知有沉浮。", "醉罷各雲散，何當複相求。"]'),
('yuding-10','月下會徐十一草堂','韋應物','唐','御定全唐诗','yuding','','[]','空齋無一事，岸幘故人期。暫輟觀書夜，還題玩月詩。',48,'御定全唐詩/json/186.json','["空齋無一事，岸幘故人期。暫輟觀書夜，還題玩月詩。", "遠鐘高枕後，清露捲簾時。暗覺新秋近，殘河欲曙遲。"]'),
('yuding-11','移疾會詩客元生與釋子法朗，因貽諸祠曹','韋應物','唐','御定全唐诗','yuding','','[]','對此嘉樹林，獨有戚戚顏。抱瘵知曠職，淹旬非樂閑。',84,'御定全唐詩/json/186.json','["對此嘉樹林，獨有戚戚顏。抱瘵知曠職，淹旬非樂閑。", "釋子來問訊，詩人亦扣關。道同意暫遣，客散疾徐還。", "園逕自幽靜，玄蟬噪其間。高窗瞰遠郊，暮色起秋山。", "英曹幸休暇，悢悢心所攀。"]'),
('yuding-12','慈恩伽藍清會','韋應物','唐','御定全唐诗','yuding','','[]','素友俱薄世，屢招清景賞。鳴鐘悟音聞，宿昔心已往。',96,'御定全唐詩/json/186.json','["素友俱薄世，屢招清景賞。鳴鐘悟音聞，宿昔心已往。", "重門相洞達，高宇亦遐朗。嵐嶺曉城分，清陰夏條長。", "氳氛芳台馥，蕭散竹池廣。平荷隨波泛，回飆激林響。", "蔬食遵道侶，泊懷遺滯想。何彼塵昏人，區區在天壤。"]'),
('yuding-13','夜偶詩客操公作','韋應物','唐','御定全唐诗','yuding','','[]','塵襟一瀟灑，清夜得禪公。遠自鶴林寺，了知人世空。',48,'御定全唐詩/json/186.json','["塵襟一瀟灑，清夜得禪公。遠自鶴林寺，了知人世空。", "驚禽翻暗葉，流水注幽叢。多謝非玄度，聊將詩興同。"]'),
('yuding-14','與韓庫部會王祠曹宅作','韋應物','唐','御定全唐诗','yuding','','[]','閑門蔭堤柳，秋渠含夕清。微風送荷氣，坐客散塵纓。',48,'御定全唐詩/json/186.json','["閑門蔭堤柳，秋渠含夕清。微風送荷氣，坐客散塵纓。", "守默共無吝，抱沖俱寡營。良時頗高會，琴酌共開情。"]'),
('yuding-15','晦日處士叔園林燕集','韋應物','唐','御定全唐诗','yuding','','[]','遽看蓂葉盡，坐闕芳年賞。賴此林下期，清風滌煩想。',72,'御定全唐詩/json/186.json','["遽看蓂葉盡，坐闕芳年賞。賴此林下期，清風滌煩想。", "始萌動新煦，佳禽發幽響。嵐嶺對高齋，春流灌蔬壤。", "樽酒遺形跡，道言屢開獎。幸蒙終夕歡，聊用稅歸鞅。"]'),
('yuding-16','扈亭西陂燕賞','韋應物','唐','御定全唐诗','yuding','','[]','杲杲朝陽時，悠悠清陂望。嘉樹始氤氳，春遊方浩蕩。',72,'御定全唐詩/json/186.json','["杲杲朝陽時，悠悠清陂望。嘉樹始氤氳，春遊方浩蕩。", "況逢文翰侶，愛此孤舟漾。綠野際遙波，橫雲分疊嶂。", "公堂日為倦，幽襟自茲曠。有酒今滿盈，願君盡弘量。"]'),
('yuding-17','西郊燕集','韋應物','唐','御定全唐诗','yuding','','[]','濟濟眾君子，高宴及時光。群山靄遐矚，綠野布熙陽。',84,'御定全唐詩/json/186.json','["濟濟眾君子，高宴及時光。群山靄遐矚，綠野布熙陽。", "列坐遵曲岸，披襟襲蘭芳。野庖薦嘉魚，激澗泛羽觴。", "眾鳥鳴茂林，綠草延高岡。盛時易徂謝，浩思坐飄颺。", "眷言同心友，茲游安可忘。"]'),
('yuding-18','春宵燕萬年吉少府中孚南館','韋應物','唐','御定全唐诗','yuding','','[]','始見斗柄回，複茲霜月霽。河漢上縱橫，春城夜迢遞。',60,'御定全唐詩/json/186.json','["始見斗柄回，複茲霜月霽。河漢上縱橫，春城夜迢遞。", "賓筵接時彥，樂燕淩芳歲。稍愛清觴滿，仰歎高文麗。", "欲去返郊扉，端為一歡滯。"]'),
('yuding-19','滁州園池燕元氏親屬','韋應物','唐','御定全唐诗','yuding','','[]','日暮游清池，疏林羅高天。餘綠飄霜露，夕氣變風煙。',72,'御定全唐詩/json/186.json','["日暮游清池，疏林羅高天。餘綠飄霜露，夕氣變風煙。", "水門架危閣，竹亭列廣筵。一展私姻禮，屢歎芳樽前。", "感往在茲會，傷離屬頹年。明晨複雲去，且願此流連。"]'),
('yuding-20','郡樓春燕','韋應物','唐','御定全唐诗','yuding','','[]','眾樂雜軍鞞，高樓邀上客。思逐花光亂，賞餘山景夕。',48,'御定全唐詩/json/186.json','["眾樂雜軍鞞，高樓邀上客。思逐花光亂，賞餘山景夕。", "為郡訪凋瘵，守程難損益。聊假一杯歡，暫忘終日迫。"]'),
('yuding-21','南塘泛舟會元六昆季','韋應物','唐','御定全唐诗','yuding','','[]','端居倦時燠，輕舟泛回塘。微風飄襟散，橫吹繞林長。',48,'御定全唐詩/json/186.json','["端居倦時燠，輕舟泛回塘。微風飄襟散，橫吹繞林長。", "雲澹水容夕，雨微荷氣涼。一寫悁勤意，甯用訴華觴。"]'),
('yuding-22','郡齋雨中與諸文士燕集','韋應物','唐','御定全唐诗','yuding','','[]','兵衛森畫戟，宴寢凝清香。海上風雨至，逍遙池閣涼。',120,'御定全唐詩/json/186.json','["兵衛森畫戟，宴寢凝清香。海上風雨至，逍遙池閣涼。", "煩屙近消散，嘉賓複滿堂。自慚居處崇，未睹斯民康。", "理會是非遣，性達形跡忘。鮮肥屬時禁，蔬果幸見嘗。", "俯飲一杯酒，仰聆金玉章。神歡體自輕，意欲淩風翔。", "吳中盛文史，群彥今汪洋。方知大藩地，豈曰財賦疆。"]'),
('yuding-23','軍中冬燕','韋應物','唐','御定全唐诗','yuding','','[]','滄海已雲晏，皇恩猶念勤。式燕遍恒秩，柔遠及斯人。',120,'御定全唐詩/json/186.json','["滄海已雲晏，皇恩猶念勤。式燕遍恒秩，柔遠及斯人。", "茲邦實大藩，伐鼓軍樂陳。是時冬服成，戎士氣益振。", "虎竹謬朝寄，英賢降上賓。旋罄周旋禮，愧無海陸珍。", "庭中丸劍闌，堂上歌吹新。光景不知晚，觥酌豈言頻。", "單醪昔所感，大醵況同忻。顧謂軍中士，仰答何由申。"]'),
('yuding-24','司空主簿琴席','韋應物','唐','御定全唐诗','yuding','','[]','煙華方散薄，蕙氣猶含露。澹景發清琴，幽期默玄悟。',48,'御定全唐詩/json/186.json','["煙華方散薄，蕙氣猶含露。澹景發清琴，幽期默玄悟。", "流連白雪意，斷續回風度。掩抑雖已終，忡忡在幽素。"]'),
('yuding-25','與村老對飲','韋應物','唐','御定全唐诗','yuding','','[]','鬢眉雪色猶嗜酒，言辭淳樸古人風。',32,'御定全唐詩/json/186.json','["鬢眉雪色猶嗜酒，言辭淳樸古人風。", "鄉村年少生離亂，見話先朝如夢中。"]'),
('yuding-0','城中臥疾，知閻、薛二子屢從邑令飲，因以贈之','韋應物','唐','御定全唐诗','yuding','','[]','車馬日蕭蕭，胡不枉我廬。方來從令飲，臥病獨何如。',84,'御定全唐詩/json/187.json','["車馬日蕭蕭，胡不枉我廬。方來從令飲，臥病獨何如。", "秋風起漢皋，開戶望平蕪。即此吝音素，焉知中密疏。", "渴者不思火，寒者不求水。人生羈寓時，去就當如此。", "猶希心異跡，眷眷存終始。"]'),
('yuding-1','聽嘉陵江水聲，寄深上人','韋應物','唐','御定全唐诗','yuding','','[]','鑿崖泄奔湍，稱古神禹跡。夜喧山門店，獨宿不安席。',60,'御定全唐詩/json/187.json','["鑿崖泄奔湍，稱古神禹跡。夜喧山門店，獨宿不安席。", "水性自雲靜，石中本無聲。如何兩相激，雷轉空山驚。", "貽之道門舊，了此物我情。"]'),
('yuding-2','高陵書情，寄三原盧少府','韋應物','唐','御定全唐诗','yuding','','[]','直方難為進，守此微賤班。開卷不及顧，沉埋案牘間。',72,'御定全唐詩/json/187.json','["直方難為進，守此微賤班。開卷不及顧，沉埋案牘間。", "兵凶久相踐，徭賦豈得閒。促戚下可哀，寬政身致患。", "日夕思自退，出門望故山。君心倘如此，攜手相與還。"]'),
('yuding-3','假中對雨，呈縣中僚友','韋應物','唐','御定全唐诗','yuding','','[]','卻足甘為笑，閒居夢杜陵。殘鶯知夏淺，社雨報年登。',48,'御定全唐詩/json/187.json','["卻足甘為笑，閒居夢杜陵。殘鶯知夏淺，社雨報年登。", "流麥非關忘，收書獨不能。自然憂曠職，緘此謝良朋。"]'),
('yuding-4','贈蕭河南','韋應物','唐','御定全唐诗','yuding','','[]','厭劇辭京縣，褒賢待詔書。酂侯方繼業，潘令且閒居。',48,'御定全唐詩/json/187.json','["厭劇辭京縣，褒賢待詔書。酂侯方繼業，潘令且閒居。", "霽後三川冷，秋深萬木疏。對琴無一事，新興複何如。"]'),
('yuding-5','示從子河南尉班','韋應物','唐','御定全唐诗','yuding','','[]','拙直餘恒守，公方爾所存。同占朱鳥克，俱起小人言。',48,'御定全唐詩/json/187.json','["拙直餘恒守，公方爾所存。同占朱鳥克，俱起小人言。", "立政思懸棒，謀身類觸藩。不能林下去，只戀府廷恩。"]'),
('yuding-6','趨府候曉，呈兩縣僚友','韋應物','唐','御定全唐诗','yuding','','[]','趨府不遑安，中宵出戶看。滿天星尚在，近壁燭仍殘。',48,'御定全唐詩/json/187.json','["趨府不遑安，中宵出戶看。滿天星尚在，近壁燭仍殘。", "立馬頻驚曙，垂簾卻避寒。可憐同宦者，應悟下流難。"]'),
('yuding-7','贈李儋','韋應物','唐','御定全唐诗','yuding','','[]','絲桐本異質，音響合自然。吾觀造化意，二物相因緣。',60,'御定全唐詩/json/187.json','["絲桐本異質，音響合自然。吾觀造化意，二物相因緣。", "誤觸龍鳳嘯，靜聞寒夜泉。心神自安宅，煩慮頓可捐。", "何因知久要，絲白漆亦堅。"]'),
('yuding-8','贈盧嵩','韋應物','唐','御定全唐诗','yuding','','[]','百川注東海，東海無虛盈。泥滓不能濁，澄波非益清。',84,'御定全唐詩/json/187.json','["百川注東海，東海無虛盈。泥滓不能濁，澄波非益清。", "恬然自安流，日照萬里晴。雲物不隱象，三山共分明。", "奈何疾風怒，忽若砥柱傾。海水雖無心，洪濤亦相驚。", "怒號在倏忽，誰識變化情。"]'),
('yuding-9','寄馮著','韋應物','唐','御定全唐诗','yuding','','[]','春雷起萌蟄，土壤日已疏。胡能遭盛明，才俊伏裏閭。',96,'御定全唐詩/json/187.json','["春雷起萌蟄，土壤日已疏。胡能遭盛明，才俊伏裏閭。", "偃仰遂真性，所求惟鬥儲。披衣出茅屋，盥漱臨清渠。", "吾道亦自適，退身保玄虛。幸無職事牽，且覽案上書。", "親友各馳騖，誰當訪敝廬。思君在何夕，明月照廣除。"]'),
('yuding-10','早春對雪，寄前殿中元侍禦','韋應物','唐','御定全唐诗','yuding','','[]','掃雪開幽徑，端居望故人。猶殘臘月酒，更值早梅春。',48,'御定全唐詩/json/187.json','["掃雪開幽徑，端居望故人。猶殘臘月酒，更值早梅春。", "幾日東城陌，何時曲水濱。聞閑且共賞，莫待繡衣新。"]'),
('yuding-11','贈王侍禦','韋應物','唐','御定全唐诗','yuding','','[]','心同野鶴與塵遠，詩似冰壺見底清。府縣同趨昨日事，',40,'御定全唐詩/json/187.json','["心同野鶴與塵遠，詩似冰壺見底清。府縣同趨昨日事，", "自歎猶為折腰吏，可憐驄馬路傍行。"]'),
('yuding-12','將往江淮，寄李十九儋','韋應物','唐','御定全唐诗','yuding','','[]','燕燕東向來，文鵷亦西飛。如何不相見，羽翼有高卑。',72,'御定全唐詩/json/187.json','["燕燕東向來，文鵷亦西飛。如何不相見，羽翼有高卑。", "徘徊到河洛，華屋未及窺。秋風飄我行，遠與淮海期。", "回首隔煙霧，遙遙兩相思。陽春自當返，短翮欲追隨。"]'),
('yuding-13','自鞏洛舟行入黃河即事，寄府縣僚友','韋應物','唐','御定全唐诗','yuding','','[]','夾水蒼山路向東，東南山豁大河通。寒樹依微遠天外，',40,'御定全唐詩/json/187.json','["夾水蒼山路向東，東南山豁大河通。寒樹依微遠天外，", "為報洛橋遊宦侶，扁舟不系與心同。"]'),
('yuding-14','寄盧庾','韋應物','唐','御定全唐诗','yuding','','[]','悠悠遠離別，分此歡會難。如何兩相近，反使心不安。',84,'御定全唐詩/json/187.json','["悠悠遠離別，分此歡會難。如何兩相近，反使心不安。", "亂髮思一櫛，垢衣思一浣。豈如望友生，對酒起長歎。", "時節異京洛，孟冬天未寒。廣陵多車馬，日夕自遊盤。", "獨我何耿耿，非君誰為歡。"]'),
('yuding-15','發廣陵留上家兄兼寄上長沙','韋應物','唐','御定全唐诗','yuding','','[]','將違安可懷，宿戀複一方。家貧無舊業，薄宦各飄颺。',120,'御定全唐詩/json/187.json','["將違安可懷，宿戀複一方。家貧無舊業，薄宦各飄颺。", "執板身有屬，淹時心恐惶。拜言不得留，聲結淚滿裳。", "漾漾動行舫，亭亭遠相望。離晨苦須臾，獨往道路長。", "蕭條風雨過，得此海氣涼。感秋意已違，況自結中腸。", "推道固當遣，及情豈所忘。何時共還歸，舉翼鳴春陽。"]'),
('yuding-16','初發揚子，寄元大校書','韋應物','唐','御定全唐诗','yuding','','[]','淒淒去親愛，泛泛入煙霧。歸棹洛陽人，殘鐘廣陵樹。',48,'御定全唐詩/json/187.json','["淒淒去親愛，泛泛入煙霧。歸棹洛陽人，殘鐘廣陵樹。", "今朝此為別，何處還相遇。世事波上舟，沿洄安得住。"]'),
('yuding-17','淮上即事，寄廣陵親故','韋應物','唐','御定全唐诗','yuding','','[]','前舟已眇眇，欲渡誰相待。秋山起暮鐘，楚雨連滄海。',48,'御定全唐詩/json/187.json','["前舟已眇眇，欲渡誰相待。秋山起暮鐘，楚雨連滄海。", "風波離思滿，宿昔容鬢改。獨鳥下東南，廣陵何處在。"]'),
('yuding-18','寄洪州幕府盧二十一侍禦','韋應物','唐','御定全唐诗','yuding','','[]','忽報南昌令，乘驄入郡城。同時趨府客，此日望塵迎。',48,'御定全唐詩/json/187.json','["忽報南昌令，乘驄入郡城。同時趨府客，此日望塵迎。", "文苑台中妙，冰壺幕下清。洛陽相去遠，猶使故林榮。"]'),
('yuding-19','經少林精舍，寄都邑親友','韋應物','唐','御定全唐诗','yuding','','[]','息駕依松嶺，高閣一攀緣。前瞻路已窮，既詣喜更延。',72,'御定全唐詩/json/187.json','["息駕依松嶺，高閣一攀緣。前瞻路已窮，既詣喜更延。", "出巘聽萬籟，入林濯幽泉。鳴鐘生道心，暮磬空雲煙。", "獨往雖暫適，多累終見牽。方思結茅地，歸息期暮年。"]'),
('yuding-20','同長源歸南徐，寄子西、子烈、有道','韋應物','唐','御定全唐诗','yuding','','[]','東洛何蕭條，相思邈遐路。策駕複誰遊，入門無與晤。',84,'御定全唐詩/json/187.json','["東洛何蕭條，相思邈遐路。策駕複誰遊，入門無與晤。", "還因送歸客，達此緘中素。屢暌心所歡，豈得顏如故。", "所歡不可暌，嚴霜晨淒淒。如彼萬里行，孤妾守空閨。", "臨觴一長歎，素欲何時諧。"]'),
('yuding-21','雪中聞李儋過門不訪，聊以寄贈','韋應物','唐','御定全唐诗','yuding','','[]','度門能不訪，冒雪屢西東。已想人如玉，遙憐馬似驄。',48,'御定全唐詩/json/187.json','["度門能不訪，冒雪屢西東。已想人如玉，遙憐馬似驄。", "乍迷金谷路，稍變上陽宮。還比相思意，紛紛正滿空。"]'),
('yuding-22','同德精舍養疾，寄河南兵曹東廳掾','韋應物','唐','御定全唐诗','yuding','','[]','逍遙東城隅，雙樹寒蔥茜。廣庭流華月，高閣凝餘霰。',84,'御定全唐詩/json/187.json','["逍遙東城隅，雙樹寒蔥茜。廣庭流華月，高閣凝餘霰。", "杜門非養素，抱疾阻良宴。孰謂無他人，思君歲雲變。", "官曹亮先忝，陳躅慚俊彥。豈知晨與夜，相代不相見。", "緘書問所如，酬藻當芬絢。"]'),
('yuding-23','同德寺雨後，寄元侍禦、李博士','韋應物','唐','御定全唐诗','yuding','','[]','川上風雨來，須臾滿城闕。岧嶢青蓮界，蕭條孤興發。',72,'御定全唐詩/json/187.json','["川上風雨來，須臾滿城闕。岧嶢青蓮界，蕭條孤興發。", "前山遽已淨，陰靄夜來歇。喬木生夏涼，流雲吐華月。", "嚴城自有限，一水非難越。相望曙河遠，高齋坐超忽。"]'),
('yuding-24','同德閣期元侍禦、李博士不至，各投贈二首','韋應物','唐','御定全唐诗','yuding','','[]','庭樹忽已暗，故人那不來。只因厭煩暑，永日坐霜台。',48,'御定全唐詩/json/187.json','["庭樹忽已暗，故人那不來。只因厭煩暑，永日坐霜台。", "官榮多所系，閒居亦愆期。高閣猶相望，青山欲暮時。"]'),
('yuding-25','使雲陽寄府曹','韋應物','唐','御定全唐诗','yuding','','[]','夙駕祗府命，冒炎不遑息。百里次雲陽，閭閻問漂溺。',108,'御定全唐詩/json/187.json','["夙駕祗府命，冒炎不遑息。百里次雲陽，閭閻問漂溺。", "上天屢愆氣，胡不均寸澤。仰瞻喬樹巔，見此洪流跡。", "良苗免湮沒，蔓草生宿昔。頹墉滿故墟，喜返將安宅。", "周旋涉塗潦，側峭緣溝脈。仁賢憂斯民，賤子甘所役。", "公堂眾君子，言笑思與覿。"]'),
('yuding-26','過扶風精舍舊居，簡朝宗、巨川兄弟','韋應物','唐','御定全唐诗','yuding','','[]','佛刹出高樹，晨光閭井中。年深念陳跡，迨此獨忡忡。',84,'御定全唐詩/json/187.json','["佛刹出高樹，晨光閭井中。年深念陳跡，迨此獨忡忡。", "零落逢故老，寂寥悲草蟲。舊宇多改構，幽篁延本叢。", "棲止事如昨，芳時去已空。佳人亦攜手，再往今不同。", "新文聊感舊，想子意無窮。"]'),
('yuding-27','贈令狐士曹','韋應物','唐','御定全唐诗','yuding','','[]','秋簷滴滴對床寢，山路迢迢聯騎行。',32,'御定全唐詩/json/187.json','["秋簷滴滴對床寢，山路迢迢聯騎行。", "到家俱及東籬菊，何事先歸半日程。"]'),
('yuding-28','贈馮著','韋應物','唐','御定全唐诗','yuding','','[]','契闊仕兩京，念子亦飄蓬。方來屬追往，十載事不同。',96,'御定全唐詩/json/187.json','["契闊仕兩京，念子亦飄蓬。方來屬追往，十載事不同。", "歲晏乃雲至，微褐還未充。慘淒遊子情，風雪自關東。", "華觴發歡顏，嘉藻播清風。始此盈抱恨，曠然一夕中。", "善蘊豈輕售，懷才希國工。誰當念素士，零落歲華空。"]'),
('yuding-29','對雨寄韓庫部協','韋應物','唐','御定全唐诗','yuding','','[]','颯至池館涼，靄然和曉霧。蕭條集新荷，氤氳散高樹。',48,'御定全唐詩/json/187.json','["颯至池館涼，靄然和曉霧。蕭條集新荷，氤氳散高樹。", "閒居興方澹，默想心已屢。暫出仍濕衣，況君東城住。"]'),
('yuding-30','寄子西','韋應物','唐','御定全唐诗','yuding','','[]','夏景已難度，懷賢思方續。喬樹落疏陰，微風散煩燠。',72,'御定全唐詩/json/187.json','["夏景已難度，懷賢思方續。喬樹落疏陰，微風散煩燠。", "傷離枉芳劄，忻遂見心曲。藍上舍已成，田家雨新足。", "托鄰素多欲，殘帙猶見束。日夕上高齋，但望東原綠。"]'),
('yuding-31','縣內閒居贈溫公','韋應物','唐','御定全唐诗','yuding','','[]','滿郭春風嵐已昏，鴉棲散吏掩重門。',32,'御定全唐詩/json/187.json','["滿郭春風嵐已昏，鴉棲散吏掩重門。", "雖居世網常清淨，夜對高僧無一言。"]'),
('yuding-32','對雪贈徐秀才','韋應物','唐','御定全唐诗','yuding','','[]','靡靡寒欲收，靄靄陰還結。晨起望南端，千林散春雪。',48,'御定全唐詩/json/187.json','["靡靡寒欲收，靄靄陰還結。晨起望南端，千林散春雪。", "妍光屬瑤階，亂緒陵新節。無為掩扉臥，獨守袁生轍。"]'),
('yuding-33','西郊遊宴，寄贈邑僚李巽','韋應物','唐','御定全唐诗','yuding','','[]','升陽曖春物，置酒臨芳席。高宴闕英僚，眾賓寡歡懌。',84,'御定全唐詩/json/187.json','["升陽曖春物，置酒臨芳席。高宴闕英僚，眾賓寡歡懌。", "是時尚多壘，板築興頹壁。羈旅念越疆，領徒方祗役。", "如何嘉會日，當子憂勤夕。西郊鬱已茂，春嵐重如積。", "何當返徂雨，雜英紛可惜。"]'),
('yuding-34','對雨贈李主簿、高秀才','韋應物','唐','御定全唐诗','yuding','','[]','邐迤曙雲薄，散漫東風來。青山滿春野，微雨灑輕埃。',48,'御定全唐詩/json/187.json','["邐迤曙雲薄，散漫東風來。青山滿春野，微雨灑輕埃。", "吏局勞佳士，賓筵得上才。終朝狎文墨，高興共徘徊。"]'),
('yuding-35','休沐東還胄貴裏示端','韋應物','唐','御定全唐诗','yuding','','[]','宦遊三十載，田野久已疏。休沐遂茲日，一來還故墟。',120,'御定全唐詩/json/187.json','["宦遊三十載，田野久已疏。休沐遂茲日，一來還故墟。", "山明宿雨霽，風暖百卉舒。泓泓野泉潔，熠熠林光初。", "竹木稍摧翳，園場亦荒蕪。俯驚鬢已衰，周覽昔所娛。", "存沒惻私懷，遷變傷裏閭。欲言少留心，中複畏簡書。", "世道良自退，榮名亦空虛。與子終攜手，歲晏當來居。"]'),
('yuding-36','朝請後還邑，寄諸友生','韋應物','唐','御定全唐诗','yuding','','[]','宰邑分甸服，夙駕朝上京。是時當暮春，休沐集友生。',120,'御定全唐詩/json/187.json','["宰邑分甸服，夙駕朝上京。是時當暮春，休沐集友生。", "抗志青雲表，俱踐高世名。樽酒且歡樂，文翰亦縱橫。", "良遊昔所希，累宴夜複明。晨露含瑤琴，夕風殞素英。", "一旦遵歸路，伏軾出京城。誰言再念別，忽若千里行。", "閑合寡喧訟，端居結幽情。況茲晝方永，輾轉何由平。"]'),
('yuding-37','灃上西齋寄諸友','韋應物','唐','御定全唐诗','yuding','','[]','絕岸臨西野，曠然塵事遙。清川下邐迤，茅棟上岧嶢。',96,'御定全唐詩/json/187.json','["絕岸臨西野，曠然塵事遙。清川下邐迤，茅棟上岧嶢。", "玩月愛佳夕，望山屬清朝。俯砌視歸翼，開襟納遠飆。", "等陶辭小秩，效朱方負樵。閒遊忽無累，心跡隨景超。", "明世重才彥，雨露降丹霄。群公正雲集，獨予忻寂寥。"]'),
('yuding-38','獨遊西齋，寄崔主簿','韋應物','唐','御定全唐诗','yuding','','[]','同心忽已別，昨事方成昔。幽徑還獨尋，綠苔見行跡。',48,'御定全唐詩/json/187.json','["同心忽已別，昨事方成昔。幽徑還獨尋，綠苔見行跡。", "秋齋正蕭散，煙水易昏夕。憂來結幾重，非君不可釋。"]'),
('yuding-39','紫閣東林居士叔緘賜松英丸捧對忻喜蓋非塵侶之所當服輙獻詩代啓','韋應物','唐','御定全唐诗','yuding','','[]','碧澗蒼松五粒稀，侵雲采去露沾衣。夜啟群仙合靈藥，',40,'御定全唐詩/json/187.json','["碧澗蒼松五粒稀，侵雲采去露沾衣。夜啟群仙合靈藥，", "一望嵐峰拜還使，腰間銅印與心違。"]'),
('yuding-40','秋集罷還途中作，謹獻壽春公、黎公','韋應物','唐','御定全唐诗','yuding','','[]','束帶自衡門，奉命宰王畿。君侯枉高鑒，舉善掩瑕疵。',144,'御定全唐詩/json/187.json','["束帶自衡門，奉命宰王畿。君侯枉高鑒，舉善掩瑕疵。", "斯民本已安，工拙兩無施。何以酬明德，歲晏不磷緇。", "時節乃來集，欣懷方載馳。平明大府開，一得拜光輝。", "溫如春風至，肅若嚴霜威。群屬所載瞻，而忘倦與饑。", "公堂燕華筵，禮罷複言辭。將從平門道，憩車灃水湄。", "山川降嘉歲，草木蒙潤滋。孰雲還本邑，懷戀獨遲遲。"]'),
('yuding-41','閒居贈友','韋應物','唐','御定全唐诗','yuding','','[]','補吏多下遷，罷歸聊自度。園廬既蕪沒，煙景空澹泊。',96,'御定全唐詩/json/187.json','["補吏多下遷，罷歸聊自度。園廬既蕪沒，煙景空澹泊。", "閒居養痾瘵，守素甘葵藿。顏鬢日衰耗，冠帶亦寥落。", "青苔已生路，綠筠始分籜。夕氣下遙陰，微風動疏薄。", "草玄良見誚，杜門無請托。非君好事者，誰來顧寂寞。"]'),
('yuding-42','四禪精舍登覽悲舊，寄朝宗、巨川兄弟','韋應物','唐','御定全唐诗','yuding','','[]','蕭散人事憂，迢遞古原行。春風日已暄，百草亦複生。',108,'御定全唐詩/json/187.json','["蕭散人事憂，迢遞古原行。春風日已暄，百草亦複生。", "躋閣謁金像，攀雲造禪扃。新景林際曙，雜花川上明。", "徂歲方緬邈，陳事尚縱橫。溫泉有佳氣，馳道指京城。", "攜手思故日，山河留恨情。存者邈難見，去者已冥冥。", "臨風一長慟，誰畏行路驚。"]'),
('yuding-43','善福閣對雨，寄李儋幼遐','韋應物','唐','御定全唐诗','yuding','','[]','飛閣淩太虛，晨躋郁崢嶸。驚飆觸懸檻，白雲冒層甍。',132,'御定全唐詩/json/187.json','["飛閣淩太虛，晨躋郁崢嶸。驚飆觸懸檻，白雲冒層甍。", "太陰布其地，密雨垂八紘。仰觀固不測，俯視但冥冥。", "感此窮秋氣，沈郁命友生。及時未高步，羈旅遊帝京。", "聖朝無隱才，品物俱昭形。國士秉繩墨，何以表堅貞。", "寸心東北馳，思與一會並。我車夙已駕，將逐晨風征。", "郊途住成淹，默默阻中情。"]'),
('yuding-44','寺居獨夜，寄崔主簿','韋應物','唐','御定全唐诗','yuding','','[]','幽人寂不寐，木葉紛紛落。寒雨暗深更，流螢度高閣。',48,'御定全唐詩/json/187.json','["幽人寂不寐，木葉紛紛落。寒雨暗深更，流螢度高閣。", "坐使青燈曉，還傷夏衣薄。甯知歲方晏，離居更蕭索。"]'),
('yuding-45','九日灃上作，寄崔主簿倬二李端系','韋應物','唐','御定全唐诗','yuding','','[]','淒淒感時節，望望臨灃涘。翠嶺明華秋，高天澄遙滓。',96,'御定全唐詩/json/187.json','["淒淒感時節，望望臨灃涘。翠嶺明華秋，高天澄遙滓。", "川寒流愈迅，霜交物初委。林葉索已空，晨禽迎飆起。", "時菊乃盈泛，濁醪自為美。良游雖可娛，殷念在之子。", "人生不自省，營欲無終已。孰能同一酌，陶然冥斯理。"]'),
('yuding-46','西郊養疾聞暢校書有新什見贈久佇不至先寄此詩','韋應物','唐','御定全唐诗','yuding','','[]','養病愜清夏，郊園敷卉木。窗夕含澗涼，雨餘愛筠綠。',72,'御定全唐詩/json/187.json','["養病愜清夏，郊園敷卉木。窗夕含澗涼，雨餘愛筠綠。", "披懷始高詠，對琴轉幽獨。仰子游群英，吐詞如蘭馥。", "還聞枉嘉藻，佇望延昏旭。唯見草青青，閉戶灃水曲。"]'),
('yuding-47','灃上寄幼遐','韋應物','唐','御定全唐诗','yuding','','[]','寂寞到城闕，惆悵返柴荊。端居無所為，念子遠徂征。',108,'御定全唐詩/json/187.json','["寂寞到城闕，惆悵返柴荊。端居無所為，念子遠徂征。", "夏晝人已息，我懷獨未寧。忽從東齋起，兀兀尋澗行。", "罥掛叢榛密，披玩孤花明。曠然西南望，一極山水情。", "周覽同遊處，逾恨阻音形。壯圖非旦夕，君子勤令名。", "勿複久留燕，蹉跎在北京。"]'),
('yuding-48','善福精舍示諸生','韋應物','唐','御定全唐诗','yuding','','[]','湛湛嘉樹陰，清露夜景沉。悄然群物寂，高閣似陰岑。',72,'御定全唐詩/json/187.json','["湛湛嘉樹陰，清露夜景沉。悄然群物寂，高閣似陰岑。", "方以玄默處，豈為名跡侵。法妙不知歸，獨此抱沖襟。", "齋舍無餘物，陶器與單衾。諸生時列坐，共愛風滿林。"]'),
('yuding-49','晚出灃上，贈崔都水','韋應物','唐','御定全唐诗','yuding','','[]','臨流一舒嘯，望山意轉延。隔林分落景，餘霞明遠川。',72,'御定全唐詩/json/187.json','["臨流一舒嘯，望山意轉延。隔林分落景，餘霞明遠川。", "首起趣東作，已看耘夏田。一從民裏居，歲月再徂遷。", "昧質得全性，世名良自牽。行忻攜手歸，聊複飲酒眠。"]'),
('yuding-50','寓居灃上精舍，寄于、張二舍人','韋應物','唐','御定全唐诗','yuding','','[]','萬木叢雲出香閣，西連碧澗竹林園。高齋猶宿遠山曙，',40,'御定全唐詩/json/187.json','["萬木叢雲出香閣，西連碧澗竹林園。高齋猶宿遠山曙，", "時憶故交那得見，曉排閶闔奉明恩。"]'),
('yuding-51','開元觀懷舊寄李二、韓二、裴四兼呈崔郎中、嚴家令','韋應物','唐','御定全唐诗','yuding','','[]','宿昔清都燕，分散各西東。車馬行跡在，霜雪竹林空。',48,'御定全唐詩/json/187.json','["宿昔清都燕，分散各西東。車馬行跡在，霜雪竹林空。", "方軫故物念，誰複一樽同。聊披道書暇，還此聽松風。"]'),
('yuding-52','春日郊居寄萬年吉少府中孚、三原少府偉、夏侯校書審','韋應物','唐','御定全唐诗','yuding','','[]','谷鳥時一囀，田園春雨餘。光風動林早，高窗照日初。',48,'御定全唐詩/json/187.json','["谷鳥時一囀，田園春雨餘。光風動林早，高窗照日初。", "獨飲澗中水，吟詠老氏書。城闕應多事，誰憶此閒居。"]'),
('yuding-53','灃上醉題寄滌武','韋應物','唐','御定全唐诗','yuding','','[]','芳園知夕燕，西郊已獨還。誰言不同賞，俱是醉花間。',24,'御定全唐詩/json/187.json','["芳園知夕燕，西郊已獨還。誰言不同賞，俱是醉花間。"]'),
('yuding-54','西郊期滌武不至，書示','韋應物','唐','御定全唐诗','yuding','','[]','山高鳴過雨，澗樹落殘花。非關春不待，當由期自賒。',24,'御定全唐詩/json/187.json','["山高鳴過雨，澗樹落殘花。非關春不待，當由期自賒。"]'),
('yuding-55','灃上對月，寄孔諫議','韋應物','唐','御定全唐诗','yuding','','[]','思懷在雲闕，泊素守中林。出處雖殊跡，明月兩知心。',24,'御定全唐詩/json/187.json','["思懷在雲闕，泊素守中林。出處雖殊跡，明月兩知心。"]'),
('yuding-56','將往滁城戀新竹，簡崔都水示端','韋應物','唐','御定全唐诗','yuding','','[]','停車欲去繞叢竹，偏愛新筠十數竿。',32,'御定全唐詩/json/187.json','["停車欲去繞叢竹，偏愛新筠十數竿。", "莫遣兒童觸瓊粉，留待幽人回日看。"]'),
('yuding-57','還闕首途，寄精舍親友','韋應物','唐','御定全唐诗','yuding','','[]','休沐日雲滿，沖然將罷觀。嚴車候門側，晨起正朝冠。',60,'御定全唐詩/json/187.json','["休沐日雲滿，沖然將罷觀。嚴車候門側，晨起正朝冠。", "山澤含餘雨，川澗注驚湍。攬轡遵東路，回首一長歎。", "居人已不見，高閣在林端。"]'),
('yuding-58','秋夜南宮，寄灃上弟及諸生','韋應物','唐','御定全唐诗','yuding','','[]','暝色起煙閣，沉抱積離憂。況茲風雨夜，蕭條梧葉秋。',48,'御定全唐詩/json/187.json','["暝色起煙閣，沉抱積離憂。況茲風雨夜，蕭條梧葉秋。", "空宇感涼至，頹顏驚歲周。日夕游闕下，山水憶同遊。"]'),
('yuding-59','途中書情，寄灃上兩弟，因送二甥卻還','韋應物','唐','御定全唐诗','yuding','','[]','華簪豈足戀，幽林徒自違。遙知別後意，寂寞掩郊扉。',36,'御定全唐詩/json/187.json','["華簪豈足戀，幽林徒自違。遙知別後意，寂寞掩郊扉。", "回首昆池上，更羨爾同歸。"]'),
('yuding-60','雪夜下朝，呈省中一絕','韋應物','唐','御定全唐诗','yuding','','[]','南望青山滿禁闈，曉陪鴛鷺正差池。',32,'御定全唐詩/json/187.json','["南望青山滿禁闈，曉陪鴛鷺正差池。", "共愛朝來何處雪，蓬萊宮裏拂松枝。"]'),
('yuding-0','寄柳州韓司戶郎中','韋應物','唐','御定全唐诗','yuding','','[]','達識與昧機，智殊跡同靜。於焉得攜手，屢賞清夜景。',108,'御定全唐詩/json/188.json','["達識與昧機，智殊跡同靜。於焉得攜手，屢賞清夜景。", "瀟灑陪高詠，從容羨華省。一逐風波遷，南登桂陽嶺。", "舊裏門空掩，歡遊事皆屏。悵望城闕遙，幽居時序永。", "春風吹百卉，和煦變閭井。獨悶終日眠，篇書不復省。", "唯當望雨露，沾子荒遐境。"]'),
('yuding-1','寄令狐侍郎','韋應物','唐','御定全唐诗','yuding','','[]','三山有瓊樹，霜雪色逾新。始自風塵交，中結綢繆姻。',144,'御定全唐詩/json/188.json','["三山有瓊樹，霜雪色逾新。始自風塵交，中結綢繆姻。", "西掖方掌誥，南宮複司春。夕燕華池月，朝奉玉階塵。", "眾寶歸和氏，吹噓多俊人。群公共然諾，聲問邁時倫。", "孤鴻既高舉，燕雀在荊榛。翔集且不同，豈不欲殷勤。", "一旦遷南郡，江湖渺無垠。寵辱良未定，君子豈緇磷。", "寒暑已推斥，別離生苦辛。非將會面目，書劄何由申。"]'),
('yuding-2','閒居寄端及重陽','韋應物','唐','御定全唐诗','yuding','','[]','山明野寺曙鐘微，雪滿幽林人跡稀。',32,'御定全唐詩/json/188.json','["山明野寺曙鐘微，雪滿幽林人跡稀。", "閒居寥落生高興，無事風塵獨不歸。"]'),
('yuding-3','園林晏起，寄昭應韓明府、盧主簿','韋應物','唐','御定全唐诗','yuding','','[]','田家已耕作，井屋起晨煙。園林鳴好鳥，閒居猶獨眠。',96,'御定全唐詩/json/188.json','["田家已耕作，井屋起晨煙。園林鳴好鳥，閒居猶獨眠。", "不覺朝已晏，起來望青天。四體一舒散，情性亦忻然。", "還複茅簷下，對酒思數賢。束帶理官府，簡牘盈目前。", "當念中林賞，覽物遍山川。上非遇明世，庶以道自全。"]'),
('yuding-4','寄大樑諸友','韋應物','唐','御定全唐诗','yuding','','[]','分竹守南譙，弭節過梁池。雄都眾君子，出餞擁河湄。',84,'御定全唐詩/json/188.json','["分竹守南譙，弭節過梁池。雄都眾君子，出餞擁河湄。", "燕謔始雲洽，方舟已解維。一為風水便，但見山川馳。", "昨日次睢陽，今夕宿符離。雲樹愴重疊，煙波念還期。", "相敦在勤事，海內方勞師。"]'),
('yuding-5','新秋夜寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','兩地俱秋夕，相望共星河。高梧一葉下，空齋歸思多。',48,'御定全唐詩/json/188.json','["兩地俱秋夕，相望共星河。高梧一葉下，空齋歸思多。", "方用憂人瘼，況自抱微痾。無將別來近，顏鬢已蹉跎。"]'),
('yuding-6','郊園聞蟬，寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','去歲郊園別，聞蟬在蘭省。今歲臥南譙，蟬鳴歸路永。',48,'御定全唐詩/json/188.json','["去歲郊園別，聞蟬在蘭省。今歲臥南譙，蟬鳴歸路永。", "夕響依山谷，餘悲散秋景。緘書報此時，此心方耿耿。"]'),
('yuding-7','寄中書劉舍人','韋應物','唐','御定全唐诗','yuding','','[]','雲霄路竟別，中年跡暫同。比翼趨丹陛，連騎下南宮。',120,'御定全唐詩/json/188.json','["雲霄路竟別，中年跡暫同。比翼趨丹陛，連騎下南宮。", "佳詠邀清月，幽賞滯芳叢。迨予一出守，與子限西東。", "晨露方愴愴，離抱更忡忡。忽睹九天詔，秉綸歸國工。", "玉座浮香氣，秋禁散涼風。應向橫門度，環佩杳玲瓏。", "光輝恨未矚，歸思坐難通。蒼蒼松桂姿，想在掖垣中。"]'),
('yuding-8','郡齋感秋，寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','首夏辭舊國，窮秋臥滁城。方如昨日別，忽覺徂歲驚。',120,'御定全唐詩/json/188.json','["首夏辭舊國，窮秋臥滁城。方如昨日別，忽覺徂歲驚。", "高閣收煙霧，池水晚澄清。戶牖已淒爽，晨夜感深情。", "昔游郎署間，是月天氣晴。授衣還西郊，曉露田中行。", "采菊投酒中，昆弟自同傾。簪組聊掛壁，焉知有世榮。", "一旦居遠郡，山川間音形。大道庶無累，及茲念已盈。"]'),
('yuding-9','郡中對雨，贈元錫兼簡楊淩','韋應物','唐','御定全唐诗','yuding','','[]','宿雨冒空山，空城響秋葉。沉沉暮色至，淒淒涼氣入。',60,'御定全唐詩/json/188.json','["宿雨冒空山，空城響秋葉。沉沉暮色至，淒淒涼氣入。", "蕭條林表散，的礫荷上集。夜霧著衣重，新苔侵履濕。", "遇茲端憂日，賴與嘉賓接。"]'),
('yuding-10','冬至夜寄京師諸弟兼懷崔都水','韋應物','唐','御定全唐诗','yuding','','[]','理郡無異政，所憂在素餐。徒令去京國，羈旅當歲寒。',96,'御定全唐詩/json/188.json','["理郡無異政，所憂在素餐。徒令去京國，羈旅當歲寒。", "子月生一氣，陽景極南端。已懷時節感，更抱別離酸。", "私燕席雲罷，還齋夜方闌。邃幕沉空宇，孤燈照床單。", "應同茲夕念，寧忘故歲歡。川途恍悠邈，涕下一闌幹。"]'),
('yuding-11','元日寄諸弟兼呈崔都水','韋應物','唐','御定全唐诗','yuding','','[]','一從守茲郡，兩鬢生素發。新正加我年，故歲去超忽。',72,'御定全唐詩/json/188.json','["一從守茲郡，兩鬢生素發。新正加我年，故歲去超忽。", "淮濱益時候，了似仲秋月。川谷風景溫，城池草木發。", "高齋屬多暇，惆悵臨芳物。日月昧還期，念君何時歇。"]'),
('yuding-12','寄職方劉郎中','韋應物','唐','御定全唐诗','yuding','','[]','相聞二十載，不得展平生。一夕南宮遇，聊用寫中情。',108,'御定全唐詩/json/188.json','["相聞二十載，不得展平生。一夕南宮遇，聊用寫中情。", "端服光朝次，群烈慕英聲。歸來坐粉闈，揮筆乃縱橫。", "始陪文翰游，歡燕難久並。予因謬忝出，君為沉疾嬰。", "別離寒暑過，荏苒春草生。故園茲日隔，新禽池上鳴。", "郡中永無事，歸思徒自盈。"]'),
('yuding-13','社日寄崔都水及諸弟群屬','韋應物','唐','御定全唐诗','yuding','','[]','山郡多暇日，社時放吏歸。坐閣獨成悶，行塘閱清輝。',48,'御定全唐詩/json/188.json','["山郡多暇日，社時放吏歸。坐閣獨成悶，行塘閱清輝。", "春風動高柳，芳園掩夕扉。遙思裏中會，心緒悵微微。"]'),
('yuding-14','寒食日寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','禁火曖佳辰，念離獨傷抱。見此野田花，心思杜陵道。',36,'御定全唐詩/json/188.json','["禁火曖佳辰，念離獨傷抱。見此野田花，心思杜陵道。", "聯騎定何時，予今顏已老。"]'),
('yuding-15','三月三日寄諸弟兼懷崔都水','韋應物','唐','御定全唐诗','yuding','','[]','暮節看已謝，茲晨愈可惜。風澹意傷春，池寒花斂夕。',48,'御定全唐詩/json/188.json','["暮節看已謝，茲晨愈可惜。風澹意傷春，池寒花斂夕。", "對酒始依依，懷人還的的。誰當曲水行，相思尋舊跡。"]'),
('yuding-16','贈李儋侍禦','韋應物','唐','御定全唐诗','yuding','','[]','風光山郡少，來看廣陵春。殘花猶待客，莫問意中人。',24,'御定全唐詩/json/188.json','["風光山郡少，來看廣陵春。殘花猶待客，莫問意中人。"]'),
('yuding-17','寄楊協律','韋應物','唐','御定全唐诗','yuding','','[]','吏散門閣掩，鳥鳴山郡中。遠念長江別，俯覺座隅空。',48,'御定全唐詩/json/188.json','["吏散門閣掩，鳥鳴山郡中。遠念長江別，俯覺座隅空。", "舟泊南池雨，簟卷北樓風。並罷芳樽燕，為愴昨時同。"]'),
('yuding-18','郡齋贈王卿','韋應物','唐','御定全唐诗','yuding','','[]','無術謬稱簡，素餐空自嗟。秋齋雨成滯，山藥寒始華。',48,'御定全唐詩/json/188.json','["無術謬稱簡，素餐空自嗟。秋齋雨成滯，山藥寒始華。", "濩落人皆笑，幽獨歲逾賒。唯君出塵意，賞愛似山家。"]'),
('yuding-19','簡恒璨','韋應物','唐','御定全唐诗','yuding','','[]','室虛多涼氣，天高屬秋時。空庭夜風雨，草木曉離披。',48,'御定全唐詩/json/188.json','["室虛多涼氣，天高屬秋時。空庭夜風雨，草木曉離披。", "簡書日雲曠，文墨誰複持。聊因遇澄靜，一與道人期。"]'),
('yuding-20','閒居寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','秋草生庭白露時，故園諸弟益相思。',32,'御定全唐詩/json/188.json','["秋草生庭白露時，故園諸弟益相思。", "盡日高齋無一事，芭蕉葉上獨題詩。"]'),
('yuding-21','登樓寄王卿','韋應物','唐','御定全唐诗','yuding','','[]','踏閣攀林恨不同，楚雲滄海思無窮。',32,'御定全唐詩/json/188.json','["踏閣攀林恨不同，楚雲滄海思無窮。", "數家砧杵秋山下，一郡荊榛寒雨中。"]'),
('yuding-22','寄暢當','韋應物','唐','御定全唐诗','yuding','','[]','寇賊起東山，英俊方未閑。聞君新應募，籍籍動京關。',96,'御定全唐詩/json/188.json','["寇賊起東山，英俊方未閑。聞君新應募，籍籍動京關。", "出身文翰場，高步不可攀。青袍未及解，白羽插腰間。", "昔為瓊樹枝，今有風霜顏。秋郊細柳道，走馬一夕還。", "丈夫當為國，破敵如摧山。何必事州府，坐使鬢毛斑。"]'),
('yuding-23','贈崔員外','韋應物','唐','御定全唐诗','yuding','','[]','一別十年事，相逢淮海濱。還思洛陽日，更話府中人。',48,'御定全唐詩/json/188.json','["一別十年事，相逢淮海濱。還思洛陽日，更話府中人。", "且對清觴滿，甯知白髮新。匆匆何處去，車馬冒風塵。"]'),
('yuding-24','寄李儋、元錫','韋應物','唐','御定全唐诗','yuding','','[]','去年花裏逢君別，今日花開已一年。世事茫茫難自料，',40,'御定全唐詩/json/188.json','["去年花裏逢君別，今日花開已一年。世事茫茫難自料，", "聞道欲來相問訊，西樓望月幾回圓。"]'),
('yuding-25','京師叛亂寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','弱冠遭世難，二紀猶未平。羈離官遠郡，虎豹滿西京。',96,'御定全唐詩/json/188.json','["弱冠遭世難，二紀猶未平。羈離官遠郡，虎豹滿西京。", "上懷犬馬戀，下有骨肉情。歸去在何時，流淚忽沾纓。", "憂來上北樓，左右但軍營。函谷行人絕，淮南春草生。", "鳥鳴野田間，思憶故園行。何當四海晏，甘與齊民耕。"]'),
('yuding-26','贈琮公','韋應物','唐','御定全唐诗','yuding','','[]','山僧一相訪，吏案正盈前。出處似殊致，喧靜兩皆禪。',48,'御定全唐詩/json/188.json','["山僧一相訪，吏案正盈前。出處似殊致，喧靜兩皆禪。", "暮春華池宴，清夜高齋眠。此道本無得，寧複有忘筌。"]'),
('yuding-27','寄諸弟','韋應物','唐','御定全唐诗','yuding','','[]','歲暮兵戈亂京國，帛書間道訪存亡。',32,'御定全唐詩/json/188.json','["歲暮兵戈亂京國，帛書間道訪存亡。", "還信忽從天上落，唯知彼此淚千行。"]'),
('yuding-28','寄恒璨','韋應物','唐','御定全唐诗','yuding','','[]','心絕去來緣，跡順人間事。獨尋秋草徑，夜宿寒山寺。',36,'御定全唐詩/json/188.json','["心絕去來緣，跡順人間事。獨尋秋草徑，夜宿寒山寺。", "今日郡齋閑，思問楞伽字。"]'),
('yuding-29','簡郡中諸生','韋應物','唐','御定全唐诗','yuding','','[]','守郡臥秋閣，四面盡荒山。此時聽夜雨，孤燈照窗間。',48,'御定全唐詩/json/188.json','["守郡臥秋閣，四面盡荒山。此時聽夜雨，孤燈照窗間。", "藥園日蕪沒，書帷長自閑。惟當上客至，論詩一解顏。"]'),
('yuding-30','寄全椒山中道士','韋應物','唐','御定全唐诗','yuding','','[]','今朝郡齋冷，忽念山中客。澗底束荊薪，歸來煮白石。',48,'御定全唐詩/json/188.json','["今朝郡齋冷，忽念山中客。澗底束荊薪，歸來煮白石。", "欲持一瓢酒，遠慰風雨夕。落葉滿空山，何處尋行跡。"]'),
('yuding-31','寄釋子良史酒','韋應物','唐','御定全唐诗','yuding','','[]','秋山僧冷病，聊寄三五杯。應瀉山瓢裏，還寄此瓢來。',24,'御定全唐詩/json/188.json','["秋山僧冷病，聊寄三五杯。應瀉山瓢裏，還寄此瓢來。"]'),
('yuding-32','重寄','韋應物','唐','御定全唐诗','yuding','','[]','複寄滿瓢去，定見空瓢來。若不打瓢破，終當費酒材。',24,'御定全唐詩/json/188.json','["複寄滿瓢去，定見空瓢來。若不打瓢破，終當費酒材。"]'),
('yuding-33','答釋子良史送酒瓢','韋應物','唐','御定全唐诗','yuding','','[]','此瓢今已到，山瓢知已空。且飲寒塘水，遙將回也同。',24,'御定全唐詩/json/188.json','["此瓢今已到，山瓢知已空。且飲寒塘水，遙將回也同。"]'),
('yuding-34','簡陟、巡、建二甥','韋應物','唐','御定全唐诗','yuding','','[]','忽羨後生連榻話，獨依寒燭一齋空。',32,'御定全唐詩/json/188.json','["忽羨後生連榻話，獨依寒燭一齋空。", "時流歡笑事從別，把酒吟詩待爾同。"]'),
('yuding-35','覽褒子臥病一絕，聊以題示','韋應物','唐','御定全唐诗','yuding','','[]','念子抱沉疾，霜露變滁城。獨此高窗下，自然無世情。',24,'御定全唐詩/json/188.json','["念子抱沉疾，霜露變滁城。獨此高窗下，自然無世情。"]'),
('yuding-36','寄璨師','韋應物','唐','御定全唐诗','yuding','','[]','林院生夜色，西廊上紗燈。時憶長松下，獨坐一山僧。',24,'御定全唐詩/json/188.json','["林院生夜色，西廊上紗燈。時憶長松下，獨坐一山僧。"]'),
('yuding-37','寄盧陟','韋應物','唐','御定全唐诗','yuding','','[]','柳葉遍寒塘，曉霜凝高閣。累日此流連，別來成寂寞。',24,'御定全唐詩/json/188.json','["柳葉遍寒塘，曉霜凝高閣。累日此流連，別來成寂寞。"]'),
('yuding-38','途中寄楊邈、裴緒，示褒子','韋應物','唐','御定全唐诗','yuding','','[]','上宰領淮右，下國屬星馳。霧野騰曉騎，霜竿裂凍旗。',72,'御定全唐詩/json/188.json','["上宰領淮右，下國屬星馳。霧野騰曉騎，霜竿裂凍旗。", "蕭蕭陟連岡，莽莽望空陂。風截雁嘹唳，雲慘樹參差。", "高齋明月夜，中庭松桂姿。當睽一酌恨，況此兩旬期。"]'),
('yuding-39','宿永陽寄璨律師','韋應物','唐','御定全唐诗','yuding','','[]','遙知郡齋夜，凍雪封松竹。時有山僧來，懸燈獨自宿。',24,'御定全唐詩/json/188.json','["遙知郡齋夜，凍雪封松竹。時有山僧來，懸燈獨自宿。"]'),
('yuding-40','雪行寄褒子','韋應物','唐','御定全唐诗','yuding','','[]','淅瀝覆寒騎，飄颻暗川容。行子郡城曉，披雲看杉松。',24,'御定全唐詩/json/188.json','["淅瀝覆寒騎，飄颻暗川容。行子郡城曉，披雲看杉松。"]'),
('yuding-41','寄裴處士','韋應物','唐','御定全唐诗','yuding','','[]','春風駐遊騎，晚景澹山暉。一問清泠子，獨掩荒園扉。',48,'御定全唐詩/json/188.json','["春風駐遊騎，晚景澹山暉。一問清泠子，獨掩荒園扉。", "草木雨來長，裏閭人到稀。方從廣陵宴，花落未言歸。"]'),
('yuding-42','偶入西齋院示釋子恒璨','韋應物','唐','御定全唐诗','yuding','','[]','僧齋地雖密，忘子跡要賒。一來非問訊，自是看山花。',24,'御定全唐詩/json/188.json','["僧齋地雖密，忘子跡要賒。一來非問訊，自是看山花。"]'),
('yuding-43','示全真元常','韋應物','唐','御定全唐诗','yuding','','[]','余辭郡符去，爾為外事牽。寧知風雪夜，複此對床眠。',48,'御定全唐詩/json/188.json','["余辭郡符去，爾為外事牽。寧知風雪夜，複此對床眠。", "始話南池飲，更詠西樓篇。無將一會易，歲月坐推遷。"]'),
('yuding-44','寄劉尊師','韋應物','唐','御定全唐诗','yuding','','[]','世間荏苒縈此身，長望碧山到無因。',32,'御定全唐詩/json/188.json','["世間荏苒縈此身，長望碧山到無因。", "白鶴徘徊看不去，遙知下有清都人。"]'),
('yuding-45','寄廬山棕衣居士','韋應物','唐','御定全唐诗','yuding','','[]','兀兀山行無處歸，山中猛虎識棕衣。',32,'御定全唐詩/json/188.json','["兀兀山行無處歸，山中猛虎識棕衣。", "俗客欲尋應不遇，雲溪道士見猶稀。"]'),
('yuding-46','因省風俗，與從侄成緒游山水，中道先歸寄示','韋應物','唐','御定全唐诗','yuding','','[]','累宵同燕酌，十舍攜征騎。始造雙林寂，遐搜洞府秘。',108,'御定全唐詩/json/188.json','["累宵同燕酌，十舍攜征騎。始造雙林寂，遐搜洞府秘。", "群峰繞盤鬱，懸泉仰特異。陰壑雲松埋，陽崖煙花媚。", "每慮觀省牽，中乖遊踐志。我尚山水行，子歸棲息地。", "一操臨流袂，上聳幹雲轡。獨往倦危途，懷沖寡幽致。", "賴爾還都期，方將登樓遲。"]'),
('yuding-47','寒食寄京師諸弟','韋應物','唐','御定全唐诗','yuding','','[]','雨中禁火空齋冷，江上流鶯獨坐聽。',32,'御定全唐詩/json/188.json','["雨中禁火空齋冷，江上流鶯獨坐聽。", "把酒看花想諸弟，杜陵寒食草青青。"]'),
('yuding-48','歲日寄京師諸季端武等','韋應物','唐','御定全唐诗','yuding','','[]','獻歲抱深惻，僑居念歸緣。常患親愛離，始覺世務牽。',120,'御定全唐詩/json/188.json','["獻歲抱深惻，僑居念歸緣。常患親愛離，始覺世務牽。", "少事河陽府，晚守淮南壖。平生幾會散，已及蹉跎年。", "昨日罷符竹，家貧遂留連。部曲多已去，車馬不復全。", "閑將酒為偶，默以道自詮。聽松南岩寺，見月西澗泉。", "為政無異術，當責豈望遷。終理來時裝，歸鑿杜陵田。"]'),
('yuding-49','簡盧陟','韋應物','唐','御定全唐诗','yuding','','[]','可憐白雪曲，未遇知音人。恓惶戎旅下，蹉跎淮海濱。',48,'御定全唐詩/json/188.json','["可憐白雪曲，未遇知音人。恓惶戎旅下，蹉跎淮海濱。", "澗樹含朝雨，山鳥哢餘春。我有一瓢酒，可以慰風塵。"]'),
('yuding-50','西澗即事示盧陟','韋應物','唐','御定全唐诗','yuding','','[]','寢扉臨碧澗，晨起澹忘情。空林細雨至，圓文遍水生。',48,'御定全唐詩/json/188.json','["寢扉臨碧澗，晨起澹忘情。空林細雨至，圓文遍水生。", "永日無餘事，山中伐木聲。知子塵喧久，暫可散煩纓。"]'),
('yuding-51','登郡寄京師諸季、淮南子弟','韋應物','唐','御定全唐诗','yuding','','[]','始罷永陽守，複臥潯陽樓。懸檻飄寒雨，危堞侵江流。',48,'御定全唐詩/json/188.json','["始罷永陽守，複臥潯陽樓。懸檻飄寒雨，危堞侵江流。", "迨茲聞雁夜，重憶別離秋。徒有盈樽酒，鎮此百端憂。"]'),
('yuding-52','寄黃尊師','韋應物','唐','御定全唐诗','yuding','','[]','結茅種杏在雲端，掃雪焚香宿石壇。',32,'御定全唐詩/json/188.json','["結茅種杏在雲端，掃雪焚香宿石壇。", "靈祇不許世人到，忽作雷風登嶺難。"]'),
('yuding-53','寄黃、劉二尊師','韋應物','唐','御定全唐诗','yuding','','[]','廬山兩道士，各在一峰居。矯掌白雲表，晞發陽和初。',72,'御定全唐詩/json/188.json','["廬山兩道士，各在一峰居。矯掌白雲表，晞發陽和初。", "清夜降真侶，焚香滿空虛。中有無為樂，自然與世疏。", "道尊不可屈，符守豈暇餘。高齋遙致敬，願示一編書。"]'),
('yuding-54','秋夜寄丘二十二員外','韋應物','唐','御定全唐诗','yuding','','[]','懷君屬秋夜，散步詠涼天。山空松子落，幽人應未眠。',24,'御定全唐詩/json/188.json','["懷君屬秋夜，散步詠涼天。山空松子落，幽人應未眠。"]'),
('yuding-55','贈丘員外二首','韋應物','唐','御定全唐诗','yuding','','[]','高詞棄浮靡，貞行表鄉閭。未真南宮拜，聊偃東山居。',144,'御定全唐詩/json/188.json','["高詞棄浮靡，貞行表鄉閭。未真南宮拜，聊偃東山居。", "大藩本多事，日與文章疏。每一睹之子，高詠遂起予。", "宵晝方連燕，煩吝亦頓祛。格言雅誨闕，善謔矜數餘。", "久局思遊曠，窮慘遇陽舒。虎丘愜登眺，吳門悵躊躇。", "方此戀攜手，豈雲還舊墟。告諸吳子弟，文學為何如。", "跡與孤雲遠，心將野鶴俱。那同石氏子，每到府門趨。"]'),
('yuding-56','贈李判官','韋應物','唐','御定全唐诗','yuding','','[]','良玉定為寶，長材世所稀。佐幕方巡郡，奏命布恩威。',108,'御定全唐詩/json/188.json','["良玉定為寶，長材世所稀。佐幕方巡郡，奏命布恩威。", "食蔬程獨守，飲冰節靡違。決獄興邦頌，高文稟天機。", "賓館在林表，望山啟西扉。下有千畝田，泱漭吳土肥。", "始耕已見獲，袗絺今授衣。政拙勞詳省，淹留未得歸。", "雖慚且忻願，日夕睹光輝。"]'),
('yuding-57','寄皎然上人','韋應物','唐','御定全唐诗','yuding','','[]','吳興老釋子，野雪蓋精廬。詩名徒自振，道心長晏如。',96,'御定全唐詩/json/188.json','["吳興老釋子，野雪蓋精廬。詩名徒自振，道心長晏如。", "想茲棲禪夜，見月東峰初。鳴鐘驚岩壑，焚香滿空虛。", "叨慕端成舊，未識豈為疏。願以碧雲思，方君怨別餘。", "茂苑文華地，流水古僧居。何當一遊詠，倚閣吟躊躇。"]'),
('yuding-58','贈舊識','韋應物','唐','御定全唐诗','yuding','','[]','少年游太學，負氣蔑諸生。蹉跎三十載，今日海隅行。',24,'御定全唐詩/json/188.json','["少年游太學，負氣蔑諸生。蹉跎三十載，今日海隅行。"]'),
('yuding-59','複理西齋，寄丘員外','韋應物','唐','御定全唐诗','yuding','','[]','前歲理西齋，得與君子同。迨茲已一周，悵望臨春風。',96,'御定全唐詩/json/188.json','["前歲理西齋，得與君子同。迨茲已一周，悵望臨春風。", "始自疏林竹，還複長榛叢。端正良難久，蕪穢易為功。", "援斧開眾郁，如師啟群蒙。庭宇還清曠，煩抱亦舒通。", "海隅雨雪霽，春序風景融。時物方如故，懷賢思無窮。"]'),
('yuding-60','和張舍人夜直中書，寄吏部劉員外','韋應物','唐','御定全唐诗','yuding','','[]','西垣草詔罷，南宮憶上才。月臨蘭殿出，涼自鳳池來。',48,'御定全唐詩/json/188.json','["西垣草詔罷，南宮憶上才。月臨蘭殿出，涼自鳳池來。", "松桂生丹禁，鴛鷺集雲台。托身各有所，相望徒徘徊。"]'),
('yuding-61','和李二主簿，寄淮上綦毋三','韋應物','唐','御定全唐诗','yuding','','[]','滿城憐傲吏，終日賦新詩。請報淮陰客，春帆浪作期。',24,'御定全唐詩/json/188.json','["滿城憐傲吏，終日賦新詩。請報淮陰客，春帆浪作期。"]'),
('yuding-62','寄二嚴','韋應物','唐','御定全唐诗','yuding','','[]','絲竹久已懶，今日遇君忺。打破蜘蛛千道網，',20,'御定全唐詩/json/188.json','["絲竹久已懶，今日遇君忺。打破蜘蛛千道網，"]'),
('yuding-0','李五席送李主簿歸西台','韋應物','唐','御定全唐诗','yuding','','[]','請告嚴程盡，西歸道路寒。欲陪鷹隼集，猶戀鶺鴒單。',48,'御定全唐詩/json/189.json','["請告嚴程盡，西歸道路寒。欲陪鷹隼集，猶戀鶺鴒單。", "洛邑人全少，嵩高雪尚殘。滿台誰不故，報我在微官。"]'),
('yuding-1','送崔押衙相州','韋應物','唐','御定全唐诗','yuding','','[]','禮樂儒家子，英豪燕趙風。驅雞嘗理邑，走馬卻從戎。',96,'御定全唐詩/json/189.json','["禮樂儒家子，英豪燕趙風。驅雞嘗理邑，走馬卻從戎。", "白刃千夫辟，黃金四海同。嫖姚恩顧下，諸將指揮中。", "別路憐芳草，歸心伴塞鴻。鄴城新騎滿，魏帝舊台空。", "望闕應懷戀，遭時貴立功。萬方如已靜，何處欲輸忠。"]'),
('yuding-2','送宣城路錄事','韋應物','唐','御定全唐诗','yuding','','[]','江上宣城郡，孤舟遠到時。雲林謝家宅，山水敬亭祠。',48,'御定全唐詩/json/189.json','["江上宣城郡，孤舟遠到時。雲林謝家宅，山水敬亭祠。", "綱紀多閑日，觀遊得賦詩。都門且盡醉，此別數年期。"]'),
('yuding-3','送李十四山東遊','韋應物','唐','御定全唐诗','yuding','','[]','聖朝有遺逸，披膽謁至尊。豈是貿榮寵，誓將救元元。',132,'御定全唐詩/json/189.json','["聖朝有遺逸，披膽謁至尊。豈是貿榮寵，誓將救元元。", "權豪非所便，書奏寢禁門。高歌長安酒，忠憤不可吞。", "欻來客河洛，日與靜者論。濟世翻小事，丹砂駐精魂。", "東遊無複系，梁楚多大蕃。高論動侯伯，疏懷脫塵喧。", "送君都門野，飲我林中樽。立馬望東道，白雲滿梁園。", "踟躕欲何贈，空是平生言。"]'),
('yuding-4','送李二歸楚州','韋應物','唐','御定全唐诗','yuding','','[]','情人南楚別，複詠在原詩。忽此嗟岐路，還令泣素絲。',48,'御定全唐詩/json/189.json','["情人南楚別，複詠在原詩。忽此嗟岐路，還令泣素絲。", "風波朝夕遠，音信往來遲。好去扁舟客，青雲何處期。"]'),
('yuding-5','送閻寀赴東川辟','韋應物','唐','御定全唐诗','yuding','','[]','冰炭俱可懷，孰雲熱與寒。何如結髮友，不得攜手歡。',84,'御定全唐詩/json/189.json','["冰炭俱可懷，孰雲熱與寒。何如結髮友，不得攜手歡。", "晨登嚴霜野，送子天一端。只承簡書命，俯仰豸角冠。", "上陟白雲嶠，下冥玄壑湍。離群自有托，歷險得所安。", "當念反窮巷，登朝成慨歎。"]'),
('yuding-6','送令狐岫宰恩陽','韋應物','唐','御定全唐诗','yuding','','[]','大雪天地閉，群山夜來晴。居家猶苦寒，子有千里行。',108,'御定全唐詩/json/189.json','["大雪天地閉，群山夜來晴。居家猶苦寒，子有千里行。", "行行安得辭，荷此蒲璧榮。賢豪爭追攀，飲餞出西京。", "樽酒豈不歡，暮春自有程。離人起視日，僕禦促前征。", "逶遲歲已窮，當造巴子城。和風被草木，江水日夜清。", "從來知善政，離別慰友生。"]'),
('yuding-7','送馮著受李廣州署為錄事','韋應物','唐','御定全唐诗','yuding','','[]','鬱鬱楊柳枝，蕭蕭征馬悲。送君灞陵岸，糾郡南海湄。',144,'御定全唐詩/json/189.json','["鬱鬱楊柳枝，蕭蕭征馬悲。送君灞陵岸，糾郡南海湄。", "名在翰墨場，群公正追隨。如何從此去，千里萬里期。", "大海吞東南，橫嶺隔地維。建邦臨日域，溫燠禦四時。", "百國共臻奏，珍奇獻京師。富豪虞興戎，繩墨不易持。", "州伯荷天寵，還當翊丹墀。子為門下生，終始豈見遺。", "所願酌貪泉，心不為磷緇。上將玩國士，下以報渴饑。"]'),
('yuding-8','送元倉曹歸廣陵','韋應物','唐','御定全唐诗','yuding','','[]','官閑得去住，告別戀音徽。舊國應無業，他鄉到是歸。',48,'御定全唐詩/json/189.json','["官閑得去住，告別戀音徽。舊國應無業，他鄉到是歸。", "楚山明月滿，淮甸夜鐘微。何處孤舟泊，遙遙心曲違。"]'),
('yuding-9','送唐明府赴溧水','韋應物','唐','御定全唐诗','yuding','','[]','三為百里宰，已過十餘年。只歎官如舊，旋聞邑屢遷。',48,'御定全唐詩/json/189.json','["三為百里宰，已過十餘年。只歎官如舊，旋聞邑屢遷。", "魚鹽濱海利，薑蔗傍湖田。到此安氓俗，琴堂又晏然。"]'),
('yuding-10','喜於廣陵拜覲家兄奉送發還池州','韋應物','唐','御定全唐诗','yuding','','[]','青青連枝樹，苒苒久別離。客遊廣陵中，俱到若有期。',96,'御定全唐詩/json/189.json','["青青連枝樹，苒苒久別離。客遊廣陵中，俱到若有期。", "俯仰敘存歿，哀腸發酸悲。收情且為歡，累日不知饑。", "夙駕多所迫，複當還歸池。長安三千里，歲晏獨何為。", "南出登閶門，驚飆左右吹。所別諒非遠，要令心不怡。"]'),
('yuding-11','送章八元秀才擢第往上都應制','韋應物','唐','御定全唐诗','yuding','','[]','決勝文場戰已酣，行應辟命複才堪。旅食不辭游闕下，',40,'御定全唐詩/json/189.json','["決勝文場戰已酣，行應辟命複才堪。旅食不辭游闕下，", "立馬欲從何處別，都門楊柳正毿毿。"]'),
('yuding-12','送張侍禦秘書江左覲省','韋應物','唐','御定全唐诗','yuding','','[]','莫歎都門路，歸無駟馬車。繡衣猶在篋，芸閣已觀書。',48,'御定全唐詩/json/189.json','["莫歎都門路，歸無駟馬車。繡衣猶在篋，芸閣已觀書。", "沃野收紅稻，長江釣白魚。晨餐亦可薦，名利欲何如。"]'),
('yuding-13','賦得鼎門，送盧耿赴任','韋應物','唐','御定全唐诗','yuding','','[]','名因定鼎地，門對鑿龍山。水北樓臺近，城南車馬還。',48,'御定全唐詩/json/189.json','["名因定鼎地，門對鑿龍山。水北樓臺近，城南車馬還。", "稍開芳野靜，欲掩暮鐘閑。去此無嗟屈，前賢尚抱關。"]'),
('yuding-14','賦得浮雲起離色，送鄭述誠','韋應物','唐','御定全唐诗','yuding','','[]','遊子欲言去，浮雲那得知。偏能見行色，自是獨傷離。',48,'御定全唐詩/json/189.json','["遊子欲言去，浮雲那得知。偏能見行色，自是獨傷離。", "晚帶城遙暗，秋生峰尚奇。還因朔吹斷，匹馬與相隨。"]'),
('yuding-15','餞雍聿之潞州謁李中丞','韋應物','唐','御定全唐诗','yuding','','[]','鬱鬱雨相遇，出門草青青。酒酣拔劍舞，慷慨送子行。',96,'御定全唐詩/json/189.json','["鬱鬱雨相遇，出門草青青。酒酣拔劍舞，慷慨送子行。", "驅馬涉大河，日暮懷洛京。前登太行路，志士亦未平。", "薄遊五府都，高步振英聲。主人才且賢，重士百金輕。", "絲竹促飛觴，夜宴達晨星。娛樂易淹暮，諒在執高情。"]'),
('yuding-16','上東門會送李幼舉南游徐方','韋應物','唐','御定全唐诗','yuding','','[]','離弦既罷彈，樽酒亦已闌。聽我歌一曲，南徐在雲端。',84,'御定全唐詩/json/189.json','["離弦既罷彈，樽酒亦已闌。聽我歌一曲，南徐在雲端。", "雲端雖雲邈，行路本非難。諸侯皆愛才，公子遠結歡。", "濟濟都門宴，將去複盤桓。令姿何昂昂，良馬遠遊冠。", "意氣且為別，由來非所歎。"]'),
('yuding-17','送洛陽韓丞東游','韋應物','唐','御定全唐诗','yuding','','[]','仙鳥何飄颻，綠衣翠為襟。顧我差池羽，咬咬懷好音。',96,'御定全唐詩/json/189.json','["仙鳥何飄颻，綠衣翠為襟。顧我差池羽，咬咬懷好音。", "徘徊洛陽中，遊戲清川潯。神交不在結，歡愛自中心。", "駕言忽徂征，雲路邈且深。朝游尚同啄，夕息當異林。", "出餞宿東郊，列筵屬城陰。舉酒欲為樂，憂懷方沉沉。"]'),
('yuding-18','送鄭長源','韋應物','唐','御定全唐诗','yuding','','[]','少年一相見，飛轡河洛間。歡游不知罷，中路忽言還。',84,'御定全唐詩/json/189.json','["少年一相見，飛轡河洛間。歡游不知罷，中路忽言還。", "泠泠鶤弦哀，悄悄冬夜閑。丈夫雖耿介，遠別多苦顏。", "君行拜高堂，速駕難久攀。雞鳴儔侶發，朔雪滿河關。", "須臾在今夕，樽酌且迴圈。"]'),
('yuding-19','送李儋','韋應物','唐','御定全唐诗','yuding','','[]','別離何從生，乃在親愛中。反念行路子，拂衣自西東。',84,'御定全唐詩/json/189.json','["別離何從生，乃在親愛中。反念行路子，拂衣自西東。", "日昃不留宴，嚴車出崇墉。行游非所樂，端憂道未通。", "春野百卉發，清川思無窮。芳時坐離散，世事誰可同。", "歸當掩重關，默默想音容。"]'),
('yuding-20','賦得暮雨，送李胄','韋應物','唐','御定全唐诗','yuding','','[]','楚江微雨裏，建業暮鐘時。漠漠帆來重，冥冥鳥去遲。',48,'御定全唐詩/json/189.json','["楚江微雨裏，建業暮鐘時。漠漠帆來重，冥冥鳥去遲。", "海門深不見，浦樹遠含滋。相送情無限，沾襟比散絲。"]'),
('yuding-21','留別洛京親友','韋應物','唐','御定全唐诗','yuding','','[]','握手出都門，駕言適京師。豈不懷舊廬，惆悵與子辭。',84,'御定全唐詩/json/189.json','["握手出都門，駕言適京師。豈不懷舊廬，惆悵與子辭。", "麗日坐高閣，清觴宴華池。昨遊倏已過，後遇良未知。", "念結路方永，歲陰野無暉。單車我當前，暮雪子獨歸。", "臨流一相望，零淚忽沾衣。"]'),
('yuding-22','賦得沙際路，送從叔象','韋應物','唐','御定全唐诗','yuding','','[]','獨樹沙邊人跡稀，欲行愁遠暮鐘時。',32,'御定全唐詩/json/189.json','["獨樹沙邊人跡稀，欲行愁遠暮鐘時。", "野泉幾處侵應盡，不遇山僧知問誰。"]'),
('yuding-23','送榆次林明府','韋應物','唐','御定全唐诗','yuding','','[]','無嗟千里遠，亦是宰王畿。策馬雨中去，逢人關外稀。',48,'御定全唐詩/json/189.json','["無嗟千里遠，亦是宰王畿。策馬雨中去，逢人關外稀。", "邑傳榆石在，路繞晉山微。別思方蕭索，新秋一葉飛。"]'),
('yuding-24','雜言送黎六郎','韋應物','唐','御定全唐诗','yuding','','[]','冰壺見底未為清，少年如玉有詩名。聞話嵩峰多野寺，',72,'御定全唐詩/json/189.json','["冰壺見底未為清，少年如玉有詩名。聞話嵩峰多野寺，", "河南庭下拜府君，陽城歸路山氛氳。山氛氳，長不見。", "釣台水淥荷已生，少姨廟寒花始遍。縣閑吏傲與塵隔，"]'),
('yuding-25','天長寺上方別子西有道','韋應物','唐','御定全唐诗','yuding','','[]','假邑非拙素，況乃別伊人。聊登釋氏居，攜手戀茲晨。',84,'御定全唐詩/json/189.json','["假邑非拙素，況乃別伊人。聊登釋氏居，攜手戀茲晨。", "高曠出塵表，逍遙滌心神。青山對芳苑，列樹繞通津。", "車馬無時絕，行子倦風塵。今當遵往路，佇立欲何申。", "唯持貞白志，以慰心所親。"]'),
('yuding-26','送黎六郎赴陽翟少府','韋應物','唐','御定全唐诗','yuding','','[]','試吏向嵩陽，春山躑躅芳。腰垂新綬色，衣滿舊芸香。',48,'御定全唐詩/json/189.json','["試吏向嵩陽，春山躑躅芳。腰垂新綬色，衣滿舊芸香。", "喬樹別時綠，客程關外長。只應傳善政，日夕慰高堂。"]'),
('yuding-27','送別覃孝廉','韋應物','唐','御定全唐诗','yuding','','[]','思親自當去，不第未蹉跎。家住青山下，門前芳草多。',48,'御定全唐詩/json/189.json','["思親自當去，不第未蹉跎。家住青山下，門前芳草多。", "秭歸通遠徼，巫峽注驚波。州舉年年事，還期複幾何。"]'),
('yuding-28','送開封盧少府','韋應物','唐','御定全唐诗','yuding','','[]','雄藩車馬地，作尉有光輝。滿席賓常侍，闐街燭夜歸。',48,'御定全唐詩/json/189.json','["雄藩車馬地，作尉有光輝。滿席賓常侍，闐街燭夜歸。", "關河征旆遠，煙樹夕陽微。到處無留滯，梁園花欲稀。"]'),
('yuding-29','送槐廣落第歸揚州','韋應物','唐','御定全唐诗','yuding','','[]','下第常稱屈，少年心獨輕。拜親歸海畔，似舅得詩名。',48,'御定全唐詩/json/189.json','["下第常稱屈，少年心獨輕。拜親歸海畔，似舅得詩名。", "晚對青山別，遙尋芳草行。還期應不遠，寒露濕蕪城。"]'),
('yuding-30','送汾城王主簿','韋應物','唐','御定全唐诗','yuding','','[]','少年初帶印，汾上又經過。芳草歸時遍，情人故郡多。',48,'御定全唐詩/json/189.json','["少年初帶印，汾上又經過。芳草歸時遍，情人故郡多。", "禁鐘春雨細，宮樹野煙和。相望東橋別，微風起夕波。"]'),
('yuding-31','送澠池崔主簿','韋應物','唐','御定全唐诗','yuding','','[]','邑帶洛陽道，年年應此行。當時匹馬客，今日縣人迎。',48,'御定全唐詩/json/189.json','["邑帶洛陽道，年年應此行。當時匹馬客，今日縣人迎。", "暮雨投關郡，春風別帝城。東西殊不遠，朝夕待佳聲。"]'),
('yuding-32','送顏司議使蜀訪圖書','韋應物','唐','御定全唐诗','yuding','','[]','軺駕一封急，蜀門千嶺曛。詎分江轉字，但見路緣雲。',48,'御定全唐詩/json/189.json','["軺駕一封急，蜀門千嶺曛。詎分江轉字，但見路緣雲。", "山館夜聽雨，秋猿獨叫群。無為久留滯，聖主待遺文。"]'),
('yuding-33','奉送從兄宰晉陵','韋應物','唐','御定全唐诗','yuding','','[]','東郊暮草歇，千里夏雲生。立馬愁將夕，看山獨送行。',48,'御定全唐詩/json/189.json','["東郊暮草歇，千里夏雲生。立馬愁將夕，看山獨送行。", "依微吳苑樹，迢遞晉陵城。慰此斷行別，邑人多頌聲。"]'),
('yuding-34','贈別河南李功曹','韋應物','唐','御定全唐诗','yuding','','[]','耿耿抱私戚，寥寥獨掩扉。臨觴自不飲，況與故人違。',120,'御定全唐詩/json/189.json','["耿耿抱私戚，寥寥獨掩扉。臨觴自不飲，況與故人違。", "故人方琢磨，瑰朗代所稀。憲禮更右職，文翰灑天機。", "聿來自東山，群彥仰餘輝。談笑取高第，綰綬即言歸。", "洛都游燕地，千里及芳菲。今朝章台別，楊柳亦依依。", "雲霞未改色，山川猶夕暉。忽複不相見，心思亂霏霏。"]'),
('yuding-35','送五經趙隨登科授廣德尉','韋應物','唐','御定全唐诗','yuding','','[]','明經有清秩，當在石渠中。獨往宣城郡，高齋謁謝公。',48,'御定全唐詩/json/189.json','["明經有清秩，當在石渠中。獨往宣城郡，高齋謁謝公。", "寒原正蕪漫，夕鳥自西東。秋日不堪別，淒淒多朔風。"]'),
('yuding-36','宴別幼遐與君貺兄弟','韋應物','唐','御定全唐诗','yuding','','[]','乖闕意方弭，安知忽來翔。累日重歡宴，一旦複離傷。',108,'御定全唐詩/json/189.json','["乖闕意方弭，安知忽來翔。累日重歡宴，一旦複離傷。", "置酒慰茲夕，秉燭坐華堂。契闊未及展，晨星出東方。", "征人慘已辭，車馬儼成裝。我懷自無歡，原野滿春光。", "群水含時澤，野雉鳴朝陽。平生有壯志，不覺淚沾裳。", "況自守空宇，日夕但彷徨。"]'),
('yuding-37','送宣州周錄事','韋應物','唐','御定全唐诗','yuding','','[]','清時重儒士，糾郡屬伊人。薄游長安中，始得一交親。',96,'御定全唐詩/json/189.json','["清時重儒士，糾郡屬伊人。薄游長安中，始得一交親。", "英豪若雲集，餞別塞城闉。高駕臨長路，日夕起風塵。", "方念清宵宴，已度芳林春。從茲一分手，緬邈吳與秦。", "但睹年運駛，安知後會因。唯當存令德，可以解悁勤。"]'),
('yuding-38','謝櫟陽令歸西郊，贈別諸友生','韋應物','唐','御定全唐诗','yuding','','[]','結髮仕州縣，蹉跎在文墨。徒有排雲心，何由生羽翼。',132,'御定全唐詩/json/189.json','["結髮仕州縣，蹉跎在文墨。徒有排雲心，何由生羽翼。", "幸遭明盛日，萬物蒙生植。獨此抱微痾，頹然謝斯職。", "世道方荏苒，郊園思偃息。為歡日已延，君子情未極。", "馳觴忽雲晏，高論良難測。游步清都宮，迎風嘉樹側。", "晨起西郊道，原野分黍稷。自樂陶唐人，服勤在微力。", "佇君列丹陛，出處兩為得。"]'),
('yuding-39','送端東行','韋應物','唐','御定全唐诗','yuding','','[]','世承清白遺，躬服古人言。從官俱守道，歸來共閉門。',36,'御定全唐詩/json/189.json','["世承清白遺，躬服古人言。從官俱守道，歸來共閉門。", "驅車何處去，暮雪滿平原。"]'),
('yuding-40','送姚孫還河中','韋應物','唐','御定全唐诗','yuding','','[]','上國旅遊罷，故園生事微。風塵滿路起，行人何處歸。',48,'御定全唐詩/json/189.json','["上國旅遊罷，故園生事微。風塵滿路起，行人何處歸。", "留思芳樹飲，惜別暮春暉。幾日投關郡，河山對掩扉。"]'),
('yuding-41','始除尚書郎，別善福精舍','韋應物','唐','御定全唐诗','yuding','','[]','簡略非世器，委身同草木。逍遙精舍居，飲酒自為足。',144,'御定全唐詩/json/189.json','["簡略非世器，委身同草木。逍遙精舍居，飲酒自為足。", "累日曾一櫛，對書常懶讀。社臘會高年，山川恣遊矚。", "明世方選士，中朝懸美祿。除書忽到門，冠帶便拘束。", "愧忝郎署跡，謬蒙君子錄。俯仰垂華纓，飄颻翔輕轂。", "行將親愛別，戀此西澗曲。遠峰明夕川，夏雨生眾綠。", "迅風飄野路，回首不遑宿。明晨下煙閣，白雲在幽谷。"]'),
('yuding-42','送常侍禦卻使西蕃','韋應物','唐','御定全唐诗','yuding','','[]','歸奏聖朝行萬里，卻銜天詔報蕃臣。本是諸生守文墨，',40,'御定全唐詩/json/189.json','["歸奏聖朝行萬里，卻銜天詔報蕃臣。本是諸生守文墨，", "此去多應收故地，甯辭沙塞往來頻。"]'),
('yuding-43','送郗詹事','韋應物','唐','御定全唐诗','yuding','','[]','聖朝列群彥，穆穆佐休明。君子獨知止，懸車守國程。',120,'御定全唐詩/json/189.json','["聖朝列群彥，穆穆佐休明。君子獨知止，懸車守國程。", "忠良信舊德，文學播英聲。既獲天爵美，況將齒位並。", "書奏蒙省察，命駕乃東征。皇恩賜印綬，歸為田裏榮。", "朝野同稱歎，園綺郁齊名。長衢軒蓋集，飲餞出西京。", "時屬春陽節，草木已含英。洛川當盛宴，斯焉為達生。"]'),
('yuding-44','送蘇評事','韋應物','唐','御定全唐诗','yuding','','[]','季弟仕譙都，元兄坐蘭省。言訪始忻忻，念離當耿耿。',48,'御定全唐詩/json/189.json','["季弟仕譙都，元兄坐蘭省。言訪始忻忻，念離當耿耿。", "嵯峨夏雲起，迢遞山川永。登高望去塵，紛思終難整。"]'),
('yuding-45','送李侍禦益赴幽州幕','韋應物','唐','御定全唐诗','yuding','','[]','二十揮篇翰，三十窮典墳。辟書五府至，名為四海聞。',108,'御定全唐詩/json/189.json','["二十揮篇翰，三十窮典墳。辟書五府至，名為四海聞。", "始從車騎幕，今赴嫖姚軍。契闊晚相遇，草戚遽離群。", "悠悠行子遠，眇眇川途分。登高望燕代，日夕生夏雲。", "司徒擁精甲，誓將除國氛。儒生幸持斧，可以佐功勳。", "無言羽書急，坐闕相思文。"]'),
('yuding-46','自尚書郎出為滁州刺史','韋應物','唐','御定全唐诗','yuding','','[]','少年不遠仕，秉笏東西京。中歲守淮郡，奉命乃征行。',132,'御定全唐詩/json/189.json','["少年不遠仕，秉笏東西京。中歲守淮郡，奉命乃征行。", "素慚省閣姿，況忝符竹榮。效愚方此始，顧私豈獲並。", "徘徊親交戀，愴悢昆友情。日暮風雪起，我去子還城。", "登途建隼旟，勒駕望承明。雲台煥中天，龍闕鬱上征。", "晨興奉早朝，玉露沾華纓。一朝從此去，服膺理庶甿。", "皇恩倘歲月，歸服廁群英。"]'),
('yuding-47','送元錫、楊淩','韋應物','唐','御定全唐诗','yuding','','[]','荒林翳山郭，積水成秋晦。端居意自違，況別親與愛。',48,'御定全唐詩/json/189.json','["荒林翳山郭，積水成秋晦。端居意自違，況別親與愛。", "歡筵慊未足，離燈悄已對。還當掩郡閣，佇君方此會。"]'),
('yuding-48','送楊氏女','韋應物','唐','御定全唐诗','yuding','','[]','永日方戚戚，出門複悠悠。女子今有行，大江溯輕舟。',144,'御定全唐詩/json/189.json','["永日方戚戚，出門複悠悠。女子今有行，大江溯輕舟。", "爾輩況無恃，撫念益慈柔。幼為長所育，兩別泣不休。", "對此結中腸，義往難複留。自小闕內訓，事姑貽我憂。", "賴茲托令門，仁恤庶無尤。貧儉誠所尚，資從豈待周。", "孝恭遵婦道，容止順其猷。別離在今晨，見爾當何秋。", "居閑始自遣，臨感忽難收。歸來視幼女，零淚緣纓流。"]'),
('yuding-49','送中弟','韋應物','唐','御定全唐诗','yuding','','[]','秋風入疏戶，離人起晨朝。山郡多風雨，西樓更蕭條。',48,'御定全唐詩/json/189.json','["秋風入疏戶，離人起晨朝。山郡多風雨，西樓更蕭條。", "嗟予淮海老，送子關河遙。同來不同去，沉憂寧複消。"]'),
('yuding-50','寄別李儋','韋應物','唐','御定全唐诗','yuding','','[]','首戴惠文冠，心有決勝籌。翩翩四五騎，結束向並州。',96,'御定全唐詩/json/189.json','["首戴惠文冠，心有決勝籌。翩翩四五騎，結束向並州。", "名在相公幕，丘山恩未酬。妻子不及顧，親友安得留。", "宿昔同文翰，交分共綢繆。忽枉別離劄，涕淚一交流。", "遠郡臥殘疾，涼氣滿西樓。想子臨長路，時當淮海秋。"]'),
('yuding-51','送倉部蕭員外院長存','韋應物','唐','御定全唐诗','yuding','','[]','襆被蹉跎老江國，情人邂逅此相逢。',32,'御定全唐詩/json/189.json','["襆被蹉跎老江國，情人邂逅此相逢。", "不隨鴛鷺朝天去，遙想蓬萊台閣重。"]'),
('yuding-52','送王校書','韋應物','唐','御定全唐诗','yuding','','[]','同宿高齋換時節，共看移石複栽杉。',32,'御定全唐詩/json/189.json','["同宿高齋換時節，共看移石複栽杉。", "送君江浦已惆悵，更上西樓看遠帆。"]'),
('yuding-53','送丘員外還山','韋應物','唐','御定全唐诗','yuding','','[]','長棲白雲表，暫訪高齋宿。還辭郡邑喧，歸泛松江淥。',72,'御定全唐詩/json/189.json','["長棲白雲表，暫訪高齋宿。還辭郡邑喧，歸泛松江淥。", "結茅隱蒼嶺，伐薪響深谷。同是山中人，不知往來躅。", "靈芝非庭草，遼鶴委池鶩。終當署裏門，一表高陽族。"]'),
('yuding-54','重送丘二十二還臨平山居','韋應物','唐','御定全唐诗','yuding','','[]','歲中始再覯，方來又解攜。才留野艇語，已憶故山棲。',48,'御定全唐詩/json/189.json','["歲中始再覯，方來又解攜。才留野艇語，已憶故山棲。", "幽澗人夜汲，深林鳥長啼。還持郡齋酒，慰子霜露淒。"]'),
('yuding-55','送鄭端公弟移院常州','韋應物','唐','御定全唐诗','yuding','','[]','時瞻憲臣重，禮為內兄全。公程儻見責，私愛信不愆。',72,'御定全唐詩/json/189.json','["時瞻憲臣重，禮為內兄全。公程儻見責，私愛信不愆。", "況昔陪朝列，今茲俱海壖。清觴方對酌，天書忽告遷。", "豈徒咫尺地，使我心思綿。應當自此始，歸拜雲台前。"]'),
('yuding-56','送房杭州','韋應物','唐','御定全唐诗','yuding','','[]','專城未四十，暫謫豈蹉跎。風雨吳門夜，惻愴別情多。',24,'御定全唐詩/json/189.json','["專城未四十，暫謫豈蹉跎。風雨吳門夜，惻愴別情多。"]'),
('yuding-57','送陸侍禦還越','韋應物','唐','御定全唐诗','yuding','','[]','居藩久不樂，遇子聊一欣。英聲頗籍甚，交辟乃時珍。',96,'御定全唐詩/json/189.json','["居藩久不樂，遇子聊一欣。英聲頗籍甚，交辟乃時珍。", "繡衣過舊裏，驄馬輝四鄰。敬恭尊郡守，箋簡具州民。", "謬忝誠所愧，思懷方見申。置榻宿清夜，加籩宴良辰。", "遵途還盛府，行舫繞長津。自有賢方伯，得此文翰賓。"]'),
('yuding-58','聽江笛送陸侍禦','韋應物','唐','御定全唐诗','yuding','','[]','遠聽江上笛，臨觴一送君。還愁獨宿夜，更向郡齋聞。',24,'御定全唐詩/json/189.json','["遠聽江上笛，臨觴一送君。還愁獨宿夜，更向郡齋聞。"]'),
('yuding-59','送丘員外歸山居','韋應物','唐','御定全唐诗','yuding','','[]','郡閣始嘉宴，青山憶舊居。為君量革履，且願住藍輿。',24,'御定全唐詩/json/189.json','["郡閣始嘉宴，青山憶舊居。為君量革履，且願住藍輿。"]'),
('yuding-60','送崔叔清游越','韋應物','唐','御定全唐诗','yuding','','[]','忘茲適越意，愛我郡齋幽。野情豈好謁，詩興一相留。',48,'御定全唐詩/json/189.json','["忘茲適越意，愛我郡齋幽。野情豈好謁，詩興一相留。", "遠水帶寒樹，閶門望去舟。方伯憐文士，無為成滯遊。"]'),
('yuding-61','送雲陽鄒儒立少府侍奉還京師','韋應物','唐','御定全唐诗','yuding','','[]','建中即藩守，天寶為侍臣。曆觀兩都士，多閱諸侯人。',144,'御定全唐詩/json/189.json','["建中即藩守，天寶為侍臣。曆觀兩都士，多閱諸侯人。", "鄒生乃後來，英俊亦罕倫。為文頗瑰麗，稟度自貞醇。", "甲科推令名，延閣播芳塵。再命趨王畿，請告奉慈親。", "一鐘信榮祿，可以展歡欣。昆弟俱時秀，長衢當自伸。", "聊從郡閣暇，美此時景新。方將極娛宴，已複及離晨。", "省署慚再入，江海綿十春。今日閶門路，握手子歸秦。"]'),
('yuding-62','送豆盧策秀才','韋應物','唐','御定全唐诗','yuding','','[]','歲交冰未泮，地卑海氣昏。子有京師遊，始發吳閶門。',96,'御定全唐詩/json/189.json','["歲交冰未泮，地卑海氣昏。子有京師遊，始發吳閶門。", "新黃含遠林，微綠生陳根。詩人感時節，行道當憂煩。", "古來濩落者，俱不事田園。文如金石韻，豈乏知音言。", "方辭郡齋榻，為酌離亭樽。無為倦羈旅，一去高飛翻。"]'),
('yuding-63','送王卿','韋應物','唐','御定全唐诗','yuding','','[]','別酌春林啼鳥稀，雙旌背日晚風吹。',32,'御定全唐詩/json/189.json','["別酌春林啼鳥稀，雙旌背日晚風吹。", "卻憶回來花已盡，東郊立馬望城池。"]'),
('yuding-64','送劉評事','韋應物','唐','御定全唐诗','yuding','','[]','聲華滿京洛，藻翰發陽春。未遂鵷鴻舉，尚為江海賓。',108,'御定全唐詩/json/189.json','["聲華滿京洛，藻翰發陽春。未遂鵷鴻舉，尚為江海賓。", "吳中高宴罷，西上一游秦。已想函關道，遊子冒風塵。", "籠禽羨歸翼，遠守懷交親。況複歲雲暮，凜凜冰霜辰。", "旭霽開郡閣，寵餞集文人。洞庭摘朱實，松江獻白鱗。", "丈夫豈恨別，一酌且歡忻。"]'),
('yuding-65','送雷監赴闕庭','韋應物','唐','御定全唐诗','yuding','','[]','才大無不備，出入為時須。雄藩精理行，秘府擢文儒。',96,'御定全唐詩/json/189.json','["才大無不備，出入為時須。雄藩精理行，秘府擢文儒。", "詔書忽已至，焉得久踟躕。方舟趁朝謁，觀者盈路衢。", "廣筵列眾賓，送爵無停迂。攀餞誠愴恨，賀榮且歡娛。", "長陪柏梁宴，日向丹墀趨。時方重右職，蹉跎獨海隅。"]'),
('yuding-66','送秦系赴潤州','韋應物','唐','御定全唐诗','yuding','','[]','近作新婚鑷白髯，長懷舊卷映藍衫。',32,'御定全唐詩/json/189.json','["近作新婚鑷白髯，長懷舊卷映藍衫。", "更欲攜君虎丘寺，不知方伯望征帆。"]'),
('yuding-67','送孫征赴雲中','韋應物','唐','御定全唐诗','yuding','','[]','黃驄少年舞雙戟，目視旁人皆辟易。百戰曾誇隴上兒，',48,'御定全唐詩/json/189.json','["黃驄少年舞雙戟，目視旁人皆辟易。百戰曾誇隴上兒，", "敲石軍中傳夜火，斧冰河畔汲朝漿。前鋒直指陰山外，"]'),
('yuding-0','期盧嵩，枉書稱日暮無馬不赴，以詩答','韋應物','唐','御定全唐诗','yuding','','[]','佳期不可失，終願枉衡門。南陌人猶度，西林日未昏。',48,'御定全唐詩/json/190.json','["佳期不可失，終願枉衡門。南陌人猶度，西林日未昏。", "庭前空倚杖，花裏獨留樽。莫道無來駕，知君有短轅。"]'),
('yuding-1','任洛陽丞，答前長安田少府問','韋應物','唐','御定全唐诗','yuding','','[]','相逢且對酒，相問欲何如。數歲猶卑吏，家人笑著書。',48,'御定全唐詩/json/190.json','["相逢且對酒，相問欲何如。數歲猶卑吏，家人笑著書。", "告歸應未得，榮宦又知疏。日日生春草，空令憶舊居。"]'),
('yuding-2','假中枉盧二十二書亦稱臥疾兼訝李二久不訪問以詩答書因亦戲李二','韋應物','唐','御定全唐诗','yuding','','[]','微官何事勞趨走，服藥閑眠養不才。花裏棋盤憎鳥汙，',40,'御定全唐詩/json/190.json','["微官何事勞趨走，服藥閑眠養不才。花裏棋盤憎鳥汙，", "應笑王戎成俗物，遙持麈尾獨徘徊。"]'),
('yuding-3','酬盧嵩秋夜見寄五韻','韋應物','唐','御定全唐诗','yuding','','[]','喬木生夜涼，月華滿前墀。去君咫尺地，勞君千里思。',60,'御定全唐詩/json/190.json','["喬木生夜涼，月華滿前墀。去君咫尺地，勞君千里思。", "素秉棲遁志，況貽招隱詩。坐見林木榮，願赴滄洲期。", "何能待歲晏，攜手當此時。"]'),
('yuding-4','酬鄭戶曹驪山感懷','韋應物','唐','御定全唐诗','yuding','','[]','蒼山何鬱盤，飛閣淩上清。先帝昔好道，下元朝百靈。',192,'御定全唐詩/json/190.json','["蒼山何鬱盤，飛閣淩上清。先帝昔好道，下元朝百靈。", "白雲已蕭條，麋鹿但縱橫。泉水今尚暖，舊林亦青青。", "我念綺襦歲，扈從當太平。小臣職前驅，馳道出灞亭。", "翻翻日月旗，殷殷鼙鼓聲。萬馬自騰驤，八駿按轡行。", "日出煙嶠綠，氛氳麗層甍。登臨起遐想，沐浴歡聖情。", "朝燕詠無事，時豐賀國禎。日和絃管音，下使萬室聽。", "海內湊朝貢，賢愚共歡榮。合遝車馬喧，西聞長安城。", "事往世如寄，感深跡所經。申章報蘭藻，一望雙涕零。"]'),
('yuding-5','答李浣三首','韋應物','唐','御定全唐诗','yuding','','[]','孤客逢春暮，緘情寄舊遊。海隅人使遠，書到洛陽秋。',72,'御定全唐詩/json/190.json','["孤客逢春暮，緘情寄舊遊。海隅人使遠，書到洛陽秋。", "馬卿猶有壁，漁父自無家。想子今何處，扁舟隱荻花。", "林中觀易罷，溪上對鷗閑。楚俗饒辭客，何人最往還。"]'),
('yuding-6','酬柳郎中春日歸揚州南郭見別之作','韋應物','唐','御定全唐诗','yuding','','[]','廣陵三月花正開，花裏逢君醉一回。',32,'御定全唐詩/json/190.json','["廣陵三月花正開，花裏逢君醉一回。", "南北相過殊不遠，暮潮從去早潮來。"]'),
('yuding-7','酬豆盧倉曹題庫壁見示','韋應物','唐','御定全唐诗','yuding','','[]','掾局勞才子，新詩動洛川。運籌知決勝，聚米似論邊。',48,'御定全唐詩/json/190.json','["掾局勞才子，新詩動洛川。運籌知決勝，聚米似論邊。", "宴罷常分騎，晨趨又比肩。莫嗟年鬢改，郎署定推先。"]'),
('yuding-8','酬李儋','韋應物','唐','御定全唐诗','yuding','','[]','開門臨廣陌，旭旦車駕喧。不見同心友，徘徊憂且煩。',96,'御定全唐詩/json/190.json','["開門臨廣陌，旭旦車駕喧。不見同心友，徘徊憂且煩。", "都城二十裏，居在艮與坤。人生所各務，乖闊累朝昏。", "湛湛樽中酒，青青芳樹園。緘情未及發，先此枉璵璠。", "邁世超高躅，尋流得真源。明當策疲馬，與子同笑言。"]'),
('yuding-9','酬元偉過洛陽夜燕','韋應物','唐','御定全唐诗','yuding','','[]','三載寄關東，所歡皆遠違。思懷方耿耿，忽得觀容輝。',96,'御定全唐詩/json/190.json','["三載寄關東，所歡皆遠違。思懷方耿耿，忽得觀容輝。", "親燕在良夜，歡攜辟中闈。問我猶杜門，不能奮高飛。", "明燈照四隅，炎炭正可依。清觴雖雲酌，所愧乏珍肥。", "晨裝複當行，寥落星已稀。何以慰心曲，佇子西還歸。"]'),
('yuding-10','酬韓質舟行阻凍','韋應物','唐','御定全唐诗','yuding','','[]','晨坐枉嘉藻，持此慰寢興。中獲辛苦奏，長河結陰冰。',96,'御定全唐詩/json/190.json','["晨坐枉嘉藻，持此慰寢興。中獲辛苦奏，長河結陰冰。", "皓曜群玉發，淒清孤景凝。至柔反成堅，造化安可恒。", "方舟未得行，鑿飲空兢兢。寒苦彌時節，待泮豈所能。", "何必涉廣川，荒衢且升騰。殷勤宣中意，庶用達吾朋。"]'),
('yuding-11','李博士弟以余罷官居同德精舍共有伊陸名山之期久而未去枉詩見問中云宋生昔登覽未云那能顧蓬蓽直寄鄙懷聊以為答','韋應物','唐','御定全唐诗','yuding','','[]','初夏息眾緣，雙林對禪客。枉茲芳蘭藻，促我幽人策。',96,'御定全唐詩/json/190.json','["初夏息眾緣，雙林對禪客。枉茲芳蘭藻，促我幽人策。", "冥搜企前哲，逸句陳往跡。仿佛陸渾南，迢遞千峰碧。", "從來遲高駕，自顧無物役。山水心所娛，如何更朝夕。", "晨興涉清洛，訪子高陽宅。莫言往來疏，駑馬知阡陌。"]'),
('yuding-12','寄酬李博士永甯主簿叔廳見待','韋應物','唐','御定全唐诗','yuding','','[]','解鞍先幾日，款曲見新詩。定向公堂醉，遙憐獨去時。',48,'御定全唐詩/json/190.json','["解鞍先幾日，款曲見新詩。定向公堂醉，遙憐獨去時。", "葉沾寒雨落，鐘度遠山遲。晨策已雲整，當同林下期。"]'),
('yuding-13','答令狐士曹、獨孤兵曹聯騎暮歸望山見寄','韋應物','唐','御定全唐诗','yuding','','[]','共愛青山住近南，行牽吏役背雙驂。',32,'御定全唐詩/json/190.json','["共愛青山住近南，行牽吏役背雙驂。", "枉書獨宿對流水，遙羨歸時滿夕嵐。"]'),
('yuding-14','答李博士','韋應物','唐','御定全唐诗','yuding','','[]','休沐去人遠，高齋出林杪。晴山多碧峰，顥氣疑秋曉。',96,'御定全唐詩/json/190.json','["休沐去人遠，高齋出林杪。晴山多碧峰，顥氣疑秋曉。", "端居喜良友，枉使千里路。緘書當夏時，開緘時已度。", "簷雛已颻颺，荷露方蕭颯。夢遠竹窗幽，行稀蘭徑合。", "舊居共南北，往來只如昨。問君今為誰，日夕度清洛。"]'),
('yuding-15','答劉西曹','韋應物','唐','御定全唐诗','yuding','','[]','公館夜雲寂，微涼群樹秋。西曹得時彥，華月共淹留。',96,'御定全唐詩/json/190.json','["公館夜雲寂，微涼群樹秋。西曹得時彥，華月共淹留。", "長嘯舉清觴，志氣誰與儔。千齡事雖邈，俯念忽已周。", "篇翰如雲興，京洛頗優遊。詮文不獨古，理妙即同流。", "淺劣見推許，恐為識者尤。空慚文璧贈，日夕不能酬。"]'),
('yuding-16','答貢士黎逢','韋應物','唐','御定全唐诗','yuding','','[]','茂等方上達，諸生安可希。棲神澹物表，渙汗布令詞。',84,'御定全唐詩/json/190.json','["茂等方上達，諸生安可希。棲神澹物表，渙汗布令詞。", "如彼昆山玉，本自有光輝。鄙人徒區區，稱歎亦何為。", "彌月曠不接，公門但驅馳。蘭章忽有贈，持用慰所思。", "不見心尚密，況當相見時。"]'),
('yuding-17','答韓庫部','韋應物','唐','御定全唐诗','yuding','','[]','良玉表貞度，麗藻頗為工。名列金閨籍，心與素士同。',96,'御定全唐詩/json/190.json','["良玉表貞度，麗藻頗為工。名列金閨籍，心與素士同。", "日晏下朝來，車馬自生風。清宵有佳興，皓月直南宮。", "矯翮方上征，顧我邈忡忡。豈不願攀舉，執事府庭中。", "智乖時亦蹇，才大命有通。還當以道推，解組守蒿蓬。"]'),
('yuding-18','答崔主簿倬','韋應物','唐','御定全唐诗','yuding','','[]','朗月分林靄，遙管動離聲。故歡良已阻，空宇澹無情。',48,'御定全唐詩/json/190.json','["朗月分林靄，遙管動離聲。故歡良已阻，空宇澹無情。", "窈窕雲雁沒，蒼茫河漢橫。蘭章不可答，沖襟徒自盈。"]'),
('yuding-19','答徐秀才','韋應物','唐','御定全唐诗','yuding','','[]','鉛鈍謝貞器，時秀猥見稱。豈如白玉仙，方與紫霞升。',48,'御定全唐詩/json/190.json','["鉛鈍謝貞器，時秀猥見稱。豈如白玉仙，方與紫霞升。", "清詩舞豔雪，孤抱瑩玄冰。一枝非所貴，懷書思武陵。"]'),
('yuding-20','答東林道士','韋應物','唐','御定全唐诗','yuding','','[]','紫閣西邊第幾峰，茅齋夜雪虎行蹤。',32,'御定全唐詩/json/190.json','["紫閣西邊第幾峰，茅齋夜雪虎行蹤。", "遙看黛色知何處，欲出山門尋暮鐘。"]'),
('yuding-21','答長寧令楊轍','韋應物','唐','御定全唐诗','yuding','','[]','皓月升林表，公堂滿清輝。嘉賓自遠至，觴飲夜何其。',108,'御定全唐詩/json/190.json','["皓月升林表，公堂滿清輝。嘉賓自遠至，觴飲夜何其。", "宰邑視京縣，歸來無寸資。瑰文溢眾寶，雅正得吾師。", "廣川含澄瀾，茂樹擢華滋。短才何足數，枉贈愧妍詞。", "歡盼良見屬，素懷亦已披。何意雲棲翰，不嫌蓬艾卑。", "但恐河漢沒，回車首路岐。"]'),
('yuding-22','答馮魯秀才','韋應物','唐','御定全唐诗','yuding','','[]','晨坐枉瓊藻，知子返中林。澹然山景晏，泉穀響幽禽。',84,'御定全唐詩/json/190.json','["晨坐枉瓊藻，知子返中林。澹然山景晏，泉穀響幽禽。", "仿佛謝塵跡，逍遙舒道心。顧我腰間綬，端為華髮侵。", "簿書勞應對，篇翰曠不尋。薄田失鋤耨，生苗安可任。", "徒令慚所問，想望東山岑。"]'),
('yuding-23','答崔主簿問，兼簡溫上人','韋應物','唐','御定全唐诗','yuding','','[]','緣情生眾累，晚悟依道流。諸境一已寂，了將身世浮。',72,'御定全唐詩/json/190.json','["緣情生眾累，晚悟依道流。諸境一已寂，了將身世浮。", "閒居澹無味，忽複四時周。靡靡芳草積，稍稍新篁抽。", "即此抱餘素，塊然誠寡儔。自適一忻意，愧蒙君子憂。"]'),
('yuding-24','清都觀答幼遐','韋應物','唐','御定全唐诗','yuding','','[]','逍遙仙家子，日夕朝玉皇。興高清露沒，渴飲瓊華漿。',108,'御定全唐詩/json/190.json','["逍遙仙家子，日夕朝玉皇。興高清露沒，渴飲瓊華漿。", "解組一來款，披衣拂天香。粲然顧我笑，綠簡發新章。", "泠泠如玉音，馥馥若蘭芳。浩意坐盈此，月華殊未央。", "卻念喧嘩日，何由得清涼。疏鬆抗高殿，密竹陰長廊。", "榮名等糞土，攜手隨風翔。"]'),
('yuding-25','善福精舍答韓司錄清都觀會宴見憶','韋應物','唐','御定全唐诗','yuding','','[]','弱志厭眾紛，抱素寄精廬。皦皦仰時彥，悶悶獨為愚。',120,'御定全唐詩/json/190.json','["弱志厭眾紛，抱素寄精廬。皦皦仰時彥，悶悶獨為愚。", "之子亦辭秩，高蹤罷馳驅。忽因西飛禽，贈我以瓊琚。", "始表仙都集，複言歡樂殊。人生各有因，契闊不獲俱。", "一來田野中，日與人事疏。水木澄秋景，逍遙清賞餘。", "枉駕懷前諾，引領豈斯須。無為便高翔，邈矣不可迂。"]'),
('yuding-26','答長安丞裴說','韋應物','唐','御定全唐诗','yuding','','[]','出身忝時士，於世本無機。爰以林壑趣，遂成頑鈍姿。',108,'御定全唐詩/json/190.json','["出身忝時士，於世本無機。爰以林壑趣，遂成頑鈍姿。", "臨流意已淒，采菊露未稀。舉頭見秋山，萬事都若遺。", "獨踐幽人蹤，邈將親友違。髦士佐京邑，懷念枉貞詞。", "久雨積幽抱，清樽宴良知。從容操劇務，文翰方見推。", "安能戢羽翼，顧此林棲時。"]'),
('yuding-27','奉酬處士叔見示','韋應物','唐','御定全唐诗','yuding','','[]','掛纓守貧賤，積雪臥郊園。叔父親降趾，壺觴攜到門。',48,'御定全唐詩/json/190.json','["掛纓守貧賤，積雪臥郊園。叔父親降趾，壺觴攜到門。", "高齋樂宴罷，清夜道心存。即此同疏氏，可以一忘言。"]'),
('yuding-28','答庫部韓郎中','韋應物','唐','御定全唐诗','yuding','','[]','高士不羈世，頗將榮辱齊。適委華冕去，欲還幽林棲。',96,'御定全唐詩/json/190.json','["高士不羈世，頗將榮辱齊。適委華冕去，欲還幽林棲。", "雖懷承明戀，忻與物累暌。逍遙觀運流，誰複識端倪。", "而我豈高致，偃息平門西。愚者世所遺，沮溺共耕犁。", "風雪積深夜，園田掩荒蹊。幸蒙相思劄，款曲期見攜。"]'),
('yuding-29','答暢校書當','韋應物','唐','御定全唐诗','yuding','','[]','偶然棄官去，投跡在田中。日出照茅屋，園林養愚蒙。',108,'御定全唐詩/json/190.json','["偶然棄官去，投跡在田中。日出照茅屋，園林養愚蒙。", "雖雲無一資，樽酌會不空。且忻百谷成，仰歎造化功。", "出入與民伍，作事靡不同。時伐南澗竹，夜還灃水東。", "貧蹇自成退，豈為高人蹤。覽君金玉篇，彩色發我容。", "日月欲為報，方春已徂冬。"]'),
('yuding-30','答崔都水','韋應物','唐','御定全唐诗','yuding','','[]','深夜竹亭雪，孤燈案上書。不遇無為化，誰複得閒居。',24,'御定全唐詩/json/190.json','["深夜竹亭雪，孤燈案上書。不遇無為化，誰複得閒居。"]'),
('yuding-31','酬令狐司錄善福精舍見贈','韋應物','唐','御定全唐诗','yuding','','[]','野寺望山雪，空齋對竹林。我以養愚地，生君道者心。',24,'御定全唐詩/json/190.json','["野寺望山雪，空齋對竹林。我以養愚地，生君道者心。"]'),
('yuding-32','灃上精舍答趙氏外生伉','韋應物','唐','御定全唐诗','yuding','','[]','遠跡出塵表，寓身雙樹林。如何小子伉，亦有超世心。',96,'御定全唐詩/json/190.json','["遠跡出塵表，寓身雙樹林。如何小子伉，亦有超世心。", "擔書從我遊，攜手廣川陰。雲開夏郊綠，景晏青山沉。", "對榻遇清夜，獻詩合雅音。所推苟禮數，於性道豈深。", "隱拙在沖默，經世昧古今。無為率爾言，可以致華簪。"]'),
('yuding-33','答趙氏生伉','韋應物','唐','御定全唐诗','yuding','','[]','暫與雲林別，忽陪鴛鷺翔。看山不得去，知爾獨相望。',24,'御定全唐詩/json/190.json','["暫與雲林別，忽陪鴛鷺翔。看山不得去，知爾獨相望。"]'),
('yuding-34','答端','韋應物','唐','御定全唐诗','yuding','','[]','郊園夏雨歇，閑院綠陰生。職事方無效，幽賞獨違情。',48,'御定全唐詩/json/190.json','["郊園夏雨歇，閑院綠陰生。職事方無效，幽賞獨違情。", "物色坐如見，離抱悵多盈。況感夕涼氣，聞此亂蟬鳴。"]'),
('yuding-35','答史館張學士段柳庶子學士集賢院看花見寄兼呈柳學士','韋應物','唐','御定全唐诗','yuding','','[]','班楊秉文史，對院自為鄰。餘香掩閣去，遲日看花頻。',48,'御定全唐詩/json/190.json','["班楊秉文史，對院自為鄰。餘香掩閣去，遲日看花頻。", "似雪飄閶闔，從風點近臣。南宮有芳樹，不並禁垣春。"]'),
('yuding-36','答王郎中','韋應物','唐','御定全唐诗','yuding','','[]','臥閣枉芳藻，覽旨悵秋晨。守郡猶羈寓，無以慰嘉賓。',96,'御定全唐詩/json/190.json','["臥閣枉芳藻，覽旨悵秋晨。守郡猶羈寓，無以慰嘉賓。", "野曠歸雲盡，天清曉露新。池荷涼已至，窗梧落漸頻。", "風物殊京國，邑裏但荒榛。賦繁屬軍興，政拙愧斯人。", "髦士久台閣，中路一漂淪。歸當列盛朝，豈念臥淮濱。"]'),
('yuding-37','答崔都水','韋應物','唐','御定全唐诗','yuding','','[]','亭亭心中人，迢迢居秦關。常緘素劄去，適枉華章還。',204,'御定全唐詩/json/190.json','["亭亭心中人，迢迢居秦關。常緘素劄去，適枉華章還。", "憶在灃郊時，攜手望秋山。久嫌官府勞，初喜罷秩閑。", "終年不事業，寢食長慵頑。不知為時來，名籍掛郎間。", "攝衣辭田裏，華簪耀頹顏。卜居又依仁，日夕正追攀。", "牧人本無術，命至苟複遷。離念積歲序，歸途眇山川。", "郡齋有佳月，園林含清泉。同心不在宴，樽酒徒盈前。", "覽君陳跡遊，詞意俱淒妍。忽忽已終日，將酬不能宣。", "氓稅況重疊，公門極熬煎。責逋甘首免，歲晏當歸田。", "勿厭守窮轍，慎為名所牽。"]'),
('yuding-38','答王卿送別','韋應物','唐','御定全唐诗','yuding','','[]','去馬嘶春草，歸人立夕陽。元知數日別，要使兩情傷。',24,'御定全唐詩/json/190.json','["去馬嘶春草，歸人立夕陽。元知數日別，要使兩情傷。"]'),
('yuding-39','答裴丞說歸京所獻','韋應物','唐','御定全唐诗','yuding','','[]','執事頗勤久，行去亦傷乖。家貧無僮僕，吏卒升寢齋。',60,'御定全唐詩/json/190.json','["執事頗勤久，行去亦傷乖。家貧無僮僕，吏卒升寢齋。", "衣服藏內篋，藥草曝前階。誰複知次第，濩落且安排。", "還期在歲晏，何以慰吾懷。"]'),
('yuding-40','答裴處士','韋應物','唐','御定全唐诗','yuding','','[]','遺民愛精舍，乘犢入青山。來署高陽裏，不遇白衣還。',48,'御定全唐詩/json/190.json','["遺民愛精舍，乘犢入青山。來署高陽裏，不遇白衣還。", "禮賢方化俗，聞風自款關。況子逸群士，棲息蓬蒿間。"]'),
('yuding-41','答楊奉禮','韋應物','唐','御定全唐诗','yuding','','[]','多病守山郡，自得接嘉賓。不見三四日，曠若十餘旬。',108,'御定全唐詩/json/190.json','["多病守山郡，自得接嘉賓。不見三四日，曠若十餘旬。", "臨觴獨無味，對榻已生塵。一詠舟中作，灑雪忽驚新。", "煙波見棲旅，景物具昭陳。秋塘唯落葉，野寺不逢人。", "白事廷吏簡，閒居文墨親。高天池閣靜，寒菊霜露頻。", "應當整孤棹，歸來展殷勤。"]'),
('yuding-42','答端','韋應物','唐','御定全唐诗','yuding','','[]','坐憶故園人已老，寧知遠郡雁還來。',32,'御定全唐詩/json/190.json','["坐憶故園人已老，寧知遠郡雁還來。", "長瞻西北是歸路，獨上城樓日幾回。"]'),
('yuding-43','答僴奴、重陽二甥','韋應物','唐','御定全唐诗','yuding','','[]','棄職曾守拙，玩幽遂忘喧。山澗依磽瘠，竹樹蔭清源。',180,'御定全唐詩/json/190.json','["棄職曾守拙，玩幽遂忘喧。山澗依磽瘠，竹樹蔭清源。", "貧居煙火濕，歲熟梨棗繁。風雨飄茅屋，蒿草沒瓜園。", "群屬相歡悅，不覺過朝昏。有時看禾黍，落日上秋原。", "飲酒任真性，揮筆肆狂言。一朝忝蘭省，三載居遠藩。", "複與諸弟子，篇翰每相敦。西園休習射，南池對芳樽。", "山藥經雨碧，海榴淩霜翻。念爾不同此，悵然複一論。", "重陽守故家，僴子旅湘沅。俱有緘中藻，惻惻動離魂。", "不知何日見，衣上淚空存。"]'),
('yuding-44','答重陽','韋應物','唐','御定全唐诗','yuding','','[]','省劄陳往事，愴憶數年中。一身朝北闕，家累守田農。',96,'御定全唐詩/json/190.json','["省劄陳往事，愴憶數年中。一身朝北闕，家累守田農。", "望山亦臨水，暇日每來同。性情一疏散，園林多清風。", "忽複隔淮海，夢想在灃東。病來經時節，起見秋塘空。", "城郭連榛嶺，鳥雀噪溝叢。坐使驚霜鬢，撩亂已如蓬。"]'),
('yuding-45','酬劉侍郎使君','韋應物','唐','御定全唐诗','yuding','','[]','瓊樹淩霜雪，蔥茜如芳春。英賢雖出守，本自玉階人。',144,'御定全唐詩/json/190.json','["瓊樹淩霜雪，蔥茜如芳春。英賢雖出守，本自玉階人。", "宿昔陪郎署，出入仰清塵。孰雲俱列郡，比德豈為鄰。", "風雨飄海氣，清涼悅心神。重門深夏晝，賦詩延眾賓。", "方以歲月舊，每蒙君子親。繼作郡齋什，遠贈荊山珍。", "高閑庶務理，遊眺景物新。朋友亦遠集，燕酌在佳辰。", "始唱已慚拙，將酬益難伸。濡毫意黽勉，一用寫悁勤。"]'),
('yuding-46','答令狐侍郎','韋應物','唐','御定全唐诗','yuding','','[]','一凶乃一吉，一是複一非。孰能逃斯理，亮在識其微。',120,'御定全唐詩/json/190.json','["一凶乃一吉，一是複一非。孰能逃斯理，亮在識其微。", "三黜故無慍，高賢當庶幾。但以親交戀，音容邈難希。", "況昔別離久，俱忻藩守歸。朝宴方陪廁，山川又乖違。", "吳門冒海霧，峽路淩連磯。同會在京國，相望涕沾衣。", "明時重英才，當複列彤闈。白玉雖塵垢，拂拭還光輝。"]'),
('yuding-47','酬張協律','韋應物','唐','御定全唐诗','yuding','','[]','昔人鬻舂地，今人複一賢。屬余藩守日，方君臥病年。',180,'御定全唐詩/json/190.json','["昔人鬻舂地，今人複一賢。屬余藩守日，方君臥病年。", "麗思阻文宴，芳蹤闕賓筵。經時豈不懷，欲往事屢牽。", "公府適煩倦，開緘瑩新篇。非將握中寶，何以比其妍。", "感茲棲寓詞，想複痾瘵纏。空宇風霜交，幽居情思綿。", "當以貧非病，孰雲白未玄。邑中有其人，憔悴即我愆。", "由來牧守重，英俊得薦延。匪人等鴻毛，斯道何由宣。", "遭時無早晚，蘊器俟良緣。觀文心未衰，勿藥疾當痊。", "晨期簡牘罷，馳慰子忡然。"]'),
('yuding-48','答秦十四校書','韋應物','唐','御定全唐诗','yuding','','[]','知掩山扉三十秋，魚須翠碧棄床頭。',32,'御定全唐詩/json/190.json','["知掩山扉三十秋，魚須翠碧棄床頭。", "莫道謝公方在郡，五言今日為君休。"]'),
('yuding-49','答賓','韋應物','唐','御定全唐诗','yuding','','[]','斜月才鑒帷，凝霜偏冷枕。持情須耿耿，故作單床寢。',24,'御定全唐詩/json/190.json','["斜月才鑒帷，凝霜偏冷枕。持情須耿耿，故作單床寢。"]'),
('yuding-50','答鄭騎曹青橘絕句','韋應物','唐','御定全唐诗','yuding','','[]','憐君臥病思新橘，試摘猶酸亦未黃。',32,'御定全唐詩/json/190.json','["憐君臥病思新橘，試摘猶酸亦未黃。", "書後欲題三百顆，洞庭須待滿林霜。"]'),
('yuding-51','奉和聖制重陽日賜宴','韋應物','唐','御定全唐诗','yuding','','[]','聖心憂萬國，端居在穆清。玄功致海晏，錫宴表文明。',72,'御定全唐詩/json/190.json','["聖心憂萬國，端居在穆清。玄功致海晏，錫宴表文明。", "恩屬重陽節，雨應此時晴。寒菊生池苑，高樹出宮城。", "捧藻千官處，垂戒百王程。複睹開元日，臣愚獻頌聲。"]'),
('yuding-52','和吳舍人早春歸沐西亭言志','韋應物','唐','御定全唐诗','yuding','','[]','曉漏戒中禁，清香肅朝衣。一門雙掌誥，伯侍仲言歸。',96,'御定全唐詩/json/190.json','["曉漏戒中禁，清香肅朝衣。一門雙掌誥，伯侍仲言歸。", "亭高性情曠，職密交遊稀。賦詩樂無事，解帶偃南扉。", "陽春美時澤，旭霽望山暉。幽禽響未轉，東原綠猶微。", "名雖列仙爵，心已遣塵機。即事同岩隱，聖渥良難違。"]'),
('yuding-53','奉和張大夫戲示青山郎','韋應物','唐','御定全唐诗','yuding','','[]','天生逸世姿，竹馬不曾騎。覽卷冰將釋，援毫露欲垂。',48,'御定全唐詩/json/190.json','["天生逸世姿，竹馬不曾騎。覽卷冰將釋，援毫露欲垂。", "金貂傳幾葉，玉樹長新枝。榮祿何妨早，甘羅亦小兒。"]'),
('yuding-54','答河南李士巽題香山寺','韋應物','唐','御定全唐诗','yuding','','[]','洛都遊宦日，少年攜手行。投杯起芳席，總轡振華纓。',192,'御定全唐詩/json/190.json','["洛都遊宦日，少年攜手行。投杯起芳席，總轡振華纓。", "關塞有佳氣，岩開伊水清。攀林憩佛寺，登高望都城。", "蹉跎二十載，世務各所營。茲賞長在夢，故人安得並。", "前歲守九江，恩詔赴咸京。因途再登曆，山河屬晴明。", "寂寞僧侶少，蒼茫林木成。牆宇或崩剝，不見舊題名。", "舊遊況存歿，獨此淚交橫。交橫誰與同，書壁貽友生。", "今茲守吳郡，綿思方未平。子複經陳跡，一感我深情。", "遠蒙惻愴篇，中有金玉聲。反復終難答，金玉尚為輕。"]'),
('yuding-55','答故人見諭','韋應物','唐','御定全唐诗','yuding','','[]','素寡名利心，自非周圓器。徒以歲月資，屢蒙藩條寄。',96,'御定全唐詩/json/190.json','["素寡名利心，自非周圓器。徒以歲月資，屢蒙藩條寄。", "時風重書劄，物情敦貨遺。機杼十縑單，慵疏百函愧。", "常負交親責，且為一官累。況本濩落人，歸無置錐地。", "省己已知非，枉書見深致。雖欲效區區，何由枉其志。"]'),
('yuding-56','酬閻員外陟','韋應物','唐','御定全唐诗','yuding','','[]','寒夜阻良覿，叢竹想幽居。虎符予已誤，金丹子何如。',48,'御定全唐詩/json/190.json','["寒夜阻良覿，叢竹想幽居。虎符予已誤，金丹子何如。", "宴集觀農暇，笙歌聽訟餘。雖蒙一言教，自愧道情疏。"]'),
('yuding-57','酬秦征君、徐少府春日見寄','韋應物','唐','御定全唐诗','yuding','','[]','終日愧無政，與君聊散襟。城根山半腹，亭影水中心。',48,'御定全唐詩/json/190.json','["終日愧無政，與君聊散襟。城根山半腹，亭影水中心。", "朗詠竹窗靜，野情花徑深。那能有餘興，不作剡溪尋。"]'),
('yuding-58','冬夜宿司空曙野居，因寄酬贈','韋應物','唐','御定全唐诗','yuding','','[]','南北與山鄰，蓬庵庇一身。繁霜疑有雪，荒草似無人。',48,'御定全唐詩/json/190.json','["南北與山鄰，蓬庵庇一身。繁霜疑有雪，荒草似無人。", "遂性在耕稼，所交唯賤貧。何掾張椽傲，每重德璋親。"]'),
('yuding-59','長安遇馮著','韋應物','唐','御定全唐诗','yuding','','[]','客從東方來，衣上灞陵雨。問客何為來，采山因買斧。',48,'御定全唐詩/json/190.json','["客從東方來，衣上灞陵雨。問客何為來，采山因買斧。", "冥冥花正開，颺颺燕新乳。昨別今已春，鬢絲生幾縷。"]'),
('yuding-60','將發楚州經寶應縣訪李二忽於州館相遇月夜書事因簡李寶應','韋應物','唐','御定全唐诗','yuding','','[]','孤舟欲夜發，只為訪情人。此地忽相遇，留連意更新。',48,'御定全唐詩/json/190.json','["孤舟欲夜發，只為訪情人。此地忽相遇，留連意更新。", "停杯嗟別久，對月言家貧。一問臨邛令，如何待上賓。"]'),
('yuding-61','廣陵遇孟九雲卿','韋應物','唐','御定全唐诗','yuding','','[]','雄藩本帝都，遊士多俊賢。夾河樹鬱鬱，華館千里連。',96,'御定全唐詩/json/190.json','["雄藩本帝都，遊士多俊賢。夾河樹鬱鬱，華館千里連。", "新知雖滿堂，中意頗未宣。忽逢翰林友，歡樂鬥酒前。", "高文激頹波，四海靡不傳。西施且一笑，眾女安得妍。", "明月滿淮海，哀鴻逝長天。所念京國遠，我來君欲還。"]'),
('yuding-62','淮上遇洛陽李主簿','韋應物','唐','御定全唐诗','yuding','','[]','結茅臨古渡，臥見長淮流。窗裏人將老，門前樹已秋。',48,'御定全唐詩/json/190.json','["結茅臨古渡，臥見長淮流。窗裏人將老，門前樹已秋。", "寒山獨過雁，暮雨遠來舟。日夕逢歸客，那能忘舊遊。"]'),
('yuding-63','路逢崔、元二侍禦避馬見招，以詩見贈','韋應物','唐','御定全唐诗','yuding','','[]','一台稱二妙，歸路望行塵。俱是攀龍客，空為避馬人。',48,'御定全唐詩/json/190.json','["一台稱二妙，歸路望行塵。俱是攀龍客，空為避馬人。", "見招翻局蹐，相問良殷勤。日日吟趨府，彈冠豈有因。"]'),
('yuding-64','逢楊開府','韋應物','唐','御定全唐诗','yuding','','[]','少事武皇帝，無賴恃恩私。身作裏中橫，家藏亡命兒。',144,'御定全唐詩/json/190.json','["少事武皇帝，無賴恃恩私。身作裏中橫，家藏亡命兒。", "朝持樗蒲局，暮竊東鄰姬。司隸不敢捕，立在白玉墀。", "驪山風雪夜，長楊羽獵時。一字都不識，飲酒肆頑癡。", "武皇升仙去，憔悴被人欺。讀書事已晚，把筆學題詩。", "兩府始收跡，南宮謬見推。非才果不容，出守撫煢嫠。", "忽逢楊開府，論舊涕俱垂。坐客何由識，惟有故人知。"]'),
('yuding-65','休暇日訪王侍禦不遇','韋應物','唐','御定全唐诗','yuding','','[]','九日驅馳一日閑，尋君不遇又空還。',32,'御定全唐詩/json/190.json','["九日驅馳一日閑，尋君不遇又空還。", "怪來詩思清人骨，門對寒流雪滿山。"]'),
('yuding-66','因省風俗，訪道士侄不見，題壁','韋應物','唐','御定全唐诗','yuding','','[]','去年澗水今亦流，去年杏花今又拆。',32,'御定全唐詩/json/190.json','["去年澗水今亦流，去年杏花今又拆。", "山人歸來問是誰，還是去年行春客。"]'),
('yuding-0','有所思','韋應物','唐','御定全唐诗','yuding','','[]','借問堤上柳，青青為誰春。空遊昨日地，不見昨日人。',48,'御定全唐詩/json/191.json','["借問堤上柳，青青為誰春。空遊昨日地，不見昨日人。", "繚繞萬家井，往來車馬塵。莫道無相識，要非心所親。"]'),
('yuding-1','暮相思','韋應物','唐','御定全唐诗','yuding','','[]','朝出自不還，暮歸花盡發。豈無終日會，惜此花間月。',36,'御定全唐詩/json/191.json','["朝出自不還，暮歸花盡發。豈無終日會，惜此花間月。", "空館忽相思，微鐘坐來歇。"]'),
('yuding-2','夏夜憶盧嵩','韋應物','唐','御定全唐诗','yuding','','[]','靄靄高館暮，開軒滌煩襟。不知湘雨來，瀟灑在幽林。',72,'御定全唐詩/json/191.json','["靄靄高館暮，開軒滌煩襟。不知湘雨來，瀟灑在幽林。", "炎月得涼夜，芳樽誰與斟。故人南北居，累月間徽音。", "人生無閑日，歡會當在今。反側候天旦，層城苦沉沉。"]'),
('yuding-3','春思','韋應物','唐','御定全唐诗','yuding','','[]','野花如雪繞江城，坐見年芳憶帝京。',32,'御定全唐詩/json/191.json','["野花如雪繞江城，坐見年芳憶帝京。", "閶闔曉開凝碧樹，曾陪鴛鷺聽流鶯。"]'),
('yuding-4','春中憶元二','韋應物','唐','御定全唐诗','yuding','','[]','雨歇萬井春，柔條已含綠。徘徊洛陽陌，惆悵杜陵曲。',48,'御定全唐詩/json/191.json','["雨歇萬井春，柔條已含綠。徘徊洛陽陌，惆悵杜陵曲。", "遊絲正高下，啼鳥還斷續。有酒今不同，思君瑩如玉。"]'),
('yuding-5','懷素友子西','韋應物','唐','御定全唐诗','yuding','','[]','廣陌並遊騎，公堂接華襟。方歡遽見別，永日獨沉吟。',84,'御定全唐詩/json/191.json','["廣陌並遊騎，公堂接華襟。方歡遽見別，永日獨沉吟。", "階暝流暗駛，氣疏露已侵。層城湛深夜，片月生幽林。", "往款良未遂，來覿曠無音。恒當清觴宴，思子玉山岑。", "耿耿何以寫，密言空委心。"]'),
('yuding-6','對韓少尹所贈硯有懷','韋應物','唐','御定全唐诗','yuding','','[]','故人謫遐遠，留硯寵斯文。白水浮香墨，清池滿夏雲。',48,'御定全唐詩/json/191.json','["故人謫遐遠，留硯寵斯文。白水浮香墨，清池滿夏雲。", "念離心已永，感物思徒紛。未有桂陽使，裁書一報君。"]'),
('yuding-7','月晦憶去年與親友曲水游宴','韋應物','唐','御定全唐诗','yuding','','[]','晦賞念前歲，京國結良儔。騎出宣平裏，飲對曲池流。',72,'御定全唐詩/json/191.json','["晦賞念前歲，京國結良儔。騎出宣平裏，飲對曲池流。", "今朝隔天末，空園傷獨遊。雨歇林光變，塘綠鳥聲幽。", "凋氓積逋稅，華鬢集新秋。誰言戀虎符，終當還舊丘。"]'),
('yuding-8','清明日憶諸弟','韋應物','唐','御定全唐诗','yuding','','[]','冷食方多病，開襟一忻然。終令思故郡，煙火滿晴川。',48,'御定全唐詩/json/191.json','["冷食方多病，開襟一忻然。終令思故郡，煙火滿晴川。", "杏粥猶堪食，榆羹已稍煎。唯恨乖親燕，坐度此芳年。"]'),
('yuding-9','池上懷王卿','韋應物','唐','御定全唐诗','yuding','','[]','幽居捐世事，佳雨散園芳。入門靄已綠，水禽鳴春塘。',72,'御定全唐詩/json/191.json','["幽居捐世事，佳雨散園芳。入門靄已綠，水禽鳴春塘。", "重雲始成夕，忽霽尚殘陽。輕舟因風泛，郡閣望蒼蒼。", "私燕阻外好，臨歡一停觴。茲游無時盡，旭日願相將。"]'),
('yuding-10','立夏日憶京師諸弟','韋應物','唐','御定全唐诗','yuding','','[]','改序念芳辰，煩襟倦日永。夏木已成陰，公門晝恒靜。',48,'御定全唐詩/json/191.json','["改序念芳辰，煩襟倦日永。夏木已成陰，公門晝恒靜。", "長風始飄閣，疊雲才吐嶺。坐想離居人，還當惜徂景。"]'),
('yuding-11','曉至園中憶諸弟、崔都水','韋應物','唐','御定全唐诗','yuding','','[]','山郭恒悄悄，林月亦娟娟。景清神已澄，事簡慮絕牽。',48,'御定全唐詩/json/191.json','["山郭恒悄悄，林月亦娟娟。景清神已澄，事簡慮絕牽。", "秋塘遍衰草，曉露洗紅蓮。不見心所愛，茲賞豈為妍。"]'),
('yuding-12','懷琅琊、深標二釋子','韋應物','唐','御定全唐诗','yuding','','[]','白雲埋大壑，陰崖滴夜泉。應居西石室，月照山蒼然。',24,'御定全唐詩/json/191.json','["白雲埋大壑，陰崖滴夜泉。應居西石室，月照山蒼然。"]'),
('yuding-13','雨夜感懷','韋應物','唐','御定全唐诗','yuding','','[]','微雨灑高林，塵埃自蕭散。耿耿心未平，沉沉夜方半。',48,'御定全唐詩/json/191.json','["微雨灑高林，塵埃自蕭散。耿耿心未平，沉沉夜方半。", "獨驚長簟冷，遽覺愁鬢換。誰能當此夕，不有盈襟歎。"]'),
('yuding-14','雲陽館懷谷口','韋應物','唐','御定全唐诗','yuding','','[]','清泚階下流，雲自穀口源。念昔白衣士，結廬在石門。',96,'御定全唐詩/json/191.json','["清泚階下流，雲自穀口源。念昔白衣士，結廬在石門。", "道高杳無累，景靜得忘言。山夕綠陰滿，世移清賞存。", "吏役豈遑暇，幽懷複朝昏。雲泉非所濯，蘿月不可援。", "長往遂真性，暫遊恨卑喧。出身既事世，高躅難等論。"]'),
('yuding-15','憶灃上幽居','韋應物','唐','御定全唐诗','yuding','','[]','一來當複去，猶此厭樊籠。況我林棲子，朝服坐南宮。',36,'御定全唐詩/json/191.json','["一來當複去，猶此厭樊籠。況我林棲子，朝服坐南宮。", "唯獨問啼鳥，還如灃水東。"]'),
('yuding-16','重九登滁城樓憶前歲九日歸灃上赴崔都水及諸弟讌集悽然懷舊','韋應物','唐','御定全唐诗','yuding','','[]','今日重九宴，去歲在京師。聊回出省步，一赴郊園期。',72,'御定全唐詩/json/191.json','["今日重九宴，去歲在京師。聊回出省步，一赴郊園期。", "嘉節始雲邁，周辰已及茲。秋山滿清景，當賞屬乖離。", "凋散民裏闊，摧翳眾木衰。樓中一長嘯，惻愴起涼颸。"]'),
('yuding-17','始夏南園思舊裏','韋應物','唐','御定全唐诗','yuding','','[]','夏首雲物變，雨餘草木繁。池荷初帖水，林花已掃園。',48,'御定全唐詩/json/191.json','["夏首雲物變，雨餘草木繁。池荷初帖水，林花已掃園。", "縈叢蝶尚亂，依閣鳥猶喧。對此殘芳月，憶在漢陵原。"]'),
('yuding-18','登蒲塘驛沿路見泉穀村墅忽想京師舊居追懷昔年','韋應物','唐','御定全唐诗','yuding','','[]','青山導騎繞，春風行旆舒。均徭視屬城，問疾躬裏閭。',96,'御定全唐詩/json/191.json','["青山導騎繞，春風行旆舒。均徭視屬城，問疾躬裏閭。", "煙水依泉谷，川陸散樵漁。忽念故園日，複憶驪山居。", "荏苒斑鬢及，夢寢婚宦初。不覺平生事，咄嗟二紀餘。", "存歿闊已永，悲多歡自疏。高秩非為美，闌幹淚盈裾。"]'),
('yuding-19','經函谷關','韋應物','唐','御定全唐诗','yuding','','[]','洪河絕山根，單軌出其側。萬古為要樞，往來何時息。',132,'御定全唐詩/json/191.json','["洪河絕山根，單軌出其側。萬古為要樞，往來何時息。", "秦皇既恃險，海內被吞食。及嗣同覆顛，咽喉莫能塞。", "炎靈詎西駕，婁子非經國。徒欲扼諸侯，不知恢至德。", "聖朝及天寶，豺虎起東北。下沉戰死魂，上結窮冤色。", "古今雖共守，成敗良可識。藩屏無俊賢，金湯獨何力。", "馳車一登眺，感慨中自惻。"]'),
('yuding-20','經武功舊宅','韋應物','唐','御定全唐诗','yuding','','[]','茲邑昔所遊，嘉會常在目。曆載俄二九，始往今來複。',84,'御定全唐詩/json/191.json','["茲邑昔所遊，嘉會常在目。曆載俄二九，始往今來複。", "戚戚居人少，茫茫野田綠。風雨經舊墟，毀垣迷往躅。", "門臨川流駛，樹有羈雌宿。多累恒悲往，長年覺時速。", "欲去中複留，徘徊結心曲。"]'),
('yuding-21','往雲門郊居途經回流作','韋應物','唐','御定全唐诗','yuding','','[]','茲晨乃休暇，適往田家廬。原穀徑途澀，春陽草木敷。',72,'御定全唐詩/json/191.json','["茲晨乃休暇，適往田家廬。原穀徑途澀，春陽草木敷。", "才遵板橋曲，複此清澗紆。崩壑方見射，回流忽已舒。", "明滅泛孤景，杳靄含夕虛。無將為邑志，一酌澄波餘。"]'),
('yuding-22','乘月過西郊渡','韋應物','唐','御定全唐诗','yuding','','[]','遠山含紫氛，春野靄雲暮。值此歸時月，留連西澗渡。',84,'御定全唐詩/json/191.json','["遠山含紫氛，春野靄雲暮。值此歸時月，留連西澗渡。", "謬當文墨會，得與群英遇。賞逐亂流翻，心將清景悟。", "行車儼未轉，芳草空盈步。已舉候亭火，猶愛村原樹。", "還當守故扃，悵恨秉幽素。"]'),
('yuding-23','晚歸灃川','韋應物','唐','御定全唐诗','yuding','','[]','淩霧朝閶闔，落日返清川。簪組方暫解，臨水一翛然。',96,'御定全唐詩/json/191.json','["淩霧朝閶闔，落日返清川。簪組方暫解，臨水一翛然。", "昆弟忻來集，童稚滿眼前。適意在無事，攜手望秋田。", "南嶺橫爽氣，高林繞遙阡。野廬不鋤理，翳翳起荒煙。", "名秩斯逾分，廉退愧不全。已想平門路，晨騎複言旋。"]'),
('yuding-24','授衣還田裏','韋應物','唐','御定全唐诗','yuding','','[]','公門懸甲令，浣濯遂其私。晨起懷愴恨，野田寒露時。',72,'御定全唐詩/json/191.json','["公門懸甲令，浣濯遂其私。晨起懷愴恨，野田寒露時。", "氣收天地廣，風淒草木衰。山明始重疊，川淺更逶迤。", "煙火生閭裏，禾黍積東菑。終然可樂業，時節一來斯。"]'),
('yuding-25','夕次盱眙縣','韋應物','唐','御定全唐诗','yuding','','[]','落帆逗淮鎮，停舫臨孤驛。浩浩風起波，冥冥日沉夕。',48,'御定全唐詩/json/191.json','["落帆逗淮鎮，停舫臨孤驛。浩浩風起波，冥冥日沉夕。", "人歸山郭暗，雁下蘆洲白。獨夜憶秦關，聽鐘未眠客。"]'),
('yuding-26','春月觀省屬城，始憩東西林精舍','韋應物','唐','御定全唐诗','yuding','','[]','因時省風俗，布惠迨高年。建隼出潯陽，整駕遊山川。',168,'御定全唐詩/json/191.json','["因時省風俗，布惠迨高年。建隼出潯陽，整駕遊山川。", "白雲斂晴壑，群峰列遙天。嶔崎石門狀，杳靄香爐煙。", "榛荒屢罥掛，逼側殆覆顛。方臻釋氏廬，時物屢華妍。", "曇遠昔經始，於茲閟幽玄。東西竹林寺，灌注寒澗泉。", "人事既雲泯，歲月複已綿。殿宇餘丹紺，磴閣峭欹懸。", "佳士亦棲息，善身絕塵緣。今我蒙朝寄，教化敷裏鄽。", "道妙苟為得，出處理無偏。心當同所尚，跡豈辭纏牽。"]'),
('yuding-27','自蒲塘驛回駕經歷山水','韋應物','唐','御定全唐诗','yuding','','[]','館宿風雨滯，始晴行蓋轉。潯陽山水多，草木俱紛衍。',96,'御定全唐詩/json/191.json','["館宿風雨滯，始晴行蓋轉。潯陽山水多，草木俱紛衍。", "崎嶇緣碧澗，蒼翠踐苔蘚。高樹夾潺湲，崩石橫陰巘。", "野杏依寒拆，餘雲冒嵐淺。性愜形豈勞，境殊路遺緬。", "憶昔終南下，佳游亦屢展。時禽下流暮，紛思何由遣。"]'),
('yuding-28','山行積雨，歸途始霽','韋應物','唐','御定全唐诗','yuding','','[]','攬轡窮登降，陰雨遘二旬。但見白雲合，不睹岩中春。',84,'御定全唐詩/json/191.json','["攬轡窮登降，陰雨遘二旬。但見白雲合，不睹岩中春。", "急澗豈易揭，峻途良難遵。深林猿聲冷，沮洳虎跡新。", "始霽升陽景，山水閱清晨。雜花積如霧，百卉萋已陳。", "鳴騶屢驤首，歸路自忻忻。"]'),
('yuding-29','傷逝','韋應物','唐','御定全唐诗','yuding','','[]','染白一為黑，焚木盡成灰。念我室中人，逝去亦不回。',144,'御定全唐詩/json/191.json','["染白一為黑，焚木盡成灰。念我室中人，逝去亦不回。", "結髮二十載，賓敬如始來。提攜屬時屯，契闊憂患災。", "柔素亮為表，禮章夙所該。仕公不及私，百事委令才。", "一旦入閨門，四屋滿塵埃。斯人既已矣，觸物但傷摧。", "單居移時節，泣涕撫嬰孩。知妄謂當遣，臨感要難裁。", "夢想忽如睹，驚起複徘徊。此心良無已，繞屋生蒿萊。"]'),
('yuding-30','往富平傷懷','韋應物','唐','御定全唐诗','yuding','','[]','晨起淩嚴霜，慟哭臨素帷。駕言百里途，惻愴複何為。',120,'御定全唐詩/json/191.json','["晨起淩嚴霜，慟哭臨素帷。駕言百里途，惻愴複何為。", "昨者仕公府，屬城常載馳。出門無所憂，返室亦熙熙。", "今者掩筠扉，但聞童稚悲。丈夫須出入，顧爾內無依。", "銜恨已酸骨，何況苦寒時。單車路蕭條，回首長逶遲。", "飄風忽截野，嘹唳雁起飛。昔時同往路，獨往今詎知。"]'),
('yuding-31','出還','韋應物','唐','御定全唐诗','yuding','','[]','昔出喜還家，今還獨傷意。入室掩無光，銜哀寫虛位。',72,'御定全唐詩/json/191.json','["昔出喜還家，今還獨傷意。入室掩無光，銜哀寫虛位。", "淒淒動幽幔，寂寂驚寒吹。幼女複何知，時來庭下戲。", "咨嗟日複老，錯莫身如寄。家人勸我餐，對案空垂淚。"]'),
('yuding-32','冬夜','韋應物','唐','御定全唐诗','yuding','','[]','杳杳日雲夕，鬱結誰為開。單衾自不暖，霜霰已皚皚。',96,'御定全唐詩/json/191.json','["杳杳日雲夕，鬱結誰為開。單衾自不暖，霜霰已皚皚。", "晚歲淪夙志，驚鴻感深哀。深哀當何為，桃李忽凋摧。", "幃帳徒自設，冥寞豈複來。平生雖恩重，遷去托窮埃。", "抱此女曹恨，顧非高世才。振衣中夜起，河漢尚裴回。"]'),
('yuding-33','送終','韋應物','唐','御定全唐诗','yuding','','[]','奄忽逾時節，日月獲其良。蕭蕭車馬悲，祖載發中堂。',144,'御定全唐詩/json/191.json','["奄忽逾時節，日月獲其良。蕭蕭車馬悲，祖載發中堂。", "生平同此居，一旦異存亡。斯須亦何益，終複委山岡。", "行出國南門，南望鬱蒼蒼。日入乃雲造，慟哭宿風霜。", "晨遷俯玄廬，臨訣但遑遑。方當永潛翳，仰視白日光。", "俯仰遽終畢，封樹已荒涼。獨留不得還，欲去結中腸。", "童稚知所失，啼號捉我裳。即事猶倉卒，歲月始難忘。"]'),
('yuding-34','除日','韋應物','唐','御定全唐诗','yuding','','[]','思懷耿如昨，季月已雲暮。忽驚年複新，獨恨人成故。',48,'御定全唐詩/json/191.json','["思懷耿如昨，季月已雲暮。忽驚年複新，獨恨人成故。", "冰池始泮綠，梅援還飄素。淑景方轉延，朝朝自難度。"]'),
('yuding-35','對芳樹','韋應物','唐','御定全唐诗','yuding','','[]','迢迢芳園樹，列映清池曲。對此傷人心，還如故時綠。',48,'御定全唐詩/json/191.json','["迢迢芳園樹，列映清池曲。對此傷人心，還如故時綠。", "風條灑餘靄，露葉承新旭。佳人不再攀，下有往來躅。"]'),
('yuding-36','月夜','韋應物','唐','御定全唐诗','yuding','','[]','皓月流春城，華露積芳草。坐念綺窗空，翻傷清景好。',36,'御定全唐詩/json/191.json','["皓月流春城，華露積芳草。坐念綺窗空，翻傷清景好。", "清景終若斯，傷多人自老。"]'),
('yuding-37','歎楊花','韋應物','唐','御定全唐诗','yuding','','[]','空蒙不自定，況值暄風度。舊賞逐流年，新愁忽盈素。',48,'御定全唐詩/json/191.json','["空蒙不自定，況值暄風度。舊賞逐流年，新愁忽盈素。", "才縈下苑曲，稍滿東城路。人意有悲歡，時芳獨如故。"]'),
('yuding-38','過昭國裏故第','韋應物','唐','御定全唐诗','yuding','','[]','不復見故人，一來過故宅。物變知景暄，心傷覺時寂。',144,'御定全唐詩/json/191.json','["不復見故人，一來過故宅。物變知景暄，心傷覺時寂。", "池荒野筠合，庭綠幽草積。風散花意謝，鳥還山光夕。", "宿昔方同賞，詎知今念昔。緘室在東廂，遺器不忍覿。", "柔翰全分意，芳巾尚染澤。殘工委筐篋，餘素經刀尺。", "收此還我家，將還複愁惕。永絕攜手歡，空存舊行跡。", "冥冥獨無語，杳杳將何適。唯思今古同，時緩傷與戚。"]'),
('yuding-39','夏日','韋應物','唐','御定全唐诗','yuding','','[]','已謂心苦傷，如何日方永。無人不晝寢，獨坐山中靜。',48,'御定全唐詩/json/191.json','["已謂心苦傷，如何日方永。無人不晝寢，獨坐山中靜。", "悟澹將遣慮，學空庶遺境。積俗易為侵，愁來複難整。"]'),
('yuding-40','端居感懷','韋應物','唐','御定全唐诗','yuding','','[]','沉沉積素抱，婉婉屬之子。永日獨無言，忽驚振衣起。',108,'御定全唐詩/json/191.json','["沉沉積素抱，婉婉屬之子。永日獨無言，忽驚振衣起。", "方如在幃室，複悟永終已。稚子傷恩絕，盛時若流水。", "暄涼同寡趣，朗晦俱無理。寂性常喻人，滯情今在己。", "空房欲雲暮，巢燕亦來止。夏木遽成陰，綠苔誰複履。", "感至竟何方，幽獨長如此。"]'),
('yuding-41','悲紈扇','韋應物','唐','御定全唐诗','yuding','','[]','非關秋節至，詎是恩情改。掩嚬人已無，委篋涼空在。',36,'御定全唐詩/json/191.json','["非關秋節至，詎是恩情改。掩嚬人已無，委篋涼空在。", "何言永不發，暗使銷光彩。"]'),
('yuding-42','閑齋對雨','韋應物','唐','御定全唐诗','yuding','','[]','幽獨自盈抱，陰淡亦連朝。空齋對高樹，疏雨共蕭條。',48,'御定全唐詩/json/191.json','["幽獨自盈抱，陰淡亦連朝。空齋對高樹，疏雨共蕭條。", "巢燕翻泥濕，蕙花依砌消。端居念往事，倏忽苦驚飆。"]'),
('yuding-43','林園晚霽','韋應物','唐','御定全唐诗','yuding','','[]','雨歇見青山，落日照林園。山多煙鳥亂，林清風景翻。',60,'御定全唐詩/json/191.json','["雨歇見青山，落日照林園。山多煙鳥亂，林清風景翻。", "提攜唯子弟，蕭散在琴言。同遊不同意，耿耿獨傷魂。", "寂寞鐘已盡，如何還入門。"]'),
('yuding-44','秋夜二首','韋應物','唐','御定全唐诗','yuding','','[]','庭樹轉蕭蕭，陰蟲還戚戚。獨向高齋眠，夜聞寒雨滴。',96,'御定全唐詩/json/191.json','["庭樹轉蕭蕭，陰蟲還戚戚。獨向高齋眠，夜聞寒雨滴。", "微風時動牖，殘燈尚留壁。惆悵平生懷，偏來委今夕。", "霜露已淒淒，星漢複昭回。朔風中夜起，驚鴻千里來。", "蕭條涼葉下，寂寞清砧哀。歲晏仰空宇，心事若寒灰。"]'),
('yuding-45','感夢','韋應物','唐','御定全唐诗','yuding','','[]','歲月轉蕪漫，形影長寂寥。仿佛覯微夢，感歎起中宵。',48,'御定全唐詩/json/191.json','["歲月轉蕪漫，形影長寂寥。仿佛覯微夢，感歎起中宵。", "綿思靄流月，驚魂颯回飆。誰念茲夕永，坐令顏鬢凋。"]'),
('yuding-46','同德精舍舊居傷懷','韋應物','唐','御定全唐诗','yuding','','[]','洛京十載別，東林訪舊扉。山河不可望，存沒意多違。',48,'御定全唐詩/json/191.json','["洛京十載別，東林訪舊扉。山河不可望，存沒意多違。", "時遷跡尚在，同去獨來歸。還見窗中鴿，日暮繞庭飛。"]'),
('yuding-47','悲故交','韋應物','唐','御定全唐诗','yuding','','[]','白璧眾求瑕，素絲易成汙。萬里顛沛還，高堂已長暮。',72,'御定全唐詩/json/191.json','["白璧眾求瑕，素絲易成汙。萬里顛沛還，高堂已長暮。", "積憤方盈抱，纏哀忽逾度。念子從此終，黃泉竟誰訴。", "一為時事感，豈獨平生故。唯見荒丘原，野草塗朝露。"]'),
('yuding-48','張彭州前與緱氏馮少府各惠寄一篇多故未答張已云沒因追哀敘事兼遠簡馮生','韋應物','唐','御定全唐诗','yuding','','[]','君昔掌文翰，西垣複石渠。朱衣乘白馬，輝光照裏閭。',144,'御定全唐詩/json/191.json','["君昔掌文翰，西垣複石渠。朱衣乘白馬，輝光照裏閭。", "余時忝南省，接宴愧空虛。一別守茲郡，蹉跎歲再除。", "長懷關河表，永日簡牘餘。郡中有方塘，涼閣對紅蕖。", "金玉蒙遠貺，篇詠見吹噓。未答平生意，已沒九原居。", "秋風吹寢門，長慟涕漣如。覆視緘中字，奄為昔人書。", "髮鬢已雲白，交友日凋疏。馮生遠同恨，憔悴在田廬。"]'),
('yuding-49','東林精舍見故殿中鄭侍御題詩追舊書情涕泗橫集因寄呈閻澧州馮少府','韋應物','唐','御定全唐诗','yuding','','[]','仲月景氣佳，東林一登曆。中有故人詩，淒涼在高壁。',144,'御定全唐詩/json/191.json','["仲月景氣佳，東林一登曆。中有故人詩，淒涼在高壁。", "精思長懸世，音容已歸寂。墨澤傳灑餘，磨滅親翰跡。", "平生忽如夢，百事皆成昔。結騎京華年，揮文篋笥積。", "朝廷重英彥，時輩分圭璧。永謝柏梁陪，獨闕金門籍。", "方嬰存歿感，豈暇林泉適。雨餘山景寒，風散花光夕。", "新知雖滿堂，故情誰能覿。唯當同時友，緘寄空淒戚。"]'),
('yuding-50','同李二過亡友鄭子故第','韋應物','唐','御定全唐诗','yuding','','[]','客車名未滅，沒世恨應長。斜月知何照，幽林判自芳。',48,'御定全唐詩/json/191.json','["客車名未滅，沒世恨應長。斜月知何照，幽林判自芳。", "故人驚逝水，寒雀噪空牆。不是平生舊，遺蹤要可傷。"]'),
('yuding-51','話舊','韋應物','唐','御定全唐诗','yuding','','[]','存亡三十載，事過悉成空。不惜沾衣淚，並話一宵中。',24,'御定全唐詩/json/191.json','["存亡三十載，事過悉成空。不惜沾衣淚，並話一宵中。"]'),
('yuding-52','至開化裏壽春公故宅','韋應物','唐','御定全唐诗','yuding','','[]','甯知府中吏，故宅一徘徊。曆階存往敬，瞻位泣餘哀。',48,'御定全唐詩/json/191.json','["甯知府中吏，故宅一徘徊。曆階存往敬，瞻位泣餘哀。", "廢井沒荒草，陰牖生綠苔。門前車馬散，非複昔時來。"]'),
('yuding-53','睢陽感懷','韋應物','唐','御定全唐诗','yuding','','[]','豺虎犯天綱，升平無內備。長驅陰山卒，略踐三河地。',144,'御定全唐詩/json/191.json','["豺虎犯天綱，升平無內備。長驅陰山卒，略踐三河地。", "張侯本忠烈，濟世有深智。堅壁梁宋間，遠籌吳楚利。", "窮年方絕輸，鄰援皆攜貳。使者哭其庭，救兵終不至。", "重圍雖可越，藩翰諒難棄。饑喉待危巢，懸命中路墜。", "甘從鋒刃斃，莫奪堅貞志。宿將降賊庭，儒生獨全義。", "空城唯白骨，同往無賤貴。哀哉豈獨今，千載當歔欷。"]'),
('yuding-54','廣德中洛陽作','韋應物','唐','御定全唐诗','yuding','','[]','生長太平日，不知太平歡。今還洛陽中，感此方苦酸。',96,'御定全唐詩/json/191.json','["生長太平日，不知太平歡。今還洛陽中，感此方苦酸。", "飲藥本攻病，毒腸翻自殘。王師涉河洛，玉石俱不完。", "時節屢遷斥，山河長鬱盤。蕭條孤煙絕，日入空城寒。", "蹇劣乏高步，緝遺守微官。西懷咸陽道，躑躅心不安。"]'),
('yuding-55','閶門懷古','韋應物','唐','御定全唐诗','yuding','','[]','獨鳥下高樹，遙知吳苑園。淒涼千古事，日暮倚閶門。',24,'御定全唐詩/json/191.json','["獨鳥下高樹，遙知吳苑園。淒涼千古事，日暮倚閶門。"]'),
('yuding-56','感事','韋應物','唐','御定全唐诗','yuding','','[]','霜雪皎素絲，何意墜墨池。青蒼猶可濯，黑色不可移。',48,'御定全唐詩/json/191.json','["霜雪皎素絲，何意墜墨池。青蒼猶可濯，黑色不可移。", "女工再三歎，委棄當此時。歲寒雖無褐，機杼誰肯施。"]'),
('yuding-57','感鏡','韋應物','唐','御定全唐诗','yuding','','[]','鑄鏡廣陵市，菱花匣中發。夙昔嘗許人，鏡成人已沒。',60,'御定全唐詩/json/191.json','["鑄鏡廣陵市，菱花匣中發。夙昔嘗許人，鏡成人已沒。", "如冰結圓器，類璧無絲發。形影終不臨，清光殊不歇。", "一感平生言，松枝樹秋月。"]'),
('yuding-58','歎白髮','韋應物','唐','御定全唐诗','yuding','','[]','還同一葉落，對此孤鏡曉。絲縷乍難分，楊花複相繞。',36,'御定全唐詩/json/191.json','["還同一葉落，對此孤鏡曉。絲縷乍難分，楊花複相繞。", "時役人易衰，吾年白猶少。"]'),
('yuding-0','登高望洛城作','韋應物','唐','御定全唐诗','yuding','','[]','高臺造雲端，遐瞰週四垠。雄都定鼎地，勢據萬國尊。',192,'御定全唐詩/json/192.json','["高臺造雲端，遐瞰週四垠。雄都定鼎地，勢據萬國尊。", "河岳出雲雨，土圭酌乾坤。舟通南越貢，城背北邙原。", "帝宅夾清洛，丹霞捧朝暾。蔥蘢瑤台榭，窈窕雙闕門。", "十載構屯難，兵戈若雲屯。膏腴滿榛蕪，比屋空毀垣。", "聖主乃東眷，俾賢拯元元。熙熙居守化，泛泛太府恩。", "至損當受益，苦寒必生溫。平明四城開，稍見市井喧。", "坐感理亂跡，永懷經濟言。吾生自不達，空鳥何翩翻。", "天高水流遠，日晏城郭昏。裴回訖旦夕，聊用寫憂煩。"]'),
('yuding-1','同德寺閣集眺','韋應物','唐','御定全唐诗','yuding','','[]','芳節欲雲晏，游遨樂相從。高閣照丹霞，飀飀含遠風。',120,'御定全唐詩/json/192.json','["芳節欲雲晏，游遨樂相從。高閣照丹霞，飀飀含遠風。", "寂寥氛氳廓，超忽神慮空。旭日霽皇州，岧嶢見兩宮。", "嵩少多秀色，群山莫與崇。三川浩東注，瀍澗亦來同。", "陰陽降大和，宇宙得其中。舟車滿川陸，四國靡不通。", "舊堵今既葺，庶氓亦已豐。周覽思自奮，行當遇時邕。"]'),
('yuding-2','登寶意寺上方舊遊','韋應物','唐','御定全唐诗','yuding','','[]','翠嶺香台出半天，萬家煙樹滿晴川。',32,'御定全唐詩/json/192.json','["翠嶺香台出半天，萬家煙樹滿晴川。", "諸僧近住不相識，坐聽微鐘記往年。"]'),
('yuding-3','登樂遊廟作','韋應物','唐','御定全唐诗','yuding','','[]','高原出東城，鬱鬱見咸陽。上有千載事，乃自漢宣皇。',108,'御定全唐詩/json/192.json','["高原出東城，鬱鬱見咸陽。上有千載事，乃自漢宣皇。", "頹壖久淩遲，陳跡翳丘荒。春草雖複綠，驚風但飄揚。", "周覽京城內，雙闕起中央。微鐘何處來，暮色忽蒼蒼。", "歌吹喧萬井，車馬塞康莊。昔人豈不爾，百世同一傷。", "歸當守沖漠，跡寓心自忘。"]'),
('yuding-4','登西南岡卜居遇雨尋竹浪至灃壖縈帶數里清流茂樹雲物可賞','韋應物','唐','御定全唐诗','yuding','','[]','登高創危構，林表見川流。微雨颯已至，蕭條川氣秋。',84,'御定全唐詩/json/192.json','["登高創危構，林表見川流。微雨颯已至，蕭條川氣秋。", "下尋密竹盡，忽曠沙際遊。紆曲水分野，綿延稼盈疇。", "寒花明廢墟，樵牧笑榛丘。雲水成陰澹，竹樹更清幽。", "適自戀佳賞，複茲永日留。"]'),
('yuding-5','灃上與幼遐月夜登西岡玩花','韋應物','唐','御定全唐诗','yuding','','[]','置酒臨高隅，佳人自城闕。已玩滿川花，還看滿川月。',36,'御定全唐詩/json/192.json','["置酒臨高隅，佳人自城闕。已玩滿川花，還看滿川月。", "花月方浩然，賞心何由歇。"]'),
('yuding-6','臺上遲客','韋應物','唐','御定全唐诗','yuding','','[]','高臺一悄望，遠樹間朝暉。但見東西騎，坐令心賞違。',48,'御定全唐詩/json/192.json','["高臺一悄望，遠樹間朝暉。但見東西騎，坐令心賞違。", "始霽郊原綠，暮春啼鳥稀。徒然對芳物，何能獨醉歸。"]'),
('yuding-7','登樓','韋應物','唐','御定全唐诗','yuding','','[]','茲樓日登眺，流歲暗蹉跎。坐厭淮南守，秋山紅樹多。',24,'御定全唐詩/json/192.json','["茲樓日登眺，流歲暗蹉跎。坐厭淮南守，秋山紅樹多。"]'),
('yuding-8','善福寺閣','韋應物','唐','御定全唐诗','yuding','','[]','殘霞照高閣，青山出遠林。晴明一登望，瀟灑此幽襟。',24,'御定全唐詩/json/192.json','["殘霞照高閣，青山出遠林。晴明一登望，瀟灑此幽襟。"]'),
('yuding-9','樓中月夜','韋應物','唐','御定全唐诗','yuding','','[]','端令倚懸檻，長望抱沉憂。寧知故園月，今夕在茲樓。',48,'御定全唐詩/json/192.json','["端令倚懸檻，長望抱沉憂。寧知故園月，今夕在茲樓。", "衰蓮送餘馥，華露湛新秋。坐見蒼林變，清輝愴已休。"]'),
('yuding-10','寒食後北樓作','韋應物','唐','御定全唐诗','yuding','','[]','園林過新節，風花亂高閣。遙聞擊鼓聲，蹴鞠軍中樂。',24,'御定全唐詩/json/192.json','["園林過新節，風花亂高閣。遙聞擊鼓聲，蹴鞠軍中樂。"]'),
('yuding-11','西樓','韋應物','唐','御定全唐诗','yuding','','[]','高閣一長望，故園何日歸。煙塵擁函穀，秋雁過來稀。',24,'御定全唐詩/json/192.json','["高閣一長望，故園何日歸。煙塵擁函穀，秋雁過來稀。"]'),
('yuding-12','夜望','韋應物','唐','御定全唐诗','yuding','','[]','南樓夜已寂，暗鳥動林間。不見城郭事，沉沉唯四山。',24,'御定全唐詩/json/192.json','["南樓夜已寂，暗鳥動林間。不見城郭事，沉沉唯四山。"]'),
('yuding-13','晚登郡閣','韋應物','唐','御定全唐诗','yuding','','[]','悵然高閣望，已掩東城關。春風偏送柳，夜景欲沉山。',24,'御定全唐詩/json/192.json','["悵然高閣望，已掩東城關。春風偏送柳，夜景欲沉山。"]'),
('yuding-14','登重玄寺閣','韋應物','唐','御定全唐诗','yuding','','[]','時暇陟雲構，晨霽澄景光。始見吳都大，十裏鬱蒼蒼。',96,'御定全唐詩/json/192.json','["時暇陟雲構，晨霽澄景光。始見吳都大，十裏鬱蒼蒼。", "山川表明麗，湖海吞大荒。合遝臻水陸，駢闐會四方。", "俗繁節又暄，雨順物亦康。禽魚各翔泳，草木遍芬芳。", "於茲省氓俗，一用勸農桑。誠知虎符忝，但恨歸路長。"]'),
('yuding-15','觀早朝','韋應物','唐','御定全唐诗','yuding','','[]','伐鼓通嚴城，車馬溢廣躔。煌煌列明燭，朝服照華鮮。',120,'御定全唐詩/json/192.json','["伐鼓通嚴城，車馬溢廣躔。煌煌列明燭，朝服照華鮮。", "金門杳深沉，尚聽清漏傳。河漢忽已沒，司閽啟晨關。", "丹殿據龍首，崔嵬對南山。寒生千門裏，日照雙闕間。", "禁旅下成列，爐香起中天。輝輝睹明聖，濟濟行俊賢。", "愧無鴛鷺姿，短翮空飛還。誰當假毛羽，雲路相追攀。"]'),
('yuding-16','陪元侍禦春遊','韋應物','唐','御定全唐诗','yuding','','[]','何處醉春風，長安西複東。不因俱罷職，豈得此時同。',48,'御定全唐詩/json/192.json','["何處醉春風，長安西複東。不因俱罷職，豈得此時同。", "貰酒宣平裏，尋芳下苑中。往來楊柳陌，猶避昔年驄。"]'),
('yuding-17','游龍門香山泉','韋應物','唐','御定全唐诗','yuding','','[]','山水本自佳，遊人已忘慮。碧泉更幽絕，賞愛未能去。',84,'御定全唐詩/json/192.json','["山水本自佳，遊人已忘慮。碧泉更幽絕，賞愛未能去。", "潺湲寫幽磴，繚繞帶嘉樹。激轉忽殊流，歸泓又同注。", "羽觴自成玩，永日亦延趣。靈草有時香，仙源不知處。", "還當候圓月，攜手重遊寓。"]'),
('yuding-18','龍門游眺','韋應物','唐','御定全唐诗','yuding','','[]','鑿山導伊流，中斷若天辟。都門遙相望，佳氣生朝夕。',96,'御定全唐詩/json/192.json','["鑿山導伊流，中斷若天辟。都門遙相望，佳氣生朝夕。", "素懷出塵意，適有攜手客。精舍繞層阿，千龕鄰峭壁。", "緣雲路猶緬，憩澗鐘已寂。花樹發煙華，淙流散石脈。", "長嘯招遠風，臨潭漱金碧。日落望都城，人間何役役。"]'),
('yuding-19','洛都游寓','韋應物','唐','御定全唐诗','yuding','','[]','東風日已和，元化亮無私。草木同時植，生條有高卑。',96,'御定全唐詩/json/192.json','["東風日已和，元化亮無私。草木同時植，生條有高卑。", "罷官守園廬，豈不懷渴饑。窮通非所幹，局促當何為。", "佳辰幸可遊，親友亦相追。朝從華林宴，暮返東城期。", "掇英出蘭皋，玩月步川坻。軒冕誠可慕，所憂在縶維。"]'),
('yuding-20','再游龍門懷舊侶','韋應物','唐','御定全唐诗','yuding','','[]','兩山鬱相對，晨策方上幹。靄靄眺都城，悠悠俯清瀾。',72,'御定全唐詩/json/192.json','["兩山鬱相對，晨策方上幹。靄靄眺都城，悠悠俯清瀾。", "邈矣二三子，茲焉屢遊盤。良時忽已周，獨往念前歡。", "好鳥始雲至，眾芳亦未闌。遇物豈殊昔，慨傷自有端。"]'),
('yuding-21','莊嚴精舍游集','韋應物','唐','御定全唐诗','yuding','','[]','良游因時暇，乃在西南隅。綠煙凝層城，豐草滿通衢。',96,'御定全唐詩/json/192.json','["良游因時暇，乃在西南隅。綠煙凝層城，豐草滿通衢。", "精舍何崇曠，煩局一弘舒。架虹施廣蔭，構雲眺八區。", "即此塵境遠，忽聞幽鳥殊。新林泛景光，叢綠含露濡。", "永日亮難遂，平生少歡娛。誰能遽還歸，幸與高士俱。"]'),
('yuding-22','府舍月游','韋應物','唐','御定全唐诗','yuding','','[]','官舍耿深夜，佳月喜同遊。橫河俱半落，泛露忽驚秋。',48,'御定全唐詩/json/192.json','["官舍耿深夜，佳月喜同遊。橫河俱半落，泛露忽驚秋。", "散彩疏群樹，分規澄素流。心期與浩景，蒼蒼殊未收。"]'),
('yuding-23','任鄠令渼陂游眺','韋應物','唐','御定全唐诗','yuding','','[]','野水灩長塘，煙花亂晴日。氤氳綠樹多，蒼翠千山出。',48,'御定全唐詩/json/192.json','["野水灩長塘，煙花亂晴日。氤氳綠樹多，蒼翠千山出。", "游魚時可見，新荷尚未密。屢往心獨閑，恨無理人術。"]'),
('yuding-24','西郊遊矚','韋應物','唐','御定全唐诗','yuding','','[]','東風散餘冱，陂水淡已綠。煙芳何處尋，杳藹春山曲。',48,'御定全唐詩/json/192.json','["東風散餘冱，陂水淡已綠。煙芳何處尋，杳藹春山曲。", "新禽哢暄節，晴光泛嘉木。一與諸君游，華觴忻見屬。"]'),
('yuding-25','再遊西郊渡','韋應物','唐','御定全唐诗','yuding','','[]','水曲一追游，遊人重懷戀。嬋娟昨夜月，還向波中見。',48,'御定全唐詩/json/192.json','["水曲一追游，遊人重懷戀。嬋娟昨夜月，還向波中見。", "驚禽棲不定，流芳寒未遍。攜手更何時，佇看花似霰。"]'),
('yuding-26','月溪與幼遐、君貺同游','韋應物','唐','御定全唐诗','yuding','','[]','岸筱覆回溪，回溪曲如月。沉沉水容綠，寂寂流鶯歇。',60,'御定全唐詩/json/192.json','["岸筱覆回溪，回溪曲如月。沉沉水容綠，寂寂流鶯歇。", "淺石方淩亂，游禽時出沒。半雨夕陽霏，緣源雜花發。", "明晨重來此，同心應已闕。"]'),
('yuding-27','與幼遐、君貺兄弟同游白家竹潭','韋應物','唐','御定全唐诗','yuding','','[]','清賞非素期，偶游方自得。前登絕嶺險，下視深潭黑。',72,'御定全唐詩/json/192.json','["清賞非素期，偶游方自得。前登絕嶺險，下視深潭黑。", "密竹已成暮，歸雲殊未極。春鳥依穀暄，紫蘭含幽色。", "已將芳景遇，複款平生憶。終念一歡別，臨風還默默。"]'),
('yuding-28','秋夕西齋與僧神靜游','韋應物','唐','御定全唐诗','yuding','','[]','晨登西齋望，不覺至夕曛。正當秋夏交，原野起煙氛。',84,'御定全唐詩/json/192.json','["晨登西齋望，不覺至夕曛。正當秋夏交，原野起煙氛。", "坐聽涼飆舉，華月稍披雲。漠漠山猶隱，灩灩川始分。", "物幽夜更殊，境靜興彌臻。息機非傲世，于時乏嘉聞。", "究空自為理，況與釋子群。"]'),
('yuding-29','觀田家','韋應物','唐','御定全唐诗','yuding','','[]','微雨眾卉新，一雷驚蟄始。田家幾日閑，耕種從此起。',84,'御定全唐詩/json/192.json','["微雨眾卉新，一雷驚蟄始。田家幾日閑，耕種從此起。", "丁壯俱在野，場圃亦就理。歸來景常晏，飲犢西澗水。", "饑劬不自苦，膏澤且為喜。倉廩無宿儲，徭役猶未已。", "方慚不耕者，祿食出閭裏。"]'),
('yuding-30','園亭覽物','韋應物','唐','御定全唐诗','yuding','','[]','積雨時物變，夏綠滿園新。殘花已落實，高筍半成筠。',36,'御定全唐詩/json/192.json','["積雨時物變，夏綠滿園新。殘花已落實，高筍半成筠。", "守此幽棲地，自是忘機人。"]'),
('yuding-31','觀灃水漲','韋應物','唐','御定全唐诗','yuding','','[]','夏雨萬壑湊，灃漲暮渾渾。草木盈川穀，澶漫一平吞。',72,'御定全唐詩/json/192.json','["夏雨萬壑湊，灃漲暮渾渾。草木盈川穀，澶漫一平吞。", "槎梗方彌泛，濤沫亦洪翻。北來注涇渭，所過無安源。", "雲嶺同昏黑，觀望悸心魂。舟人空斂棹，風波正自奔。"]'),
('yuding-32','陪王卿郎中游南池','韋應物','唐','御定全唐诗','yuding','','[]','鵷鴻俱失侶，同為此地遊。露浥荷花氣，風散柳園秋。',72,'御定全唐詩/json/192.json','["鵷鴻俱失侶，同為此地遊。露浥荷花氣，風散柳園秋。", "煙草凝衰嶼，星漢泛歸流。林高初上月，塘深未轉舟。", "清言屢往復，華樽始獻酬。終憶秦川賞，端坐起離憂。"]'),
('yuding-33','南園陪王卿游矚','韋應物','唐','御定全唐诗','yuding','','[]','形跡雖拘檢，世事澹無心。郡中多山水，日夕聽幽禽。',72,'御定全唐詩/json/192.json','["形跡雖拘檢，世事澹無心。郡中多山水，日夕聽幽禽。", "幾閣文墨暇，園林春景深。雜花芳意散，綠池暮色沉。", "君子有高躅，相攜在幽尋。一酌何為貴，可以寫沖襟。"]'),
('yuding-34','游西山','韋應物','唐','御定全唐诗','yuding','','[]','時事方擾擾，幽賞獨悠悠。弄泉朝涉澗，採石夜歸州。',48,'御定全唐詩/json/192.json','["時事方擾擾，幽賞獨悠悠。弄泉朝涉澗，採石夜歸州。", "揮翰題蒼峭，下馬曆嵌丘。所愛唯山水，到此即淹留。"]'),
('yuding-35','春遊南亭','韋應物','唐','御定全唐诗','yuding','','[]','川明氣已變，岩寒雲尚擁。南亭草心綠，春塘泉脈動。',48,'御定全唐詩/json/192.json','["川明氣已變，岩寒雲尚擁。南亭草心綠，春塘泉脈動。", "景煦聽禽響，雨餘看柳重。逍遙池館華，益愧專城寵。"]'),
('yuding-36','再游西山','韋應物','唐','御定全唐诗','yuding','','[]','南譙古山郡，信是高人居。自歎乏弘量，終朝親簿書。',108,'御定全唐詩/json/192.json','["南譙古山郡，信是高人居。自歎乏弘量，終朝親簿書。", "于時忽命駕，秋野正蕭疏。積逋誠待責，尋山亦有餘。", "測測石泉冷，曖曖煙穀虛。中有釋門子，種果結茅廬。", "出身厭名利，遇境即躊躇。守直雖多忤，視險方晏如。", "況將塵埃外，襟抱從此舒。"]'),
('yuding-37','遊靈岩寺','韋應物','唐','御定全唐诗','yuding','','[]','始入松路永，獨忻山寺幽。不知臨絕檻，乃見西江流。',84,'御定全唐詩/json/192.json','["始入松路永，獨忻山寺幽。不知臨絕檻，乃見西江流。", "吳岫分煙景，楚甸散林丘。方悟關塞眇，重軫故園愁。", "聞鐘戒歸騎，憩澗惜良遊。地疏泉穀狹，春深草木稠。", "茲焉賞未極，清景期杪秋。"]'),
('yuding-38','與盧陟同遊永定寺北池僧齋','韋應物','唐','御定全唐诗','yuding','','[]','密竹行已遠，子規啼更深。綠池芳草氣，閑齋春樹陰。',48,'御定全唐詩/json/192.json','["密竹行已遠，子規啼更深。綠池芳草氣，閑齋春樹陰。", "晴蝶飄蘭徑，遊蜂繞花心。不遇君攜手，誰複此幽尋。"]'),
('yuding-39','游溪','韋應物','唐','御定全唐诗','yuding','','[]','野水煙鶴唳，楚天雲雨空。玩舟清景晚，垂釣綠蒲中。',48,'御定全唐詩/json/192.json','["野水煙鶴唳，楚天雲雨空。玩舟清景晚，垂釣綠蒲中。", "落花飄旅衣，歸流澹清風。緣源不可極，遠樹但青蔥。"]'),
('yuding-40','遊開元精舍','韋應物','唐','御定全唐诗','yuding','','[]','夏衣始輕體，游步愛僧居。果園新雨後，香台照日初。',48,'御定全唐詩/json/192.json','["夏衣始輕體，游步愛僧居。果園新雨後，香台照日初。", "綠陰生晝靜，孤花表春餘。符竹方為累，形跡一來疏。"]'),
('yuding-41','襄武館游眺','韋應物','唐','御定全唐诗','yuding','','[]','州民知禮讓，訟簡得遨遊。高亭憑古地，山川當暮秋。',96,'御定全唐詩/json/192.json','["州民知禮讓，訟簡得遨遊。高亭憑古地，山川當暮秋。", "是時粳稻熟，西望盡田疇。仰恩慚政拙，念勞喜歲收。", "澹泊風景晏，繚繞雲樹幽。節往情惻惻，天高思悠悠。", "嘉賓幸雲集，芳樽始淹留。還希習池賞，聊以駐鳴騶。"]'),
('yuding-42','秋景詣琅琊精舍','韋應物','唐','御定全唐诗','yuding','','[]','屢訪塵外跡，未窮幽賞情。高秋天景遠，始見山水清。',72,'御定全唐詩/json/192.json','["屢訪塵外跡，未窮幽賞情。高秋天景遠，始見山水清。", "上陟岩殿憩，暮看雲壑平。蒼茫寒色起，迢遞晚鐘鳴。", "意有清夜戀，身為符守嬰。悟言緇衣子，蕭灑中林行。"]'),
('yuding-43','同韓郎中閒庭南望秋景','韋應物','唐','御定全唐诗','yuding','','[]','朝下抱餘素，地高心本閑。如何趨府客，罷秩見秋山。',48,'御定全唐詩/json/192.json','["朝下抱餘素，地高心本閑。如何趨府客，罷秩見秋山。", "疏樹共寒意，游禽同暮還。因君悟清景，西望一開顏。"]'),
('yuding-44','慈恩精舍南池作','韋應物','唐','御定全唐诗','yuding','','[]','清境豈雲遠，炎氛忽如遺。重門布綠陰，菡萏滿廣池。',84,'御定全唐詩/json/192.json','["清境豈雲遠，炎氛忽如遺。重門布綠陰，菡萏滿廣池。", "石發散清淺，林光動漣漪。緣崖摘紫房，扣檻集靈龜。", "浥浥餘露氣，馥馥幽襟披。積喧忻物曠，耽玩覺景馳。", "明晨複趨府，幽賞當反思。"]'),
('yuding-45','雨夜宿清都觀','韋應物','唐','御定全唐诗','yuding','','[]','靈飆動閶闔，微雨灑瑤林。複此新秋夜，高閣正沉沉。',84,'御定全唐詩/json/192.json','["靈飆動閶闔，微雨灑瑤林。複此新秋夜，高閣正沉沉。", "曠歲恨殊跡，茲夕一披襟。洞戶含涼氣，網軒構層陰。", "況自展良友，芳樽遂盈斟。適悟委前妄，清言怡道心。", "豈戀腰間綬，如彼籠中禽。"]'),
('yuding-46','善福精舍秋夜遲諸君','韋應物','唐','御定全唐诗','yuding','','[]','廣庭獨閒步，夜色方湛然。丹閣已排雲，皓月更高懸。',96,'御定全唐詩/json/192.json','["廣庭獨閒步，夜色方湛然。丹閣已排雲，皓月更高懸。", "繁露降秋節，蒼林鬱芊芊。仰觀天氣涼，高詠古人篇。", "撫己亮無庸，結交賴群賢。屬予翹思時，方子中夜眠。", "相去隔城闕，佳期屢徂遷。如何日夕待，見月三四圓。"]'),
('yuding-47','東郊','韋應物','唐','御定全唐诗','yuding','','[]','吏舍局終年，出郊曠清曙。楊柳散和風，青山澹吾慮。',72,'御定全唐詩/json/192.json','["吏舍局終年，出郊曠清曙。楊柳散和風，青山澹吾慮。", "依叢適自憩，緣澗還複去。微雨靄芳原，春鳩鳴何處。", "樂幽心屢止，遵事蹟猶遽。終罷斯結廬，慕陶真可庶。"]'),
('yuding-48','秋郊作','韋應物','唐','御定全唐诗','yuding','','[]','清露澄境遠，旭日照林初。一望秋山淨，蕭條形跡疏。',48,'御定全唐詩/json/192.json','["清露澄境遠，旭日照林初。一望秋山淨，蕭條形跡疏。", "登原忻時稼，采菊行故墟。方願沮溺耦，淡泊守田廬。"]'),
('yuding-49','行寬禪師院','韋應物','唐','御定全唐诗','yuding','','[]','北望極長廊，斜扉映叢竹。亭午一來尋，院幽僧亦獨。',36,'御定全唐詩/json/192.json','["北望極長廊，斜扉映叢竹。亭午一來尋，院幽僧亦獨。", "唯聞山鳥啼，愛此林下宿。"]'),
('yuding-50','神靜師院','韋應物','唐','御定全唐诗','yuding','','[]','青苔幽巷遍，新林露氣微。經聲在深竹，高齋獨掩扉。',48,'御定全唐詩/json/192.json','["青苔幽巷遍，新林露氣微。經聲在深竹，高齋獨掩扉。", "憩樹愛嵐嶺，聽禽悅朝暉。方耽靜中趣，自與塵事違。"]'),
('yuding-51','精舍納涼','韋應物','唐','御定全唐诗','yuding','','[]','山景寂已晦，野寺變蒼蒼。夕風吹高殿，露葉散林光。',48,'御定全唐詩/json/192.json','["山景寂已晦，野寺變蒼蒼。夕風吹高殿，露葉散林光。", "清鐘始戒夜，幽禽尚歸翔。誰複掩扉臥，不詠南軒涼。"]'),
('yuding-52','藍嶺精舍','韋應物','唐','御定全唐诗','yuding','','[]','石壁精舍高，排雲聊直上。佳遊愜始願，忘險得前賞。',84,'御定全唐詩/json/192.json','["石壁精舍高，排雲聊直上。佳遊愜始願，忘險得前賞。", "崖傾景方晦，穀轉川如掌。綠林含蕭條，飛閣起弘敞。", "道人上方至，清夜還獨往。日落群山陰，天秋百泉響。", "所嗟累已成，安得長偃仰。"]'),
('yuding-53','道晏寺主院','韋應物','唐','御定全唐诗','yuding','','[]','北鄰有幽竹，潛筠穿我廬。往來地已密，心樂道者居。',48,'御定全唐詩/json/192.json','["北鄰有幽竹，潛筠穿我廬。往來地已密，心樂道者居。", "殘花回往節，輕條蔭夏初。聞鐘北窗起，嘯傲永日餘。"]'),
('yuding-54','義演法師西齋','韋應物','唐','御定全唐诗','yuding','','[]','結茅臨絕岸，隔水聞清磬。山水曠蕭條，登臨散情性。',48,'御定全唐詩/json/192.json','["結茅臨絕岸，隔水聞清磬。山水曠蕭條，登臨散情性。", "稍指緣原騎，還尋汲澗徑。長嘯倚亭樹，悵然川光暝。"]'),
('yuding-55','澄秀上座院','韋應物','唐','御定全唐诗','yuding','','[]','繚繞西南隅，鳥聲轉幽靜。秀公今不在，獨禮高僧影。',36,'御定全唐詩/json/192.json','["繚繞西南隅，鳥聲轉幽靜。秀公今不在，獨禮高僧影。", "林下器未收，何人適煮茗。"]'),
('yuding-56','至西峰蘭若受田婦饋','韋應物','唐','御定全唐诗','yuding','','[]','攀崖複緣澗，遂造幽人居。鳥鳴泉穀暖，土起萌甲舒。',72,'御定全唐詩/json/192.json','["攀崖複緣澗，遂造幽人居。鳥鳴泉穀暖，土起萌甲舒。", "聊登石樓憩，下玩潭中魚。田婦有嘉獻，潑撒新歲餘。", "常怪投錢飲，事與賢達疏。今我何為答，鰥寡欲焉如。"]'),
('yuding-57','曇智禪師院','韋應物','唐','御定全唐诗','yuding','','[]','高年不復出，門徑眾草生。時夏方新雨，果藥發餘榮。',48,'御定全唐詩/json/192.json','["高年不復出，門徑眾草生。時夏方新雨，果藥發餘榮。", "疏澹下林景，流暮幽禽情。身名兩俱遣，獨此野寺行。"]'),
('yuding-58','起度律師同居東齋院','韋應物','唐','御定全唐诗','yuding','','[]','釋子喜相偶，幽林俱避喧。安居同僧夏，清夜諷道言。',48,'御定全唐詩/json/192.json','["釋子喜相偶，幽林俱避喧。安居同僧夏，清夜諷道言。", "對閣景恒晏，步庭陰始繁。逍遙無一事，松風入南軒。"]'),
('yuding-59','遊琅琊山寺','韋應物','唐','御定全唐诗','yuding','','[]','受命恤人隱，茲遊久未遑。鳴騶響幽澗，前旌耀崇岡。',108,'御定全唐詩/json/192.json','["受命恤人隱，茲遊久未遑。鳴騶響幽澗，前旌耀崇岡。", "青冥台砌寒，綠縟草木香。填壑躋花界，疊石構雲房。", "經制隨岩轉，繚繞豈定方。新泉泄陰壁，高蘿蔭綠塘。", "攀林一棲止，飲水得清涼。物累誠可遣，疲氓終未忘。", "還歸坐郡閣，但見山蒼蒼。"]'),
('yuding-60','同越琅琊山','韋應物','唐','御定全唐诗','yuding','','[]','石門有雪無行跡，松壑凝煙滿眾香。',32,'御定全唐詩/json/192.json','["石門有雪無行跡，松壑凝煙滿眾香。", "餘食施庭寒鳥下，破衣掛樹老僧亡。"]'),
('yuding-61','詣西山深師','韋應物','唐','御定全唐诗','yuding','','[]','曹溪舊弟子，何緣住此山。世有征戰事，心將流水閑。',48,'御定全唐詩/json/192.json','["曹溪舊弟子，何緣住此山。世有征戰事，心將流水閑。", "掃林驅虎出，宴坐一林間。藩守甯為重，擁騎造雲關。"]'),
('yuding-62','尋簡寂觀瀑布','韋應物','唐','御定全唐诗','yuding','','[]','躡石欹危過急澗，攀崖迢遞弄懸泉。',32,'御定全唐詩/json/192.json','["躡石欹危過急澗，攀崖迢遞弄懸泉。", "猶將虎竹為身累，欲付歸人絕世緣。"]'),
('yuding-63','簡寂觀西澗瀑布下作','韋應物','唐','御定全唐诗','yuding','','[]','淙流絕壁散，虛煙翠澗深。叢際松風起，飄來灑塵襟。',72,'御定全唐詩/json/192.json','["淙流絕壁散，虛煙翠澗深。叢際松風起，飄來灑塵襟。", "窺蘿玩猿鳥，解組傲雲林。茶果邀真侶，觴酌洽同心。", "曠歲懷茲賞，行春始重尋。聊將橫吹笛，一寫山水音。"]'),
('yuding-64','游南齋','韋應物','唐','御定全唐诗','yuding','','[]','池上鳴佳禽，僧齋日幽寂。高林晚露清，紅藥無人摘。',48,'御定全唐詩/json/192.json','["池上鳴佳禽，僧齋日幽寂。高林晚露清，紅藥無人摘。", "春水不生煙，荒岡筠翳石。不應朝夕遊，良為蹉跎客。"]'),
('yuding-65','南園','韋應物','唐','御定全唐诗','yuding','','[]','清露夏天曉，荒園野氣通。水禽遙泛雪，池蓮迥披紅。',48,'御定全唐詩/json/192.json','["清露夏天曉，荒園野氣通。水禽遙泛雪，池蓮迥披紅。", "幽林詎知暑，環舟似不窮。頓灑塵喧意，長嘯滿襟風。"]'),
('yuding-66','西亭','韋應物','唐','御定全唐诗','yuding','','[]','亭宇麗朝景，簾牖散暄風。小山初構石，珍樹正然紅。',48,'御定全唐詩/json/192.json','["亭宇麗朝景，簾牖散暄風。小山初構石，珍樹正然紅。", "弱藤已扶樹，幽蘭欲成叢。芳心幸如此，佳人時不同。"]'),
('yuding-67','夏景園廬','韋應物','唐','御定全唐诗','yuding','','[]','群木晝陰靜，北窗涼氣多。閒居逾時節，夏雲已嵯峨。',48,'御定全唐詩/json/192.json','["群木晝陰靜，北窗涼氣多。閒居逾時節，夏雲已嵯峨。", "搴葉愛繁綠，緣澗弄驚波。豈為論夙志，對此青山阿。"]'),
('yuding-68','夏至避暑北池','韋應物','唐','御定全唐诗','yuding','','[]','晝晷已雲極，宵漏自此長。未及施政教，所憂變炎涼。',96,'御定全唐詩/json/192.json','["晝晷已雲極，宵漏自此長。未及施政教，所憂變炎涼。", "公門日多暇，是月農稍忙。高居念田裏，苦熱安可當。", "亭午息群物，獨游愛方塘。門閉陰寂寂，城高樹蒼蒼。", "綠筠尚含粉，圓荷始散芳。於焉灑煩抱，可以對華觴。"]'),
('yuding-69','題從侄成緒西林精舍書齋','韋應物','唐','御定全唐诗','yuding','','[]','棲身齒多暮，息心君獨少。慕謝始精文，依僧欲觀妙。',120,'御定全唐詩/json/192.json','["棲身齒多暮，息心君獨少。慕謝始精文，依僧欲觀妙。", "冽泉前階注，清池北窗照。果藥雜芬敷，松筠疏蒨峭。", "屢躋幽人境，每肆芳辰眺。采栗玄猿窟，擷芝丹林嶠。", "紵衣豈寒禦，蔬食非饑療。雖甘巷北單，豈塞青紫耀。", "郡有優賢榻，朝編貢士詔。欲同朱輪載，勿憚移文誚。"]'),
('yuding-70','題鄭弘憲侍禦遺愛草堂','韋應物','唐','御定全唐诗','yuding','','[]','居士近依僧，青山結茅屋。疏鬆映嵐晚，春池含苔綠。',48,'御定全唐詩/json/192.json','["居士近依僧，青山結茅屋。疏鬆映嵐晚，春池含苔綠。", "繁華冒陽嶺，新禽響幽谷。長嘯攀喬林，慕茲高世躅。"]'),
('yuding-71','同元錫題琅琊寺','韋應物','唐','御定全唐诗','yuding','','[]','適從郡邑喧，又茲三伏熱。山中清景多，石罅寒泉潔。',96,'御定全唐詩/json/192.json','["適從郡邑喧，又茲三伏熱。山中清景多，石罅寒泉潔。", "花香天界事，松竹人間別。殿分嵐嶺明，磴臨懸壑絕。", "昏旭窮陟降，幽顯盡披閱。嶔駭風雨區，寒知龍蛇穴。", "情虛澹泊生，境寂塵妄滅。經世豈非道，無為厭車轍。"]'),
('yuding-72','題鄭拾遺草堂','韋應物','唐','御定全唐诗','yuding','','[]','借地結茅棟，橫竹掛朝衣。秋園雨中綠，幽居塵事違。',48,'御定全唐詩/json/192.json','["借地結茅棟，橫竹掛朝衣。秋園雨中綠，幽居塵事違。", "陰井夕蟲亂，高林霜果稀。子有白雲意，構此想岩扉。"]'),
('yuding-0','詠玉','韋應物','唐','御定全唐诗','yuding','','[]','乾坤有精物，至寶無文章。雕琢為世器，真性一朝傷。',24,'御定全唐詩/json/193.json','["乾坤有精物，至寶無文章。雕琢為世器，真性一朝傷。"]'),
('yuding-1','詠露珠','韋應物','唐','御定全唐诗','yuding','','[]','秋荷一滴露，清夜墜玄天。將來玉盤上，不定始知圓。',24,'御定全唐詩/json/193.json','["秋荷一滴露，清夜墜玄天。將來玉盤上，不定始知圓。"]'),
('yuding-2','詠水精','韋應物','唐','御定全唐诗','yuding','','[]','映物隨顏色，含空無表裏。持來向明月，的皪愁成水。',24,'御定全唐詩/json/193.json','["映物隨顏色，含空無表裏。持來向明月，的皪愁成水。"]'),
('yuding-3','詠珊瑚','韋應物','唐','御定全唐诗','yuding','','[]','絳樹無花葉，非石亦非瓊。世人何處得，蓬萊石上生。',24,'御定全唐詩/json/193.json','["絳樹無花葉，非石亦非瓊。世人何處得，蓬萊石上生。"]'),
('yuding-4','詠琉璃','韋應物','唐','御定全唐诗','yuding','','[]','有色同寒冰，無物隔纖塵。象筵看不見，堪將對玉人。',24,'御定全唐詩/json/193.json','["有色同寒冰，無物隔纖塵。象筵看不見，堪將對玉人。"]'),
('yuding-5','詠琥珀','韋應物','唐','御定全唐诗','yuding','','[]','曾為老茯神，本是寒松液。蚊蚋落其中，千年猶可覿。',24,'御定全唐詩/json/193.json','["曾為老茯神，本是寒松液。蚊蚋落其中，千年猶可覿。"]'),
('yuding-6','詠曉','韋應物','唐','御定全唐诗','yuding','','[]','軍中始吹角，城上河初落。深沉猶隱帷，晃朗先分閣。',24,'御定全唐詩/json/193.json','["軍中始吹角，城上河初落。深沉猶隱帷，晃朗先分閣。"]'),
('yuding-7','詠夜','韋應物','唐','御定全唐诗','yuding','','[]','明從何處去，暗從何處來。但覺年年老，半是此中催。',24,'御定全唐詩/json/193.json','["明從何處去，暗從何處來。但覺年年老，半是此中催。"]'),
('yuding-8','詠聲','韋應物','唐','御定全唐诗','yuding','','[]','萬物自生聽，太空恒寂寥。還從靜中起，卻向靜中消。',24,'御定全唐詩/json/193.json','["萬物自生聽，太空恒寂寥。還從靜中起，卻向靜中消。"]'),
('yuding-9','任洛陽丞請告一首','韋應物','唐','御定全唐诗','yuding','','[]','方鑿不受圓，直木不為輪。揆材各有用，反性生苦辛。',108,'御定全唐詩/json/193.json','["方鑿不受圓，直木不為輪。揆材各有用，反性生苦辛。", "折腰非吾事，飲水非吾貧。休告臥空館，養病絕囂塵。", "游魚自成族，野鳥亦有群。家園杜陵下，千歲心氛氳。", "天晴嵩山高，雪後河洛春。喬木猶未芳，百草日已新。", "著書複何為，當去東皋耘。"]'),
('yuding-10','縣齋','韋應物','唐','御定全唐诗','yuding','','[]','仲春時景好，草木漸舒榮。公門且無事，微雨園林清。',72,'御定全唐詩/json/193.json','["仲春時景好，草木漸舒榮。公門且無事，微雨園林清。", "決決水泉動，忻忻眾鳥鳴。閑齋始延矚，東作興庶氓。", "即事玩文墨，抱沖披道經。於焉日淡泊，徒使芳尊盈。"]'),
('yuding-11','晚出府舍與獨孤兵曹、令狐士曹南尋朱雀街歸裏第','韋應物','唐','御定全唐诗','yuding','','[]','分曹幸同簡，聯騎方愜素。還從廣陌歸，不覺青山暮。',72,'御定全唐詩/json/193.json','["分曹幸同簡，聯騎方愜素。還從廣陌歸，不覺青山暮。", "翻翻鳥未沒，杳杳鐘猶度。尋草遠無人，望山多枉路。", "聊參世士跡，嘗得靜者顧。出入雖見牽，忘身緣所晤。"]'),
('yuding-12','休暇東齋','韋應物','唐','御定全唐诗','yuding','','[]','由來束帶士，請謁無朝暮。公暇及私身，何能獨閒步。',84,'御定全唐詩/json/193.json','["由來束帶士，請謁無朝暮。公暇及私身，何能獨閒步。", "摘葉愛芳在，捫竹憐粉汙。岸幘偃東齋，夏天清曉露。", "懷仙閱真誥，貽友題幽素。榮達頗知疏，恬然自成度。", "綠苔日已滿，幽寂誰來顧。"]'),
('yuding-13','夜直省中','韋應物','唐','御定全唐诗','yuding','','[]','河漢有秋意，南宮生早涼。玉漏殊杳杳，雲闕更蒼蒼。',48,'御定全唐詩/json/193.json','["河漢有秋意，南宮生早涼。玉漏殊杳杳，雲闕更蒼蒼。", "華燈發新焰，輕煙浮夕香。顧跡知為忝，束帶愧周行。"]'),
('yuding-14','郡內閒居','韋應物','唐','御定全唐诗','yuding','','[]','棲息絕塵侶，孱鈍得自怡。腰懸竹使符，心與廬山緇。',72,'御定全唐詩/json/193.json','["棲息絕塵侶，孱鈍得自怡。腰懸竹使符，心與廬山緇。", "永日一酣寢，起坐兀無思。長廊獨看雨，眾藥發幽姿。", "今夕已雲罷，明晨複如斯。何事能為累，寵辱豈要辭。"]'),
('yuding-15','燕居即事','韋應物','唐','御定全唐诗','yuding','','[]','蕭條竹林院，風雨叢蘭折。幽鳥林上啼，青苔人跡絕。',48,'御定全唐詩/json/193.json','["蕭條竹林院，風雨叢蘭折。幽鳥林上啼，青苔人跡絕。", "燕居日已永，夏木紛成結。幾閣積群書，時來北窗閱。"]'),
('yuding-16','幽居','韋應物','唐','御定全唐诗','yuding','','[]','貴賤雖異等，出門皆有營。獨無外物牽，遂此幽居情。',72,'御定全唐詩/json/193.json','["貴賤雖異等，出門皆有營。獨無外物牽，遂此幽居情。", "微雨夜來過，不知春草生。青山忽已曙，鳥雀繞舍鳴。", "時與道人偶，或隨樵者行。自當安蹇劣，誰謂薄世榮。"]'),
('yuding-17','野居書情','韋應物','唐','御定全唐诗','yuding','','[]','世事日可見，身名良蹉跎。尚瞻白雲嶺，聊作負薪歌。',24,'御定全唐詩/json/193.json','["世事日可見，身名良蹉跎。尚瞻白雲嶺，聊作負薪歌。"]'),
('yuding-18','郊居言志','韋應物','唐','御定全唐诗','yuding','','[]','負暄衡門下，望雲歸遠山。但要尊中物，餘事豈相關。',96,'御定全唐詩/json/193.json','["負暄衡門下，望雲歸遠山。但要尊中物，餘事豈相關。", "交無是非責，且得任疏頑。日夕臨清澗，逍遙思慮閑。", "出去唯空屋，弊簀委窗間。何異林棲鳥，戀此複來還。", "世榮斯獨已，頹志亦何攀。唯當歲豐熟，閭裏一歡顏。"]'),
('yuding-19','夏景端居即事','韋應物','唐','御定全唐诗','yuding','','[]','北齋有涼氣，嘉樹對層城。重門永日掩，清池夏雲生。',48,'御定全唐詩/json/193.json','["北齋有涼氣，嘉樹對層城。重門永日掩，清池夏雲生。", "遇此庭訟簡，始聞蟬初鳴。逾懷故園愴，默默以緘情。"]'),
('yuding-20','始至郡','韋應物','唐','御定全唐诗','yuding','','[]','湓城古雄郡，橫江千里馳。高樹上迢遞，峻堞繞欹危。',120,'御定全唐詩/json/193.json','["湓城古雄郡，橫江千里馳。高樹上迢遞，峻堞繞欹危。", "井邑煙火晚，郊原草樹滋。洪流蕩北址，崇嶺郁南圻。", "斯民本樂生，逃逝竟何為。旱歲屬荒歉，舊逋積如坻。", "到郡方逾月，終朝理亂絲。賓朋未及宴，簡牘已雲疲。", "昔賢播高風，得守愧無施。豈待干戈戢，且願撫惸嫠。"]'),
('yuding-21','郡中西齋','韋應物','唐','御定全唐诗','yuding','','[]','似與塵境絕，蕭條齋舍秋。寒花獨經雨，山禽時到州。',48,'御定全唐詩/json/193.json','["似與塵境絕，蕭條齋舍秋。寒花獨經雨，山禽時到州。", "清觴養真氣，玉書示道流。豈將符守戀，幸已棲心幽。"]'),
('yuding-22','新理西齋','韋應物','唐','御定全唐诗','yuding','','[]','方將氓訟理，久翳西齋居。草木無行次，閒暇一芟除。',84,'御定全唐詩/json/193.json','["方將氓訟理，久翳西齋居。草木無行次，閒暇一芟除。", "春陽土脈起，膏澤發生初。養條刊朽枿，護藥鋤穢蕪。", "稍稍覺林聳，歷歷忻竹疏。始見庭宇曠，頓令煩抱舒。", "茲焉即可愛，何必是吾廬。"]'),
('yuding-23','曉坐西齋','韋應物','唐','御定全唐诗','yuding','','[]','冬冬城鼓動，稍稍林鴉去。柳意不勝春，岩光已知曙。',60,'御定全唐詩/json/193.json','["冬冬城鼓動，稍稍林鴉去。柳意不勝春，岩光已知曙。", "寢齋有單祶，靈藥為朝茹。盥漱忻景清，焚香澄神慮。", "公門自常事，道心甯易處。"]'),
('yuding-24','郡齋臥疾絕句','韋應物','唐','御定全唐诗','yuding','','[]','香爐宿火滅，蘭燈宵影微。秋齋獨臥病，誰與覆寒衣。',24,'御定全唐詩/json/193.json','["香爐宿火滅，蘭燈宵影微。秋齋獨臥病，誰與覆寒衣。"]'),
('yuding-25','寓居永定精舍','韋應物','唐','御定全唐诗','yuding','','[]','政拙忻罷守，閒居初理生。家貧何由往，夢想在京城。',72,'御定全唐詩/json/193.json','["政拙忻罷守，閒居初理生。家貧何由往，夢想在京城。", "野寺霜露月，農興羈旅情。聊租二頃田，方課子弟耕。", "眼暗文字廢，身閑道心精。即與人群遠，豈謂是非嬰。"]'),
('yuding-26','永定寺喜辟強夜至','韋應物','唐','御定全唐诗','yuding','','[]','子有新歲慶，獨此苦寒歸。夜叩竹林寺，山行雪滿衣。',48,'御定全唐詩/json/193.json','["子有新歲慶，獨此苦寒歸。夜叩竹林寺，山行雪滿衣。", "深爐正燃火，空齋共掩扉。還將一尊對，無言百事違。"]'),
('yuding-27','野居','韋應物','唐','御定全唐诗','yuding','','[]','結髮屢辭秩，立身本疏慢。今得罷守歸，幸無世欲患。',72,'御定全唐詩/json/193.json','["結髮屢辭秩，立身本疏慢。今得罷守歸，幸無世欲患。", "棲止且偏僻，嬉遊無早宴。逐兔上坡岡，捕魚緣赤澗。", "高歌意氣在，貰酒貧居慣。時啟北窗扉，豈將文墨間。"]'),
('yuding-28','同褒子秋齋獨宿','韋應物','唐','御定全唐诗','yuding','','[]','山月皎如燭，風霜時動竹。夜半鳥驚棲，窗間人獨宿。',24,'御定全唐詩/json/193.json','["山月皎如燭，風霜時動竹。夜半鳥驚棲，窗間人獨宿。"]'),
('yuding-29','餌黃精','韋應物','唐','御定全唐诗','yuding','','[]','靈藥出西山，服食采其根。九蒸換凡骨，經著上世言。',72,'御定全唐詩/json/193.json','["靈藥出西山，服食采其根。九蒸換凡骨，經著上世言。", "候火起中夜，馨香滿南軒。齋居感眾靈，藥術啟妙門。", "自懷物外心，豈與俗士論。終期脫印綬，永與天壤存。"]'),
('yuding-30','昭國裏第聽元老師彈琴','韋應物','唐','御定全唐诗','yuding','','[]','竹林高宇霜露清，朱絲玉徽多故情。',32,'御定全唐詩/json/193.json','["竹林高宇霜露清，朱絲玉徽多故情。", "暗識啼烏與別鶴，只緣中有斷腸聲。"]'),
('yuding-31','野次聽元昌奏橫吹','韋應物','唐','御定全唐诗','yuding','','[]','立馬蓮塘吹橫笛，微風動柳生水波。',32,'御定全唐詩/json/193.json','["立馬蓮塘吹橫笛，微風動柳生水波。", "北人聽罷淚將落，南朝曲中怨更多。"]'),
('yuding-32','樓中閱清管','韋應物','唐','御定全唐诗','yuding','','[]','山陽遺韻在，林端橫吹驚。響迥憑高閣，曲怨繞秋城。',48,'御定全唐詩/json/193.json','["山陽遺韻在，林端橫吹驚。響迥憑高閣，曲怨繞秋城。", "淅瀝危葉振，蕭瑟涼氣生。始遇茲管賞，已懷故園情。"]'),
('yuding-33','寒食','韋應物','唐','御定全唐诗','yuding','','[]','晴明寒食好，春園百卉開。彩繩拂花去，輕球度閣來。',48,'御定全唐詩/json/193.json','["晴明寒食好，春園百卉開。彩繩拂花去，輕球度閣來。", "長歌送落日，緩吹逐殘杯。非關無燭罷，良為羈思催。"]'),
('yuding-34','七夕','韋應物','唐','御定全唐诗','yuding','','[]','人世拘形跡，別去間山川。豈意靈仙偶，相望亦彌年。',48,'御定全唐詩/json/193.json','["人世拘形跡，別去間山川。豈意靈仙偶，相望亦彌年。", "夕衣清露濕，晨駕秋風前。臨歡定不住，當為何所牽。"]'),
('yuding-35','九日','韋應物','唐','御定全唐诗','yuding','','[]','今朝把酒複惆悵，憶在杜陵田舍時。',32,'御定全唐詩/json/193.json','["今朝把酒複惆悵，憶在杜陵田舍時。", "明年九日知何處，世難還家未有期。"]'),
('yuding-36','秋夜','韋應物','唐','御定全唐诗','yuding','','[]','暗窗涼葉動，秋天寢席單。憂人半夜起，明月在林端。',48,'御定全唐詩/json/193.json','["暗窗涼葉動，秋天寢席單。憂人半夜起，明月在林端。", "一與清景遇，每憶平生歡。如何方惻愴，披衣露更寒。"]'),
('yuding-37','秋夜一絕','韋應物','唐','御定全唐诗','yuding','','[]','高閣漸凝露，涼葉稍飄闈。憶在南宮直，夜長鐘漏稀。',24,'御定全唐詩/json/193.json','["高閣漸凝露，涼葉稍飄闈。憶在南宮直，夜長鐘漏稀。"]'),
('yuding-38','滁城對雪','韋應物','唐','御定全唐诗','yuding','','[]','晨起滿闈雪，憶朝閶闔時。玉座分曙早，金爐上煙遲。',60,'御定全唐詩/json/193.json','["晨起滿闈雪，憶朝閶闔時。玉座分曙早，金爐上煙遲。", "飄散雲台下，淩亂桂樹姿。廁跡鴛鷺末，蹈舞豐年期。", "今朝覆山郡，寂寞複何為。"]'),
('yuding-39','雪中','韋應物','唐','御定全唐诗','yuding','','[]','空堂歲已晏，密室獨安眠。壓筱夜偏積，覆閣曉逾妍。',48,'御定全唐詩/json/193.json','["空堂歲已晏，密室獨安眠。壓筱夜偏積，覆閣曉逾妍。", "連山暗古郡，驚風散一川。此時騎馬出，忽省京華年。"]'),
('yuding-40','詠春雪','韋應物','唐','御定全唐诗','yuding','','[]','裴回輕雪意，似惜豔陽時。不悟風花冷，翻令梅柳遲。',24,'御定全唐詩/json/193.json','["裴回輕雪意，似惜豔陽時。不悟風花冷，翻令梅柳遲。"]'),
('yuding-41','對春雪','韋應物','唐','御定全唐诗','yuding','','[]','蕭屑杉松聲，寂寥寒夜慮。州貧人吏稀，雪滿山城曙。',48,'御定全唐詩/json/193.json','["蕭屑杉松聲，寂寥寒夜慮。州貧人吏稀，雪滿山城曙。", "春塘看幽谷，棲禽愁未去。開闈正亂流，寧辨花枝處。"]'),
('yuding-42','對殘燈','韋應物','唐','御定全唐诗','yuding','','[]','獨照碧窗久，欲隨寒燼滅。幽人將遽眠，解帶翻成結。',24,'御定全唐詩/json/193.json','["獨照碧窗久，欲隨寒燼滅。幽人將遽眠，解帶翻成結。"]'),
('yuding-43','對芳尊','韋應物','唐','御定全唐诗','yuding','','[]','對芳尊，醉來百事何足論。遙見青山始一醒，',20,'御定全唐詩/json/193.json','["對芳尊，醉來百事何足論。遙見青山始一醒，"]'),
('yuding-44','夜對流螢作','韋應物','唐','御定全唐诗','yuding','','[]','月暗竹亭幽，螢光拂席流。還思故園夜，更度一年秋。',48,'御定全唐詩/json/193.json','["月暗竹亭幽，螢光拂席流。還思故園夜，更度一年秋。", "自愜觀書興，何慚秉燭遊。府中徒冉冉，明發好歸休。"]'),
('yuding-45','對新篁','韋應物','唐','御定全唐诗','yuding','','[]','新綠苞初解，嫩氣筍猶香。含露漸舒葉，抽叢稍自長。',36,'御定全唐詩/json/193.json','["新綠苞初解，嫩氣筍猶香。含露漸舒葉，抽叢稍自長。", "清晨止亭下，獨愛此幽篁。"]'),
('yuding-46','夏花明','韋應物','唐','御定全唐诗','yuding','','[]','夏條綠已密，朱萼綴明鮮。炎炎日正午，灼灼火俱燃。',48,'御定全唐詩/json/193.json','["夏條綠已密，朱萼綴明鮮。炎炎日正午，灼灼火俱燃。", "翻風適自亂，照水複成妍。歸視窗間字，熒煌滿眼前。"]'),
('yuding-47','對萱草','韋應物','唐','御定全唐诗','yuding','','[]','何人樹萱草，對此郡齋幽。本是忘憂物，今夕重生憂。',48,'御定全唐詩/json/193.json','["何人樹萱草，對此郡齋幽。本是忘憂物，今夕重生憂。", "叢疏露始滴，芳餘蝶尚留。還思杜陵圃，離披風雨秋。"]'),
('yuding-48','見紫荊花','韋應物','唐','御定全唐诗','yuding','','[]','雜英紛已積，含芳獨暮春。還如故園樹，忽憶故園人。',24,'御定全唐詩/json/193.json','["雜英紛已積，含芳獨暮春。還如故園樹，忽憶故園人。"]'),
('yuding-49','玩螢火','韋應物','唐','御定全唐诗','yuding','','[]','時節變衰草，物色近新秋。度月影才斂，繞竹光復流。',24,'御定全唐詩/json/193.json','["時節變衰草，物色近新秋。度月影才斂，繞竹光復流。"]'),
('yuding-50','對雜花','韋應物','唐','御定全唐诗','yuding','','[]','朝紅爭景新，夕素含露翻。妍姿如有意，流芳複滿園。',48,'御定全唐詩/json/193.json','["朝紅爭景新，夕素含露翻。妍姿如有意，流芳複滿園。", "單棲守遠郡，永日掩重門。不與花為偶，終遣與誰言。"]'),
('yuding-51','種藥','韋應物','唐','御定全唐诗','yuding','','[]','好讀神農書，多識藥草名。持縑購山客，移蒔羅眾英。',84,'御定全唐詩/json/193.json','["好讀神農書，多識藥草名。持縑購山客，移蒔羅眾英。", "不改幽澗色，宛如此地生。汲井既蒙澤，插楥亦扶傾。", "陰穎夕房斂，陽條夏花明。悅玩從茲始，日夕繞庭行。", "州民自寡訟，養閑非政成。"]'),
('yuding-52','西澗種柳','韋應物','唐','御定全唐诗','yuding','','[]','宰邑乖所願，黽勉愧昔人。聊將休暇日，種柳西澗濱。',72,'御定全唐詩/json/193.json','["宰邑乖所願，黽勉愧昔人。聊將休暇日，種柳西澗濱。", "置鍤息微倦，臨流睇歸雲。封壤自人力，生條在陽春。", "成陰豈自取，為茂屬他辰。延詠留佳賞，山水變夕曛。"]'),
('yuding-53','種瓜','韋應物','唐','御定全唐诗','yuding','','[]','率性方鹵莽，理生尤自疏。今年學種瓜，園圃多荒蕪。',72,'御定全唐詩/json/193.json','["率性方鹵莽，理生尤自疏。今年學種瓜，園圃多荒蕪。", "眾草同雨露，新苗獨翳如。直以春窘迫，過時不得鋤。", "田家笑枉費，日夕轉空虛。信非吾儕事，且讀古人書。"]'),
('yuding-54','喜園中茶生','韋應物','唐','御定全唐诗','yuding','','[]','潔性不可汙，為飲滌塵煩。此物信靈味，本自出山原。',48,'御定全唐詩/json/193.json','["潔性不可汙，為飲滌塵煩。此物信靈味，本自出山原。", "聊因理郡餘，率爾植荒園。喜隨眾草長，得與幽人言。"]'),
('yuding-55','移海榴','韋應物','唐','御定全唐诗','yuding','','[]','葉有苦寒色，山中霜霰多。雖此蒙陽景，移根意如何。',24,'御定全唐詩/json/193.json','["葉有苦寒色，山中霜霰多。雖此蒙陽景，移根意如何。"]'),
('yuding-56','郡齋移杉','韋應物','唐','御定全唐诗','yuding','','[]','擢幹方數尺，幽姿已蒼然。結根西山寺，來植郡齋前。',48,'御定全唐詩/json/193.json','["擢幹方數尺，幽姿已蒼然。結根西山寺，來植郡齋前。", "新含野露氣，稍靜高窗眠。雖為賞心遇，豈有岩中緣。"]'),
('yuding-57','花徑','韋應物','唐','御定全唐诗','yuding','','[]','山花夾徑幽，古甃生苔澀。胡床理事餘，玉琴承露濕。',48,'御定全唐詩/json/193.json','["山花夾徑幽，古甃生苔澀。胡床理事餘，玉琴承露濕。", "朝與詩人賞，夜攜禪客入。自是塵外蹤，無令吏趨急。"]'),
('yuding-58','慈恩寺南池秋荷詠','韋應物','唐','御定全唐诗','yuding','','[]','對殿含涼氣，裁規覆清沼。衰紅受露多，餘馥依人少。',48,'御定全唐詩/json/193.json','["對殿含涼氣，裁規覆清沼。衰紅受露多，餘馥依人少。", "蕭蕭遠塵跡，颯颯淩秋曉。節謝客來稀，回塘方獨繞。"]'),
('yuding-59','題桐葉','韋應物','唐','御定全唐诗','yuding','','[]','參差剪綠綺，瀟灑覆瓊柯。憶在灃東寺，偏書此葉多。',24,'御定全唐詩/json/193.json','["參差剪綠綺，瀟灑覆瓊柯。憶在灃東寺，偏書此葉多。"]'),
('yuding-60','題石橋','韋應物','唐','御定全唐诗','yuding','','[]','遠學臨海嶠，橫此莓苔石。郡齋三四峰，如有靈仙跡。',48,'御定全唐詩/json/193.json','["遠學臨海嶠，橫此莓苔石。郡齋三四峰，如有靈仙跡。", "方愁暮雲滑，始照寒池碧。自與幽人期，逍遙竟朝夕。"]'),
('yuding-61','池上','韋應物','唐','御定全唐诗','yuding','','[]','郡中臥病久，池上一來賒。榆柳飄枯葉，風雨倒橫查。',24,'御定全唐詩/json/193.json','["郡中臥病久，池上一來賒。榆柳飄枯葉，風雨倒橫查。"]'),
('yuding-62','滁州西澗','韋應物','唐','御定全唐诗','yuding','','[]','獨憐幽草澗邊生，上有黃鸝深樹鳴。',32,'御定全唐詩/json/193.json','["獨憐幽草澗邊生，上有黃鸝深樹鳴。", "春潮帶雨晚來急，野渡無人舟自橫。"]'),
('yuding-63','西塞山','韋應物','唐','御定全唐诗','yuding','','[]','勢從千里奔，直入江中斷。嵐橫秋塞雄，地束驚流滿。',24,'御定全唐詩/json/193.json','["勢從千里奔，直入江中斷。嵐橫秋塞雄，地束驚流滿。"]'),
('yuding-64','山耕叟','韋應物','唐','御定全唐诗','yuding','','[]','蕭蕭垂白髮，默默詎知情。獨放寒林燒，多尋虎跡行。',36,'御定全唐詩/json/193.json','["蕭蕭垂白髮，默默詎知情。獨放寒林燒，多尋虎跡行。", "暮歸何處宿，來此空山耕。"]'),
('yuding-65','上方僧','韋應物','唐','御定全唐诗','yuding','','[]','見月出東山，上方高處禪。空林無宿火，獨夜汲寒泉。',36,'御定全唐詩/json/193.json','["見月出東山，上方高處禪。空林無宿火，獨夜汲寒泉。", "不下藍溪寺，今年三十年。"]'),
('yuding-66','煙際鐘','韋應物','唐','御定全唐诗','yuding','','[]','隱隱起何處，迢迢送落暉。蒼茫隨思遠，蕭散逐煙微。',36,'御定全唐詩/json/193.json','["隱隱起何處，迢迢送落暉。蒼茫隨思遠，蕭散逐煙微。", "秋野寂雲晦，望山僧獨歸。"]'),
('yuding-67','始聞夏蟬','韋應物','唐','御定全唐诗','yuding','','[]','徂夏暑未晏，蟬鳴景已曛。一聽知何處，高樹但侵雲。',48,'御定全唐詩/json/193.json','["徂夏暑未晏，蟬鳴景已曛。一聽知何處，高樹但侵雲。", "響悲遇衰齒，節謝屬離群。還憶郊園日，獨向澗中聞。"]'),
('yuding-68','射雉','韋應物','唐','御定全唐诗','yuding','','[]','走馬上東岡，朝日照野田。野田雙雉起，翻射鬥回鞭。',72,'御定全唐詩/json/193.json','["走馬上東岡，朝日照野田。野田雙雉起，翻射鬥回鞭。", "雖無百發中，聊取一笑妍。羽分繡臆碎，頭弛錦鞘懸。", "方將悅羈旅，非關學少年。弢弓一長嘯，憶在灞城阡。"]'),
('yuding-69','夜聞獨鳥啼','韋應物','唐','御定全唐诗','yuding','','[]','失侶度山覓，投林舍北啼。今將獨夜意，偏知對影棲。',24,'御定全唐詩/json/193.json','["失侶度山覓，投林舍北啼。今將獨夜意，偏知對影棲。"]'),
('yuding-70','述園鹿','韋應物','唐','御定全唐诗','yuding','','[]','野性本難畜，玩習亦逾年。麑班始力直，麚角已蒼然。',72,'御定全唐詩/json/193.json','["野性本難畜，玩習亦逾年。麑班始力直，麚角已蒼然。", "仰首嚼園柳，俯身飲清泉。見人若閒暇，蹶起忽低騫。", "茲獸有高貌，凡類寧比肩。不得遊山澤，局促誠可憐。"]'),
('yuding-71','聞雁','韋應物','唐','御定全唐诗','yuding','','[]','故園眇何處，歸思方悠哉。淮南秋雨夜，高齋聞雁來。',24,'御定全唐詩/json/193.json','["故園眇何處，歸思方悠哉。淮南秋雨夜，高齋聞雁來。"]'),
('yuding-72','子規啼','韋應物','唐','御定全唐诗','yuding','','[]','高林滴露夏夜清，南山子規啼一聲。',32,'御定全唐詩/json/193.json','["高林滴露夏夜清，南山子規啼一聲。", "鄰家孀婦抱兒泣，我獨輾轉何時明。"]'),
('yuding-73','始建射侯','韋應物','唐','御定全唐诗','yuding','','[]','男子本懸弧，有志在四方。虎竹忝明命，熊侯始張惶。',72,'御定全唐詩/json/193.json','["男子本懸弧，有志在四方。虎竹忝明命，熊侯始張惶。", "賓登時事畢，諸將備戎裝。星飛的屢破，鼓噪武更揚。", "曾習鄒魯學，亦陪鴛鷺翔。一朝願投筆，世難激中腸。"]'),
('yuding-74','仙人祠','韋應物','唐','御定全唐诗','yuding','','[]','蒼岑古仙子，清廟閟華容。千載去寥廓，白雲遺舊蹤。',36,'御定全唐詩/json/193.json','["蒼岑古仙子，清廟閟華容。千載去寥廓，白雲遺舊蹤。", "歸來灞陵上，猶見最高峰。"]'),
('yuding-75','鷓鴣啼','韋應物','唐','御定全唐诗','yuding','','[]','可憐鷓鴣飛，飛向樹南枝。南枝日照暖，北枝霜露滋。',84,'御定全唐詩/json/193.json','["可憐鷓鴣飛，飛向樹南枝。南枝日照暖，北枝霜露滋。", "露滋不堪棲，使我夜常啼。願逢雲中鶴，銜我向寥廓。", "願作城上烏，一年生九雛。何不舊巢住，枝弱不得去。", "何意道苦辛，客子常畏人。"]'),
('yuding-0','長安道','韋應物','唐','御定全唐诗','yuding','','[]','漢家宮殿含雲煙，兩宮十裏相連延。晨霞出沒弄丹闕，',150,'御定全唐詩/json/194.json','["漢家宮殿含雲煙，兩宮十裏相連延。晨霞出沒弄丹闕，", "寶馬橫來下建章，香車卻轉避馳道。貴遊誰最貴，", "歸來甲第拱皇居，朱門峨峨臨九衢。", "中有流蘇合歡之寶帳，一百二十鳳凰羅列含明珠。", "下有錦鋪翠被之粲爛，博山吐香五雲散。", "麗人綺閣情飄颻，頭上鴛釵雙翠翹。低鬟曳袖回春雪，", "既請列侯封部曲，還將金印授廬兒。歡榮若此何所苦，"]'),
('yuding-1','行路難','韋應物','唐','御定全唐诗','yuding','','[]','荊山之白玉兮，良工雕琢雙環連，月蝕中央鏡心穿。',75,'御定全唐詩/json/194.json','["荊山之白玉兮，良工雕琢雙環連，月蝕中央鏡心穿。", "故人贈妾初相結，恩在環中尋不絕。人情厚薄苦須臾，", "上客勿遽歡，聽妾歌路難。旁人見環環可憐。", "不知中有長恨端。"]'),
('yuding-2','橫塘行','韋應物','唐','御定全唐诗','yuding','','[]','妾家住橫塘，夫婿郗家郎。玉盤的曆雙白魚，',44,'御定全唐詩/json/194.json','["妾家住橫塘，夫婿郗家郎。玉盤的曆雙白魚，", "岸上種蓮豈得生，池中種槿豈得成。丈夫一去花落樹，"]'),
('yuding-3','貴遊行','韋應物','唐','御定全唐诗','yuding','','[]','漢帝外家子，恩澤少封侯。垂楊拂白馬，曉日上青樓。',120,'御定全唐詩/json/194.json','["漢帝外家子，恩澤少封侯。垂楊拂白馬，曉日上青樓。", "上有顏如玉，高情世無儔。輕裾含碧煙，窈窕似雲浮。", "良時無還景，促節為我謳。忽聞豔陽曲，四坐亦已柔。", "賓友仰稱歎，一生何所求。平明擊鐘食，入夜樂未休。", "風雨愆歲候，兵戎橫九州。焉知坐上客，草草心所憂。"]'),
('yuding-4','酒肆行','韋應物','唐','御定全唐诗','yuding','','[]','豪家沽酒長安陌，一旦起樓高百尺。碧疏玲瓏含春風，',88,'御定全唐詩/json/194.json','["豪家沽酒長安陌，一旦起樓高百尺。碧疏玲瓏含春風，", "四方稱賞名已高，五陵車馬無近遠。晴景悠揚三月天，", "主人無厭且專利，百斛須臾一壺費。初醲後薄為大偷，", "長安酒徒空擾擾，路傍過去那得知。"]'),
('yuding-5','相逢行','韋應物','唐','御定全唐诗','yuding','','[]','二十登漢朝，英聲邁今古。適從東方來，又欲謁明主。',72,'御定全唐詩/json/194.json','["二十登漢朝，英聲邁今古。適從東方來，又欲謁明主。", "猶酣新豐酒，尚帶灞陵雨。邂逅兩相逢，別來問寒暑。", "甯知白日晚，暫向花間語。忽聞長樂鐘，走馬東西去。"]'),
('yuding-6','烏引雛','韋應物','唐','御定全唐诗','yuding','','[]','日出照東城，春烏鴉鴉雛和鳴。雛和鳴，羽猶短。',70,'御定全唐詩/json/194.json','["日出照東城，春烏鴉鴉雛和鳴。雛和鳴，羽猶短。", "巢在深林春正寒，引飛欲集東城暖。群雛縭褷睥睨高，", "引雛烏，爾心急急將何如，何得比日搜索雀卵啖爾雛。"]'),
('yuding-7','鳶奪巢','韋應物','唐','御定全唐诗','yuding','','[]','野鵲野鵲巢林梢，鴟鳶恃力奪鵲巢。吞鵲之肝啄鵲腦，',48,'御定全唐詩/json/194.json','["野鵲野鵲巢林梢，鴟鳶恃力奪鵲巢。吞鵲之肝啄鵲腦，", "霜鸇野鷂得殘肉，同啄膻腥不肯逐。可憐百鳥紛縱橫，"]'),
('yuding-8','燕銜泥','韋應物','唐','御定全唐诗','yuding','','[]','銜泥燕，聲嘍嘍，尾涎涎。秋去何所歸，春來複相見。',51,'御定全唐詩/json/194.json','["銜泥燕，聲嘍嘍，尾涎涎。秋去何所歸，春來複相見。", "豈不解決絕高飛碧雲裏，何為地上銜泥滓。銜泥雖賤意有營，"]'),
('yuding-9','鼙鼓行','韋應物','唐','御定全唐诗','yuding','','[]','淮海生雲暮慘澹，廣陵城頭鼙鼓暗，寒聲坎坎風動邊。',64,'御定全唐詩/json/194.json','["淮海生雲暮慘澹，廣陵城頭鼙鼓暗，寒聲坎坎風動邊。", "忽似孤城萬里絕，四望無人煙。又如虜騎截遼水，", "何況鰥孤火絕無晨炊，獨婦夜泣官有期。"]'),
('yuding-10','古劍行','韋應物','唐','御定全唐诗','yuding','','[]','千年土中兩刃鐵，土蝕不入金星滅。沉沉青脊鱗甲滿，',40,'御定全唐詩/json/194.json','["千年土中兩刃鐵，土蝕不入金星滅。沉沉青脊鱗甲滿，", "夏雲奔走雷闐闐，恐成霹靂飛上天。"]'),
('yuding-11','金穀園歌','韋應物','唐','御定全唐诗','yuding','','[]','石氏滅，金穀園中水流絕。當時豪右爭驕侈，',60,'御定全唐詩/json/194.json','["石氏滅，金穀園中水流絕。當時豪右爭驕侈，", "洛陽陌上人回首，絲竹飄颻入青天。晉武平吳恣歡燕，", "禍端一發埋恨長，百草無情春自綠。"]'),
('yuding-12','溫泉行','韋應物','唐','御定全唐诗','yuding','','[]','出身天寶今年幾，頑鈍如錘命如紙。作官不了卻來歸，',96,'御定全唐詩/json/194.json','["出身天寶今年幾，頑鈍如錘命如紙。作官不了卻來歸，", "身騎廄馬引天仗，直入華清列御前。玉林瑤雪滿寒山，", "蒙恩每浴華池水，扈獵不蹂渭北田。朝廷無事共歡燕，", "今來蕭瑟萬井空，唯見蒼山起煙霧。可憐蹭蹬失風波，"]'),
('yuding-13','學仙二首','韋應物','唐','御定全唐诗','yuding','','[]','昔有道士求神仙，靈真下試心確然。千鈞巨石一發懸，',119,'御定全唐詩/json/194.json','["昔有道士求神仙，靈真下試心確然。千鈞巨石一發懸，", "雲氣冉冉漸不見，留語弟子但精堅。", "石上鑿井欲到水，惰心一起中路止。", "豈不見古來三人俱弟兄，結茅深山讀仙經。", "上有青冥倚天之絕壁，下有颼飀萬壑之松聲。", "仙人變化為白鹿，二弟玩之兄誦讀。讀多七過可乞言，"]'),
('yuding-14','廣陵行','韋應物','唐','御定全唐诗','yuding','','[]','雄藩鎮楚郊，地勢鬱岧嶢。雙旌擁萬戟，中有霍嫖姚。',108,'御定全唐詩/json/194.json','["雄藩鎮楚郊，地勢鬱岧嶢。雙旌擁萬戟，中有霍嫖姚。", "海雲助兵氣，寶貨益軍饒。嚴城動寒角，晚騎踏霜橋。", "翕習英豪集，振奮士卒驍。列郡何足數，趨拜等卑寮。", "日宴方雲罷，人逸馬蕭蕭。忽如京洛間，遊子風塵飄。", "歸來視寶劍，功名豈一朝。"]'),
('yuding-15','萼綠華歌','韋應物','唐','御定全唐诗','yuding','','[]','有一人兮升紫霞，書名玉牒兮萼綠華。',69,'御定全唐詩/json/194.json','["有一人兮升紫霞，書名玉牒兮萼綠華。", "仙容矯矯兮雜瑤佩，輕衣重重兮蒙絳紗。", "雲雨愁思兮望淮海，鼓吹蕭條兮駕龍車。", "世淫濁兮不可降，胡不來兮玉斧家。"]'),
('yuding-16','王母歌','韋應物','唐','御定全唐诗','yuding','','[]','眾仙翼神母，羽蓋隨雲起。上游玄極杳冥中，',36,'御定全唐詩/json/194.json','["眾仙翼神母，羽蓋隨雲起。上游玄極杳冥中，", "玉顏眇眇何處尋，世上茫茫人自死。"]'),
('yuding-17','馬明生遇神女歌','韋應物','唐','御定全唐诗','yuding','','[]','學仙貴功亦貴精，神女變化感馬生。石壁千尋啟雙檢，',72,'御定全唐詩/json/194.json','["學仙貴功亦貴精，神女變化感馬生。石壁千尋啟雙檢，", "馬生一立心轉堅，知其丹白蒙哀憐。安期先生來起居，", "賜仙複坐對食訖，頷之使去隨煙升。乃言馬生合不死，"]'),
('yuding-18','石鼓歌','韋應物','唐','御定全唐诗','yuding','','[]','周宣大獵兮岐之陽，刻石表功兮煒煌煌。',84,'御定全唐詩/json/194.json','["周宣大獵兮岐之陽，刻石表功兮煒煌煌。", "石如鼓形數止十，風雨缺訛苔蘚澀。今人濡紙脫其文，", "喘逶迤，相糾錯，乃是宣王之臣史籀作。", "一書遺此天地間，精意長存世冥寞。秦家祖龍還刻石，"]'),
('yuding-19','寶觀主白鴝鵒歌','韋應物','唐','御定全唐诗','yuding','','[]','鴝鵒鴝鵒，眾皆如漆，爾獨如玉。鴝之鵒之，',79,'御定全唐詩/json/194.json','["鴝鵒鴝鵒，眾皆如漆，爾獨如玉。鴝之鵒之，", "人心鳥意自無猜，玉指霜毛本同色。有時一去淩蒼蒼，", "日夕依仁全羽翼，空欲銜環非報德。", "豈不及阿母之家青鳥兒，漢宮來往傳消息。"]'),
('yuding-20','彈棋歌','韋應物','唐','御定全唐诗','yuding','','[]','園天方地局，二十四氣子。劉生絕藝難對曹，',76,'御定全唐詩/json/194.json','["園天方地局，二十四氣子。劉生絕藝難對曹，", "履機乘變安可當，置之死地翻取強。", "不見短兵反掌收已盡，唯有猛士守四方。四方又何難，", "神安志愜動十全，滿堂驚視誰得然。"]'),
('yuding-0','聽鶯曲','韋應物','唐','御定全唐诗','yuding','','[]','東方欲曙花冥冥，啼鶯相喚亦可聽。乍去乍來時近遠，',88,'御定全唐詩/json/195.json','["東方欲曙花冥冥，啼鶯相喚亦可聽。乍去乍來時近遠，", "欲囀不囀意自嬌，羌兒弄笛曲未調。前聲後聲不相及，", "誰家懶婦驚殘夢，何處愁人憶故園。伯勞飛過聲局促，", "還棲碧樹鎖千門，春漏方殘一聲曉。"]'),
('yuding-1','白沙亭逢吳叟歌','韋應物','唐','御定全唐诗','yuding','','[]','龍池宮裏上皇時，羅衫寶帶香風吹。滿朝豪士今已盡，',72,'御定全唐詩/json/195.json','["龍池宮裏上皇時，羅衫寶帶香風吹。滿朝豪士今已盡，", "問之執戟亦先朝，零落難艱卻負樵。親觀文物蒙雨露，", "嘗陪月夕竹宮齋，每返溫泉灞陵醉。星歲再周十二辰，"]'),
('yuding-2','送褚校書歸舊山歌','韋應物','唐','御定全唐诗','yuding','','[]','握珠不返泉，匣玉不歸山。明皇重士亦如此，',68,'御定全唐詩/json/195.json','["握珠不返泉，匣玉不歸山。明皇重士亦如此，", "漢篋亡書已暗傳，嵩丘遺簡還能識。朝朝待詔青鎖闈，", "藏書壁中苔半侵，洗藥泉中月還在。春風飲餞灞陵原，"]'),
('yuding-3','五弦行','韋應物','唐','御定全唐诗','yuding','','[]','美人為我彈五弦，塵埃忽靜心悄然。古刀幽磬初相觸，',70,'御定全唐詩/json/195.json','["美人為我彈五弦，塵埃忽靜心悄然。古刀幽磬初相觸，", "如伴風流縈豔雪，更逐落花飄禦園。獨鳳寥寥有時隱，", "末曲感我情，解幽釋結和樂生。壯士有仇未得報，"]'),
('yuding-4','驪山行','韋應物','唐','御定全唐诗','yuding','','[]','君不見開元至化垂衣裳，厭坐明堂朝萬方。',179,'御定全唐詩/json/195.json','["君不見開元至化垂衣裳，厭坐明堂朝萬方。", "訪道靈山降聖祖，沐浴華池集百祥。千乘萬騎被原野，", "玉階寂歷朝無事，碧樹萎蕤寒更芳。三清小鳥傳仙語，", "翠華稍隱天半雲，丹閣光明海中日。羽旗旄節憩瑤台，", "憑高覽古嗟寰宇，造化茫茫思悠哉。秦川八水長繚繞，", "蒼生咸壽陰陽泰，高謝前王出塵外。英豪共理天下晏，", "干戈一起文武乖，歡娛已極人事變。聖皇弓劍墜幽泉，", "太平遊幸今可待，湯泉嵐嶺還氛氳。"]'),
('yuding-5','漢武帝雜歌三首','韋應物','唐','御定全唐诗','yuding','','[]','漢武好神仙，黃金作台與天近。王母摘桃海上還，',223,'御定全唐詩/json/195.json','["漢武好神仙，黃金作台與天近。王母摘桃海上還，", "綠鬢縈雲裾曳霧，雙節飄颻下仙步。白日分明到世間，", "海水桑田幾翻覆，中間此桃四五熟。可憐穆滿瑤池燕，", "顏如芳華潔如玉，心念我皇多嗜欲。雖留桃核桃有靈，", "掩扇一言相謝去，如煙非煙不知處。", "金莖孤峙兮淩紫煙，漢宮美人望杳然。通天臺上月初出，", "仙方稱上藥，靜者服之常綽約。柏梁沉飲自傷神，", "漢天子，觀風自南國。浮舟大江屹不前，", "愕然觀者千萬眾，舉麾齊呼一矢中。死蛟浮出不復靈，", "左有佽飛落霜翮，右有孤兒貫犀革。何為臨深親射蛟，"]'),
('yuding-6','棕櫚蠅拂歌','韋應物','唐','御定全唐诗','yuding','','[]','棕櫚為拂登君席，青蠅掩亂飛四壁。文如輕羅散如發，',40,'御定全唐詩/json/195.json','["棕櫚為拂登君席，青蠅掩亂飛四壁。文如輕羅散如發，", "麗人紈素可憐色，安能點白還為黑。"]'),
('yuding-7','信州錄事參軍常曾古鼎歌','韋應物','唐','御定全唐诗','yuding','','[]','三年糾一郡，獨飲寒泉井。江南鑄器多鑄銀，',44,'御定全唐詩/json/195.json','["三年糾一郡，獨飲寒泉井。江南鑄器多鑄銀，", "左對蒼山右流水，雲有古來葛仙子。葛仙埋之何不還，"]'),
('yuding-8','夏冰歌','韋應物','唐','御定全唐诗','yuding','','[]','出自玄泉杳杳之深井，汲在朱明赫赫之炎辰。',68,'御定全唐詩/json/195.json','["出自玄泉杳杳之深井，汲在朱明赫赫之炎辰。", "九天含露未銷鑠，閶闔初開賜貴人。碎如墜瓊方截璐，", "咫尺炎涼變四時，出門焦灼君詎知。肥羊甘醴心悶悶，"]'),
('yuding-9','黿頭山神女歌','韋應物','唐','御定全唐诗','yuding','','[]','黿頭之山，直上洞庭連青天。蒼蒼煙樹閉古廟，',141,'御定全唐詩/json/195.json','["黿頭之山，直上洞庭連青天。蒼蒼煙樹閉古廟，", "魂同魍魎潛太陰，身與空山長不滅。東晉永和今幾代，", "山精木魅不敢親，昏明想像如有人。蕙蘭瓊芳積煙露，", "碧水冥空惟鳥飛，長天何處雲隨雨。紅渠綠蘋芳意多，", "皓雪瓊枝殊異色，北方絕代徒傾國。雲沒煙銷不可期，", "湘妃獨立九疑暮，漢女菱歌春日長。始知仙事無不有，"]'),
('yuding-10','寇季膺古刀歌','韋應物','唐','御定全唐诗','yuding','','[]','古刀寒鋒青槭槭，少年交結平陵客。求之時代不可知，',118,'御定全唐詩/json/195.json','["古刀寒鋒青槭槭，少年交結平陵客。求之時代不可知，", "古物有靈知所適，貂裘拂之橫廣席。陰森白日掩雲虹，", "厭見今時繞指柔，片鋒折刃猶堪佩。高山成穀蒼海填，", "夜光投人人不畏，知君獨識精靈器。酬恩結思心自知，", "月肅風淒古堂淨，精芒切切如有聲。何不跨蓬萊，"]'),
('yuding-11','淩霧行','韋應物','唐','御定全唐诗','yuding','','[]','秋城海霧重，職事淩晨出。浩浩合元天，溶溶迷朗日。',72,'御定全唐詩/json/195.json','["秋城海霧重，職事淩晨出。浩浩合元天，溶溶迷朗日。", "才看含鬢白，稍視沾衣密。道騎全不分，郊樹都如失。", "霏微誤噓吸，膚腠生寒栗。歸當飲一杯，庶用蠲斯疾。"]'),
('yuding-12','樂燕行','韋應物','唐','御定全唐诗','yuding','','[]','良辰且燕樂，樂往不再來。趙瑟正高張，音響清塵埃。',96,'御定全唐詩/json/195.json','["良辰且燕樂，樂往不再來。趙瑟正高張，音響清塵埃。", "一彈和妙謳，吹去繞瑤台。豔雪淩空散，舞羅起徘徊。", "輝輝發眾顏，灼灼歎令才。當喧既無寂，中飲亦停杯。", "華燈何遽升，馳景忽西頹。高節亦雲立，安能滯不回。"]'),
('yuding-13','采玉行','韋應物','唐','御定全唐诗','yuding','','[]','官府征白丁，言采藍溪玉。絕嶺夜無家，深榛雨中宿。',36,'御定全唐詩/json/195.json','["官府征白丁，言采藍溪玉。絕嶺夜無家，深榛雨中宿。", "獨婦餉糧還，哀哀舍南哭。"]'),
('yuding-14','難言','韋應物','唐','御定全唐诗','yuding','','[]','掬土移山望山盡，投石填海望海滿。持索捕風幾時得，',24,'御定全唐詩/json/195.json','["掬土移山望山盡，投石填海望海滿。持索捕風幾時得，"]'),
('yuding-15','易言','韋應物','唐','御定全唐诗','yuding','','[]','洪爐熾炭燎一毛，大鼎炊湯沃殘雪。疾影隨形不覺至，',24,'御定全唐詩/json/195.json','["洪爐熾炭燎一毛，大鼎炊湯沃殘雪。疾影隨形不覺至，"]'),
('yuding-16','三台二首','韋應物','唐','御定全唐诗','yuding','','[]','一年一年老去，明日後日花開。',56,'御定全唐詩/json/195.json','["一年一年老去，明日後日花開。", "未報長安平定，萬國豈得銜杯。", "冰泮寒塘始綠，雨餘百草皆生。", "朝來門閣無事，晚下高齋有情。"]'),
('yuding-17','上皇三台','韋應物','唐','御定全唐诗','yuding','','[]','不寐倦長更，披衣出戶行。月寒秋竹冷，風切夜窗聲。',24,'御定全唐詩/json/195.json','["不寐倦長更，披衣出戶行。月寒秋竹冷，風切夜窗聲。"]'),
('yuding-18','答暢參軍','韋應物','唐','御定全唐诗','yuding','','[]','秉筆振芳步，少年且吏游。官閑高興生，夜直河漢秋。',96,'御定全唐詩/json/195.json','["秉筆振芳步，少年且吏游。官閑高興生，夜直河漢秋。", "念與清賞遇，方抱沉疾憂。嘉言忽見贈，良藥同所瘳。", "高樹起棲鴉，晨鐘滿皇州。淒清露華動，曠朗景氣浮。", "偶宦心非累，處喧道自幽。空虛為世薄，子獨意綢繆。"]'),
('yuding-19','南池宴錢子辛，賦得科鬥','韋應物','唐','御定全唐诗','yuding','','[]','臨池見科鬥，美爾樂有餘。不憂網與鉤，幸得免為魚。',36,'御定全唐詩/json/195.json','["臨池見科鬥，美爾樂有餘。不憂網與鉤，幸得免為魚。", "且願充文字，登君尺素書。"]'),
('yuding-20','詠徐正字畫青蠅','韋應物','唐','御定全唐诗','yuding','','[]','誤點能成物，迷真許一時。筆端來已久，座上去何遲。',48,'御定全唐詩/json/195.json','["誤點能成物，迷真許一時。筆端來已久，座上去何遲。", "顧白曾無變，聽雞不復疑。詎勞才子賞，為入國人詩。"]'),
('yuding-21','虞獲子鹿','韋應物','唐','御定全唐诗','yuding','','[]','虞獲子鹿，畜之城陬。園有美草，池有清流。',40,'御定全唐詩/json/195.json','["虞獲子鹿，畜之城陬。園有美草，池有清流。", "但見蹶蹶，亦聞呦呦。誰知其思，岩谷雲遊。"]'),
('yuding-22','陪王郎中尋孔征君','韋應物','唐','御定全唐诗','yuding','','[]','俗吏閒居少，同人會面難。偶隨香署客，來訪竹林歡。',48,'御定全唐詩/json/195.json','["俗吏閒居少，同人會面難。偶隨香署客，來訪竹林歡。", "暮館花微落，春城雨暫寒。甕間聊共酌，莫使宦情闌。"]'),
('yuding-23','送宮人入道','韋應物','唐','御定全唐诗','yuding','','[]','舍寵求仙畏色衰，辭天素面立天墀。金丹擬駐千年貌，',40,'御定全唐詩/json/195.json','["舍寵求仙畏色衰，辭天素面立天墀。金丹擬駐千年貌，", "從來宮女皆相妒，說著瑤台總淚垂。"]'),
('yuding-24','和晉陵陸丞早春遊望','韋應物','唐','御定全唐诗','yuding','','[]','獨有宦遊人，偏驚物候新。雲霞出海曙，梅柳渡江春。',48,'御定全唐詩/json/195.json','["獨有宦遊人，偏驚物候新。雲霞出海曙，梅柳渡江春。", "淑氣催黃鳥，晴光照綠蘋。忽聞歌苦調，歸思欲沾巾。"]'),
('yuding-25','九日','韋應物','唐','御定全唐诗','yuding','','[]','一為吳郡守，不覺菊花開。始有故園思，且喜眾賓來。',24,'御定全唐詩/json/195.json','["一為吳郡守，不覺菊花開。始有故園思，且喜眾賓來。"]'),
('yuding-0','元次山居武昌之樊山，新春大雪，以詩問之','孟彥深','唐','御定全唐诗','yuding','','[]','江山十日雪，雪深江霧濃。起來望樊山，但見群玉峰。',72,'御定全唐詩/json/196.json','["江山十日雪，雪深江霧濃。起來望樊山，但見群玉峰。", "林鶯卻不語，野獸翻有蹤。山中應大寒，短褐何以完。", "皓氣凝書帳，清著釣魚竿。懷君欲進謁，溪滑渡舟難。"]'),
('yuding-1','出塞曲','劉灣','唐','御定全唐诗','yuding','','[]','將軍在重圍，音信絕不通。羽書如流星，飛入甘泉宮。',96,'御定全唐詩/json/196.json','["將軍在重圍，音信絕不通。羽書如流星，飛入甘泉宮。", "倚是並州兒，少年心膽雄。一朝隨召募，百戰爭王公。", "去年桑幹北，今年桑幹東。死是征人死，功是將軍功。", "汗馬牧秋月，疲卒臥霜風。仍聞左賢王，更將圍雲中。"]'),
('yuding-2','雲南曲','劉灣','唐','御定全唐诗','yuding','','[]','百蠻亂南方，群盜如蝟起。騷然疲中原，征戰從此始。',96,'御定全唐詩/json/196.json','["百蠻亂南方，群盜如蝟起。騷然疲中原，征戰從此始。", "白門太和城，來往一萬里。去者無全生，十人九人死。", "岱馬臥陽山，燕兵哭瀘水。妻行求死夫，父行求死子。", "蒼天滿愁雲，白骨積空壘。哀哀雲南行，十萬同已矣。"]');
